// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue } = useStore();

  // --- Resize Handler ---
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current && canvasRef.current) {
        const { width, height } = containerRef.current.getBoundingClientRect();
        // Handle high DPI displays
        const dpr = window.devicePixelRatio || 1;
        canvasRef.current.width = width * dpr;
        canvasRef.current.height = height * dpr;
        canvasRef.current.style.width = `${width}px`;
        canvasRef.current.style.height = `${height}px`;

        const ctx = canvasRef.current.getContext('2d');
        if (ctx) ctx.scale(dpr, dpr);
      }
    };

    window.addEventListener('resize', handleResize);
    handleResize(); // Initial call
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Input Handling (Basic Mouse Tracking for Axes) ---
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e: MouseEvent) => {
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;

      // Update Axes based on mouse position
      // In a real scenario, this would only happen if "Recording" or "Playing"
      // or if the specific axis is mapped to MouseX/MouseY
      updateAxisValue('axis-x', Math.max(0, Math.min(1, x)));
      updateAxisValue('axis-y', Math.max(0, Math.min(1, y)));
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    return () => canvas.removeEventListener('mousemove', handleMouseMove);
  }, [updateAxisValue]);


  // --- Main Render Loop ---
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = () => {
      const { width, height } = canvas.getBoundingClientRect();

      // 1. Clear Canvas
      ctx.clearRect(0, 0, width, height);

      // 2. Draw Grid (Optional)
      if (ui.showGrid) {
        ctx.strokeStyle = '#E5E7EB';
        ctx.lineWidth = 1;
        const gridSize = 50 * ui.zoom;
        const offsetX = ui.pan.x % gridSize;
        const offsetY = ui.pan.y % gridSize;

        ctx.beginPath();
        for (let x = offsetX; x < width; x += gridSize) {
          ctx.moveTo(x, 0);
          ctx.lineTo(x, height);
        }
        for (let y = offsetY; y < height; y += gridSize) {
          ctx.moveTo(0, y);
          ctx.lineTo(width, y);
        }
        ctx.stroke();
      }

      // 3. Draw Interpolated State
      // NOTE: This is where the complex Prosopopus engine logic lives.
      // For Phase 1, we will visualize the interpolation axes as a HUD
      // to demonstrate the state connection.

      // HUD: Display Axis Values
      ctx.font = '12px Inter, sans-serif';
      ctx.fillStyle = APP_COLORS.textMuted;

      let hudY = height - 20;
      project.axes.forEach(axis => {
        const barWidth = 100;
        const filled = axis.currentValue * barWidth;

        // Label
        ctx.fillText(`${axis.name}: ${axis.currentValue.toFixed(2)}`, 20, hudY);

        // Bar bg
        ctx.fillStyle = '#E5E7EB';
        ctx.fillRect(120, hudY - 10, barWidth, 8);

        // Bar fill
        ctx.fillStyle = APP_COLORS.primary;
        ctx.fillRect(120, hudY - 10, filled, 8);

        // Reset text color
        ctx.fillStyle = APP_COLORS.textMuted;
        hudY -= 20;
      });

      // Placeholder: Draw a circle that moves with the interpolated axis
      // This proves the interpolation engine connection
      const xVal = project.axes.find(a => a.id === 'axis-x')?.currentValue || 0.5;
      const yVal = project.axes.find(a => a.id === 'axis-y')?.currentValue || 0.5;

      ctx.beginPath();
      ctx.arc(xVal * width, yVal * height, 20, 0, Math.PI * 2);
      ctx.fillStyle = ui.brushColor;
      ctx.fill();

      // Request next frame
      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [project.axes, ui.showGrid, ui.zoom, ui.pan, ui.brushColor, project.layers]); // Re-bind if dependencies change deeply

  return (
    <div ref={containerRef} className="absolute inset-0 z-0 bg-[#F9F9F9] cursor-crosshair overflow-hidden touch-none">
      <canvas ref={canvasRef} className="block" />
    </div>
  );
};

