// utils/math.ts
import { Point, Stroke } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// Calculate weights based on Inverse Distance Weighting (IDW)
export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
): Record<string, number> => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    // Singularity check: if we are exactly on a keyframe
    if (dist < 0.001) {
      return { [kf.id]: 1.0 };
    }

    // Power parameter p=2 (standard gravity model)
    const weight = 1 / (dist * dist);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  // Normalize weights so they sum to 1
  for (const id in weights) {
    weights[id] /= totalWeight;
  }

  return weights;
};

// Core Engine: Interpolate a single stroke across multiple keyframes
export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], // The points from the primary keyframe (topology source)
  keyframesData: { weight: number; points: Point[] | undefined }[]
): Point[] => {

  // If only one keyframe has this stroke, or total weight is trivial, return base
  if (keyframesData.length === 0) return basePoints;

  const resultPoints: Point[] = [];
  const count = basePoints.length;

  for (let i = 0; i < count; i++) {
    let x = 0;
    let y = 0;
    let totalAppliedWeight = 0;

    for (const kf of keyframesData) {
      // We only interpolate if the stroke exists in this keyframe and has compatible topology (same point count)
      // In a production app, we would implement resampling here to match point counts.
      // For this version, we assume "Cloned Keyframes" maintain point count.
      if (kf.points && kf.points.length === count) {
        x += kf.points[i].x * kf.weight;
        y += kf.points[i].y * kf.weight;
        totalAppliedWeight += kf.weight;
      }
    }

    if (totalAppliedWeight > 0) {
      resultPoints.push({ 
        x: x / totalAppliedWeight, // Normalize in case some keyframes were missing the stroke
        y: y / totalAppliedWeight 
      });
    } else {
      // Fallback to base point if no other keyframe has valid data
      resultPoints.push(basePoints[i]);
    }
  }

  return resultPoints;
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, INITIAL_LAYER_ID } from '../constants';

interface StoreState {
  project: Project;
  ui: UIState;

  // Actions
  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setBrushSize: (size: number) => void;
  toggleGrid: () => void;

  // Axis Management
  updateAxisValue: (axisId: string, value: number) => void;

  // Layer Management
  addLayer: () => void;
  toggleLayerVisibility: (layerId: string) => void;
  selectLayer: (layerId: string) => void;

  // Canvas Interaction
  addStrokeToCurrentKeyframe: (points: Point[]) => void;

  // Keyframe Management
  createKeyframeAtCurrentAxes: () => void;
  selectKeyframe: (keyframeId: string) => void;
}

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool } })),
  setBrushColor: (color) => set((state) => ({ ui: { ...state.ui, brushColor: color } })),
  setBrushSize: (size) => set((state) => ({ ui: { ...state.ui, brushSize: size } })),
  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),

  updateAxisValue: (axisId, value) => set((state) => {
    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: Math.max(a.min, Math.min(a.max, value)) } : a
    );
    return { project: { ...state.project, axes: newAxes } };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),

  addLayer: () => set((state) => {
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1
    };
    return {
      project: {
        ...state.project,
        layers: [newLayer, ...state.project.layers], 
      },
      ui: { ...state.ui, selectedLayerId: newId }
    };
  }),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  addStrokeToCurrentKeyframe: (points) => set((state) => {
    const { selectedKeyframeId, selectedLayerId, brushColor, brushSize } = state.ui;
    if (!selectedKeyframeId || !selectedLayerId) return state;

    const newStroke: Stroke = {
      id: `stroke-${Date.now()}-${Math.random()}`,
      points,
      color: brushColor,
      width: brushSize,
      style: 'solid',
      closed: false
    };

    const newKeyframes = state.project.keyframes.map(kf => {
      if (kf.id === selectedKeyframeId) {
        // Find if layerState exists
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);

        let newLayerStates = [...kf.layerStates];
        if (existingLayerStateIndex >= 0) {
          // Update existing layer state
          const updatedLayerState = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [...newLayerStates[existingLayerStateIndex].strokes, newStroke]
          };
          newLayerStates[existingLayerStateIndex] = updatedLayerState;
        } else {
          // Create new layer state
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes: newKeyframes } };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
    // 1. Capture current axis values
    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => {
      currentAxisValues[a.id] = a.currentValue;
    });

    // 2. Clone the "Interpolated State" to form the base of the new Keyframe.
    // NOTE: For simplicity in this step, we are cloning the *selected keyframe's content*
    // if it exists, or the 'kf-origin' content. In a full implementation, 
    // we would bake the current interpolation into the new keyframe.

    const sourceKeyframeId = state.ui.selectedKeyframeId || 'kf-origin';
    const sourceKeyframe = state.project.keyframes.find(k => k.id === sourceKeyframeId);

    // Deep clone the layer states (so strokes can be moved independently)
    const clonedLayerStates: LayerState[] = sourceKeyframe 
      ? JSON.parse(JSON.stringify(sourceKeyframe.layerStates))
      : [];

    const newKeyframe: Keyframe = {
      id: `kf-${Date.now()}`,
      name: `Keyframe ${state.project.keyframes.length}`,
      axisValues: currentAxisValues,
      layerStates: clonedLayerStates
    };

    return {
      project: {
        ...state.project,
        keyframes: [...state.project.keyframes, newKeyframe]
      },
      ui: {
        ...state.ui,
        selectedKeyframeId: newKeyframe.id
      }
    };
  })
}));

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';
import { calculateInterpolationWeights, interpolateStrokePoints } from '../utils/math';
import { Point, Stroke } from '../types';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe } = useStore();

  // Local state for drawing
  const [isDrawing, setIsDrawing] = useState(false);
  const currentPointsRef = useRef<Point[]>([]);

  // --- Resize Handler ---
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current && canvasRef.current) {
        const { width, height } = containerRef.current.getBoundingClientRect();
        const dpr = window.devicePixelRatio || 1;
        canvasRef.current.width = width * dpr;
        canvasRef.current.height = height * dpr;
        canvasRef.current.style.width = `${width}px`;
        canvasRef.current.style.height = `${height}px`;
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) ctx.scale(dpr, dpr);
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Interaction Handlers ---

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return {
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
      pressure: e.pressure || 0.5
    };
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    // Only draw if pen is selected
    if (ui.selectedTool === 'pen') {
      setIsDrawing(true);
      const p = getCanvasPoint(e);
      currentPointsRef.current = [p];
      // Capture the pointer to track even if it leaves canvas
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (isDrawing) {
      currentPointsRef.current.push(p);
    } else if (ui.selectedTool === 'cursor') {
       // Update Axes based on mouse position (Interpolation Mode)
       // Calculate normalized coordinates 0..1
       const rect = canvasRef.current!.getBoundingClientRect();
       const normX = Math.max(0, Math.min(1, p.x / rect.width));
       const normY = Math.max(0, Math.min(1, p.y / rect.height));

       updateAxisValue('axis-x', normX);
       updateAxisValue('axis-y', normY);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (isDrawing) {
      setIsDrawing(false);
      (e.target as Element).releasePointerCapture(e.pointerId);

      // Simplify path (basic optimization)
      if (currentPointsRef.current.length > 1) {
         addStrokeToCurrentKeyframe([...currentPointsRef.current]);
      }
      currentPointsRef.current = [];
    }
  };

  // --- Main Render Loop ---
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    const render = () => {
      const { width, height } = canvas.getBoundingClientRect();

      // 1. Clear Canvas
      ctx.clearRect(0, 0, width, height);

      // 2. Draw Grid
      if (ui.showGrid) {
        ctx.strokeStyle = '#E5E7EB';
        ctx.lineWidth = 1;
        ctx.beginPath();
        const gridSize = 50;
        for (let x = 0; x < width; x += gridSize) ctx.rect(x, 0, 1, height);
        for (let y = 0; y < height; y += gridSize) ctx.rect(0, y, width, 1);
        ctx.stroke();
      }

      // 3. Interpolation Engine
      // A. Calculate Weights
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);
      const weights = calculateInterpolationWeights(currentAxesDict, project.keyframes);

      // B. Filter active Keyframes (weight > 0)
      const activeKeyframes = project.keyframes
        .map(k => ({ ...k, weight: weights[k.id] || 0 }))
        .filter(k => k.weight > 0.001);

      // C. Iterate Layers
      project.layers.forEach(layer => {
        if (!layer.visible) return;

        // Collect all stroke IDs present in this layer across active keyframes
        const allStrokeIds = new Set<string>();
        activeKeyframes.forEach(kf => {
          const state = kf.layerStates.find(ls => ls.layerId === layer.id);
          state?.strokes.forEach(s => allStrokeIds.add(s.id));
        });

        // D. Interpolate and Draw each Stroke
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        allStrokeIds.forEach(strokeId => {
          // Gather data for this stroke from all active keyframes
          const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes.find(st => st.id === strokeId);
            return { weight: kf.weight, points: s?.points, style: s };
          });

          // Find the "Primary" style (usually from the closest keyframe or just the first found)
          const primaryStroke = strokeData.find(sd => sd.style)?.style;
          if (!primaryStroke) return;

          // Calculate Interpolated Points
          // We use the primary stroke's points as the topology base
          const interpolatedPoints = interpolateStrokePoints(
             strokeId,
             primaryStroke.points,
             strokeData.map(sd => ({ weight: sd.weight, points: sd.points }))
          );

          // Draw
          ctx.beginPath();
          if (interpolatedPoints.length > 0) {
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) {
              ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            }
          }

          ctx.strokeStyle = primaryStroke.color;
          ctx.lineWidth = primaryStroke.width;
          ctx.globalAlpha = layer.opacity;
          // Blend mode could be applied here to context
          ctx.stroke();
          ctx.globalAlpha = 1.0;
        });
      });

      // 4. Draw Current Stroke (while drawing)
      if (isDrawing && currentPointsRef.current.length > 0) {
        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor;
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
      }

      // HUD Debug
      ctx.fillStyle = APP_COLORS.textMuted;
      ctx.font = '10px monospace';
      ctx.fillText(`Keyframes: ${project.keyframes.length}`, 10, height - 10);
      let yOffset = 25;
      project.axes.forEach(a => {
          ctx.fillText(`${a.name}: ${a.currentValue.toFixed(2)}`, 10, height - yOffset);
          yOffset += 15;
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, isDrawing]);

  return (
    <div ref={containerRef} className="absolute inset-0 z-0 bg-[#F9F9F9] touch-none">
      <canvas 
        ref={canvasRef} 
        className="block cursor-crosshair"
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerLeave={handlePointerUp}
      />
    </div>
  );
};

