// components/AxisMap.tsx
import React, { useRef } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';

export const AxisMap: React.FC = () => {
  const { project, updateAxisValue, ui, selectKeyframe } = useStore();
  const containerRef = useRef<HTMLDivElement>(null);

  // Find X and Y axes
  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  const handlePointer = (e: React.PointerEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    const y = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

    // Allow dragging to set interpolation
    if (e.buttons > 0) {
      updateAxisValue(axisX.id, x);
      updateAxisValue(axisY.id, y);
      (e.target as Element).setPointerCapture(e.pointerId);
    }
  };

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-40">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400">Interpolation Space</span>
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-gray-50 rounded-lg border border-gray-100 cursor-crosshair overflow-hidden"
          onPointerDown={handlePointer}
          onPointerMove={handlePointer}
        >
          {/* Grid Lines */}
          <div className="absolute inset-0 grid grid-cols-2 grid-rows-2">
            <div className="border-r border-b border-gray-200/50"></div>
            <div className="border-b border-gray-200/50"></div>
            <div className="border-r border-gray-200/50"></div>
          </div>

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;
            const isSelected = ui.selectedKeyframeId === kf.id;

            return (
              <div
                key={kf.id}
                onClick={(e) => { e.stopPropagation(); selectKeyframe(kf.id); }}
                className={`absolute w-3 h-3 -ml-1.5 -mt-1.5 rounded-full border-2 transition-transform cursor-pointer hover:scale-125 ${
                  isSelected 
                    ? 'bg-blue-500 border-white z-20 shadow-md' 
                    : 'bg-white border-gray-400 z-10'
                }`}
                style={{ left: `${kfX * 100}%`, top: `${kfY * 100}%` }}
                title={kf.name}
              />
            );
          })}

          {/* Current Interpolation Cursor (Crosshair) */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30"
