               }
            </button>

            <span className="truncate flex-1 font-medium select-none">{layer.name}</span>

            {/* Blend Mode - Tiny Indicator/Toggle */}
            <button
               onClick={(e) => {
                 e.stopPropagation();
                 const modes: BlendMode[] = ['normal', 'multiply'];
                 const nextMode = modes[(modes.indexOf(layer.blendMode) + 1) % modes.length];
                 setLayerBlendMode(layer.id, nextMode);
               }}
               className={`text-[9px] uppercase font-bold px-1.5 py-0.5 rounded border ${
                 layer.blendMode === 'multiply' 
                    ? 'bg-purple-100 text-purple-700 border-purple-200' 
                    : 'bg-gray-100 text-gray-500 border-gray-200'
               }`}
            >
              {layer.blendMode.substring(0, 3)}
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

