// types.ts

// --- Basic Geometry ---
export interface Point {
  x: number;
  y: number;
  pressure?: number; // 0 to 1
}

export interface Size {
  width: number;
  height: number;
}

// --- Vector Elements ---
export type StrokeStyle = 'solid' | 'dashed' | 'dotted';

export interface Stroke {
  id: string;
  points: Point[];
  color: string;
  width: number;
  style: StrokeStyle;
  closed: boolean; // True for shapes, false for lines
  fillColor?: string; // Optional fill
}

// --- Layers ---
export type BlendMode = 'normal' | 'multiply' | 'screen' | 'overlay';

export interface Layer {
  id: string;
  name: string;
  visible: boolean;
  locked: boolean;
  blendMode: BlendMode;
  opacity: number;
  // In v2, layers serve as containers/identifiers. 
  // The ACTUAL geometry is stored within Keyframes referenced by Layer ID.
}

// --- Axes & Keyframes (The Interpolation Engine) ---
export type AxisType = 'mouseX' | 'mouseY' | 'scrollLoop' | 'stylus' | 'time';

export interface Axis {
  id: string;
  name: string;
  type: AxisType;
  min: number;
  max: number;
  currentValue: number; // The live value (0-1 usually)
}

export interface LayerState {
  layerId: string;
  strokes: Stroke[]; // In "Puppet Mode", this array will typically contain exactly ONE stroke.
}

export interface Keyframe {
  id: string;
  name: string;
  // Position in the N-dimensional axis space
  axisValues: Record<string, number>; // e.g., { "x": 0.5, "y": 0 }
  // The content of the drawing at this specific state
  layerStates: LayerState[]; 
}

// --- Project Structure ---
export interface Project {
  id: string;
  name: string;
  version: string;
  created: number;
  modified: number;
  canvasSize: Size; // Fixed dimensions for the artboard
  axes: Axis[];
  layers: Layer[];
  keyframes: Keyframe[];
}

// --- UI State ---
export type ToolType = 'cursor' | 'pen' | 'rect' | 'circle' | 'eraser';
export type UIMode = 'edit' | 'play'; // New: Distinct modes

export interface UIState {
  mode: UIMode;
  selectedTool: ToolType;
  selectedLayerId: string | null;
  selectedKeyframeId: string | null;
  isPlaying: boolean;
  showGrid: boolean;
  zoom: number;
  pan: Point;
  brushSize: number;
  brushColor: string;
}

