import { Point, Stroke } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// CRITICAL: Resamples a stroke to have exactly `targetCount` points distributed evenly along its length.
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  const step = totalLength / (targetCount - 1);

  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;

    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  if (newPoints.length < targetCount) {
     newPoints.push(points[points.length - 1]);
  } else {
     newPoints[newPoints.length - 1] = points[points.length - 1];
  }

  return newPoints;
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Interpolation Logic ---

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
): Record<string, number> => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / (dist * dist);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) {
      weights[id] /= totalWeight;
    }
  } else {
    if (keyframes.length > 0) weights[keyframes[0].id] = 1;
  }

  return weights;
};

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined }[],
  mode: 'resample' | 'points' = 'resample'
): Point[] => {
  if (keyframesData.length === 0 || basePoints.length === 0) return basePoints;

  const TARGET_RESOLUTION = mode === 'resample' 
    ? Math.max(basePoints.length, 50) 
    : basePoints.length; // In 'points' mode, we trust the point count (good for grid snapping)

  // In 'points' mode, we assume index matching, so we don't resample the base
  const normalizedBase = mode === 'resample' 
    ? resamplePoints(basePoints, TARGET_RESOLUTION)
    : basePoints;

  const resultPoints: Point[] = [];

  for (let i = 0; i < normalizedBase.length; i++) {
    let x = 0;
    let y = 0;
    let pressure = 0;
    let totalAppliedWeight = 0;

    for (const kf of keyframesData) {
      if (kf.weight <= 0.001) continue;

      let kfPoints = kf.points;

      if (kfPoints && kfPoints.length > 0) {
        if (mode === 'resample') {
             // Re-sample to match resolution
             if (kfPoints.length !== TARGET_RESOLUTION) {
                 kfPoints = resamplePoints(kfPoints, TARGET_RESOLUTION);
             }
             // Safety check after resampling
             if (i < kfPoints.length) {
                x += kfPoints[i].x * kf.weight;
                y += kfPoints[i].y * kf.weight;
                pressure += (kfPoints[i].pressure || 0.5) * kf.weight;
                totalAppliedWeight += kf.weight;
             }
        } else {
             // POINT MODE: Direct Index Mapping
             // If keyframe has fewer points, we clamp to last point (or could wrap)
             const idx = Math.min(i, kfPoints.length - 1);
             x += kfPoints[idx].x * kf.weight;
             y += kfPoints[idx].y * kf.weight;
             pressure += (kfPoints[idx].pressure || 0.5) * kf.weight;
             totalAppliedWeight += kf.weight;
        }
      }
    }

    if (totalAppliedWeight > 0) {
      resultPoints.push({ 
        x: x / totalAppliedWeight, 
        y: y / totalAppliedWeight,
        pressure: pressure / totalAppliedWeight
      });
    } else {
      resultPoints.push(normalizedBase[i]);
    }
  }

  return resultPoints;
};

// --- Optimization Logic ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE } from '../constants';
import { simplifyPoints, distance } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  toggleSettings: () => void;
  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;
  toggleOnionSkin: () => void;
  setInterpolationMode: (mode: InterpolationMode) => void;

  updateAxisValue: (axisId: string, value: number) => void;

  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  selectLayer: (layerId: string) => void;

  addStrokeToCurrentKeyframe: (points: Point[]) => void;

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  selectKeyframe: (keyframeId: string) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,

  history: {
    past: [],
    future: []
  },

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool } })),
  setBrushColor: (color) => set((state) => ({ ui: { ...state.ui, brushColor: color } })),
  setBrushSize: (size) => set((state) => ({ ui: { ...state.ui, brushSize: size } })),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),
  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setInterpolationMode: (mode) => set((state) => ({ ui: { ...state.ui, interpolationMode: mode } })),

  updateAxisValue: (axisId, value) => set((state) => {
    // Round to 2 decimal places for cleanliness
    const cleanValue = Math.round(Math.max(0, Math.min(1, value)) * 100) / 100;

    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    // Auto-select nearby keyframe if exact match
    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let matchingKfId = state.ui.selectedKeyframeId;

    // Find if we are sitting exactly on a keyframe
    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.01;
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1
    };
    return {
      project: { ...state.project, layers: [newLayer, ...state.project.layers] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; // Prevent deleting last layer
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);
    return {
      project: { ...state.project, layers: newLayers },
      ui: { ...state.ui, selectedLayerId: newLayers[0].id }, // Select another layer
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      },
      history: { past, future: [] }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints) => set((state) => {
    const { selectedLayerId, brushColor, brushSize, interpolationMode } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    // Optimization based on mode
    let points = rawPoints;
    if (interpolationMode === 'resample') {
       points = simplifyPoints(rawPoints, 1.0);
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    // --- AUTO KEYFRAME LOGIC ---
    // 1. Get current axes
    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    // 2. Check if a keyframe exists exactly here
    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    // Calculate distance to all keyframes
    const match = keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      return dist < 0.001; // Epsilon
    });

    if (match) {
      targetKeyframeId = match.id;
    } else {
      // Create NEW keyframe automatically
      const newKfId = `kf-${Date.now()}`;

      // We clone layer states from the "closest" keyframe to preserve other layers? 
      // Or empty? Let's clone previous state to avoid content disappearing.
      // Simple strategy: Empty state for new position, or clone from nearest neighbor?
      // Puppet mode usually implies continuous drawing. Let's start empty for this layer.

      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] // Will fill below
      };

      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor,
      width: brushSize,
      style: 'solid',
      closed: false
    };

    // 3. Update the specific keyframe
    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          // Replace stroke
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          // Add new layer state
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     // This manual action is less needed now with Auto-KF, but kept for explicit control
     // Logic effectively covered by addStroke Auto-KF, but this duplicates state without stroke.
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; // Keep at least one
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    // Find new selected ID if we deleted the current one
    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  })
}));

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { calculateInterpolationWeights, interpolateStrokePoints, snapPointToGrid } from '../utils/math';
import { Point } from '../types';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe } = useStore();

  const [isDrawing, setIsDrawing] = useState(false);
  const currentPointsRef = useRef<Point[]>([]);

  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const availW = contW - margin;
      const availH = contH - margin;
      const scaleW = availW / CANVAS_WIDTH;
      const scaleH = availH / CANVAS_HEIGHT;
      const newScale = Math.min(scaleW, scaleH, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    let p = {
      x: (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width),
      y: (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height),
      pressure: e.pressure || 0.5
    };

    if (ui.snapToGrid && ui.mode === 'edit') {
      p = snapPointToGrid(p, 50); // Hardcoded 50px grid for now
    }
    return p;
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }
    if (ui.selectedTool === 'pen') {
      setIsDrawing(true);
      const p = getCanvasPoint(e);
      currentPointsRef.current = [p];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        const relX = e.clientX - rect.left;
        const relY = e.clientY - rect.top;
        const normX = Math.max(0, Math.min(1, relX / rect.width));
        const normY = Math.max(0, Math.min(1, relY / rect.height));
        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }
    const p = getCanvasPoint(e);
    if (isDrawing) {
      currentPointsRef.current.push(p);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
      (e.target as Element).releasePointerCapture(e.pointerId);
      return;
    }
    if (isDrawing) {
      setIsDrawing(false);
      (e.target as Element).releasePointerCapture(e.pointerId);
      if (currentPointsRef.current.length > 1) {
         addStrokeToCurrentKeyframe([...currentPointsRef.current]);
      }
      currentPointsRef.current = [];
    }
  };

  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.strokeStyle = '#F3F4F6';
        ctx.lineWidth = 1;
        ctx.beginPath();
        const gridSize = 50;
        for (let x = 0; x <= CANVAS_WIDTH; x += gridSize) { ctx.moveTo(x, 0); ctx.lineTo(x, CANVAS_HEIGHT); }
        for (let y = 0; y <= CANVAS_HEIGHT; y += gridSize) { ctx.moveTo(0, y); ctx.lineTo(CANVAS_WIDTH, y); }
        ctx.stroke();
      }

      // ONION SKIN (Render *other* keyframes in background)
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; // Skip current

           // Simple distance check to only show neighbors? 
           // For now, show all with low opacity
           ctx.globalAlpha = ui.onionSkinOpacity * 0.5;

           kf.layerStates.forEach(ls => {
              const layer = project.layers.find(l => l.id === ls.layerId);
              if (layer && layer.visible) {
                 const stroke = ls.strokes[0];
                 if (stroke && stroke.points.length > 1) {
                    ctx.beginPath();
                    ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                    for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                    ctx.strokeStyle = '#999999'; // Neutral grey for onion
                    ctx.lineWidth = stroke.width;
                    ctx.lineCap = 'round';
                    ctx.lineJoin = 'round';
                    ctx.stroke();
                 }
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);
      const weights = calculateInterpolationWeights(currentAxesDict, project.keyframes);

      const activeKeyframes = project.keyframes
        .map(k => ({ ...k, weight: weights[k.id] || 0 }))
        .filter(k => k.weight > 0.001);

      project.layers.forEach(layer => {
        if (!layer.visible) return;
        const strokeId = `stroke-${layer.id}-unique`;
        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s };
        });

        const primaryStroke = strokeData.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const interpolatedPoints = interpolateStrokePoints(
            strokeId,
            primaryStroke.points,
            strokeData.map(sd => ({ weight: sd.weight, points: sd.points })),
            ui.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) {
                ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            }
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';
            ctx.strokeStyle = primaryStroke.color;
            ctx.lineWidth = primaryStroke.width;

            ctx.globalAlpha = layer.opacity;
            if (layer.blendMode === 'multiply') ctx.globalCompositeOperation = 'multiply';
            else ctx.globalCompositeOperation = 'source-over';

            ctx.stroke();
            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // CURRENT DRAWING
      if (isDrawing && currentPointsRef.current.length > 0) {
        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor;
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-[32px] overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-8 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : 'cursor-crosshair'}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onPointerLeave={handlePointerUp}
          />
      </div>
    </div>
  );
};

// components/AxisMap.tsx
import React, { useRef } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';

export const AxisMap: React.FC = () => {
  const { project, updateAxisValue, ui, selectKeyframe, deleteKeyframe } = useStore();
  const containerRef = useRef<HTMLDivElement>(null);

  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  const handlePointer = (e: React.PointerEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    // Raw value
    let x = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    let y = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

    // SNAP TO 10x10 GRID (0.1 increments)
    // We snap if shift is held OR by default? 
    // Let's make it always snap to a finer grid for better UX, or specifically 10% blocks.
    // The prompt asked for "Matrix ... snap 10x10".

    const SNAP_INCREMENT = 0.1;
    x = Math.round(x / SNAP_INCREMENT) * SNAP_INCREMENT;
    y = Math.round(y / SNAP_INCREMENT) * SNAP_INCREMENT;

    if (e.buttons > 0) {
      updateAxisValue(axisX.id, x);
      updateAxisValue(axisY.id, y);
      (e.target as Element).setPointerCapture(e.pointerId);
    }
  };

  const selectedKf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-48">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400">Interpolation Matrix</span>

          {selectedKf && project.keyframes.length > 1 && (
             <button 
               onClick={() => deleteKeyframe(selectedKf.id)}
               className="text-[10px] text-red-500 hover:bg-red-50 px-2 py-0.5 rounded"
             >
               Delete State
             </button>
          )}
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-white rounded-lg border border-gray-200 cursor-crosshair overflow-hidden shadow-inner"
          onPointerDown={handlePointer}
          onPointerMove={handlePointer}
        >
          {/* 10x10 Grid Lines */}
          <div className="absolute inset-0" style={{ 
              backgroundImage: 'linear-gradient(#F3F4F6 1px, transparent 1px), linear-gradient(90deg, #F3F4F6 1px, transparent 1px)', 
              backgroundSize: '10% 10%' 
          }}></div>

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;
            const isSelected = ui.selectedKeyframeId === kf.id;

            return (
              <div
                key={kf.id}
                onClick={(e) => { e.stopPropagation(); selectKeyframe(kf.id); }}
                className={`absolute w-3 h-3 -ml-1.5 -mt-1.5 rounded-full border-2 transition-transform cursor-pointer hover:scale-125 ${
                  isSelected 
                    ? 'bg-blue-500 border-white z-20 shadow-md' 
                    : 'bg-white border-gray-400 z-10'
                }`}
                style={{ left: `${kfX * 100}%`, top: `${kfY * 100}%` }}
                title={kf.name}
              />
            );
          })}

          {/* Current Cursor */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30 transition-all duration-75 ease-linear"
            style={{ left: `${axisX.currentValue * 100}%`, top: `${axisY.currentValue * 100}%` }}
          >
             <svg viewBox="0 0 24 24" fill="none" stroke={APP_COLORS.primary} strokeWidth="3">
               <line x1="12" y1="0" x2="12" y2="24" />
               <line x1="0" y1="12" x2="24" y2="12" />
             </svg>
          </div>
        </div>

        <div className="mt-2 flex justify-between text-[10px] text-gray-400 font-mono">
          <span>X: {Math.round(axisX.currentValue * 100)}%</span>
          <span>Y: {Math.round(axisY.currentValue * 100)}%</span>
        </div>
      </div>
    </div>
  );
};

