  const { ui, setTool, undo, redo, history, toggleSettings, isSettingsOpen, setMode } = useStore();

  const isPlayMode = ui.mode === 'play';

  const ToolButton = ({ tool, icon: Icon, label }: { tool: ToolType; icon: any; label: string }) => (
    <button
      onClick={() => setTool(tool)}
      disabled={isPlayMode}
      className={`p-3 rounded-full transition-all duration-200 flex items-center justify-center group relative
        ${ui.selectedTool === tool && !isPlayMode
          ? 'bg-blue-500 text-white shadow-lg scale-105' 
          : 'hover:bg-gray-100 text-gray-600 disabled:opacity-30 disabled:cursor-not-allowed'}`}
    >
      <Icon />
      {!isPlayMode && (
        <span className="absolute top-full mt-2 left-1/2 -translate-x-1/2 bg-gray-800 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-50 pointer-events-none">
          {label}
        </span>
      )}
    </button>
  );

  return (
    <div className="fixed top-6 left-1/2 -translate-x-1/2 z-50">
      <div className="bg-white/90 backdrop-blur-md border border-gray-200/50 shadow-xl rounded-full px-4 py-2 flex items-center gap-3 h-16">

        {/* Undo/Redo */}
        <div className="flex items-center gap-1">
          <button onClick={undo} disabled={history.past.length === 0} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full disabled:opacity-30">
            <Icons.Undo />
          </button>
          <button onClick={redo} disabled={history.future.length === 0} className="p-2 text-gray-500 hover:bg-gray-100 rounded-full disabled:opacity-30">
            <Icons.Redo />
          </button>
        </div>

        <div className="w-px h-8 bg-gray-200" />

        {/* Fixed Width Play Toggle */}
        <button 
           onClick={() => setMode(isPlayMode ? 'edit' : 'play')}
           className={`w-28 py-3 rounded-full transition-all duration-200 flex items-center justify-center gap-2
             ${isPlayMode 
               ? 'bg-green-500 text-white shadow-lg' 
               : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`}
        >
          {isPlayMode ? <Icons.Pause /> : <Icons.Play />}
          <span className="text-sm font-bold">{isPlayMode ? 'Playing' : 'Play'}</span>
        </button>

        <div className="w-px h-8 bg-gray-200" />

        {/* Drawing Tools */}
        <div className={`flex items-center gap-2 transition-opacity ${isPlayMode ? 'opacity-30 pointer-events-none grayscale' : 'opacity-100'}`}>
          <ToolButton tool="cursor" icon={Icons.Cursor} label="Select" />
          <ToolButton tool="pen" icon={Icons.Pen} label="Pen" />
          <ToolButton tool="eraser" icon={Icons.Eraser} label="Eraser" />

          <div className="w-px h-6 bg-gray-200 mx-1" />

          <div className="w-8 h-8 rounded-full border border-gray-200 overflow-hidden cursor-pointer shadow-sm relative group">
             <input type="color" className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" value={ui.brushColor} onChange={(e) => useStore.getState().setBrushColor(e.target.value)} />
             <div className="w-full h-full" style={{ backgroundColor: ui.brushColor }} />
          </div>
        </div>

        <div className="w-px h-8 bg-gray-200" />

        <button 
          onClick={toggleSettings}
          className={`p-3 rounded-full transition-colors ${isSettingsOpen ? 'bg-gray-200 text-gray-900' : 'text-gray-500 hover:bg-gray-100'}`}
        >
          <Icons.Settings />
        </button>

      </div>
    </div>
  );
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { calculateInterpolationWeights, interpolateStrokePoints, snapPointToGrid } from '../utils/math';
import { Point } from '../types';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe } = useStore();

  const [isDrawing, setIsDrawing] = useState(false);
  const currentPointsRef = useRef<Point[]>([]);

  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const availW = contW - margin;
      const availH = contH - margin;
      const scaleW = availW / CANVAS_WIDTH;
      const scaleH = availH / CANVAS_HEIGHT;
      const newScale = Math.min(scaleW, scaleH, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    let p: Point = {
      x: (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width),
      y: (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height),
      pressure: e.pressure || 0.5
    };

    if (ui.snapToGrid && ui.mode === 'edit') {
      p = snapPointToGrid(p, ui.gridSize);
    }
    return p;
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }
    if (ui.selectedTool === 'pen') {
      setIsDrawing(true);
      const p = getCanvasPoint(e);
      currentPointsRef.current = [p];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        const relX = e.clientX - rect.left;
        const relY = e.clientY - rect.top;
        const normX = Math.max(0, Math.min(1, relX / rect.width));
        const normY = Math.max(0, Math.min(1, relY / rect.height));
        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }
    const p = getCanvasPoint(e);
    if (isDrawing) {
      currentPointsRef.current.push(p);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
      (e.target as Element).releasePointerCapture(e.pointerId);
      return;
    }
    if (isDrawing) {
      setIsDrawing(false);
      (e.target as Element).releasePointerCapture(e.pointerId);
      if (currentPointsRef.current.length > 1) {
         addStrokeToCurrentKeyframe([...currentPointsRef.current]);
      }
      currentPointsRef.current = [];
    }
  };

  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID (Dots, Centered)
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;

        // Find start positions to ensure grid passes through center
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);

        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN (Render *all keyframes* in background lightly)
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; // Skip current (active) keyframe

           ctx.globalAlpha = ui.onionSkinOpacity;

           kf.layerStates.forEach(ls => {
              // Only show onion skin for selected layer OR all visible? 
              // Usually onion skin is context dependent. 
              // Let's show onion skin ONLY for the currently selected layer to reduce noise, 
              // or global if multiple. The prompt asked for "differentiation". 
              // Let's stick to selected Layer for clarity in onion skin mode.
              if (ls.layerId !== ui.selectedLayerId) return;

              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);

                // Onion Skin Color: Blueish for visual distinction? Or simple Grey.
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; // Thinner
                ctx.lineCap = 'round';
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);
      const weights = calculateInterpolationWeights(currentAxesDict, project.keyframes);

      const activeKeyframes = project.keyframes
        .map(k => ({ ...k, weight: weights[k.id] || 0 }))
        .filter(k => k.weight > 0.001);

      project.layers.forEach(layer => {
        if (!layer.visible) return;
        const strokeId = `stroke-${layer.id}-unique`;
        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s };
        });

        // Find best reference stroke (prefer one with highest weight)
        strokeData.sort((a, b) => b.weight - a.weight);
        const primaryStroke = strokeData.find(sd => sd.style)?.style;

        // If we have no strokes in active keyframes for this layer, nothing to draw.
        if (!primaryStroke) return;

        const interpolatedPoints = interpolateStrokePoints(
            strokeId,
            primaryStroke.points,
            strokeData.map(sd => ({ weight: sd.weight, points: sd.points })),
            ui.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) {
                ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            }
            ctx.lineCap = 'round';
            ctx.lineJoin = 'round';
            ctx.strokeStyle = primaryStroke.color;
            ctx.lineWidth = primaryStroke.width;

            ctx.globalAlpha = layer.opacity;
            if (layer.blendMode === 'multiply') ctx.globalCompositeOperation = 'multiply';
            else ctx.globalCompositeOperation = 'source-over';

            ctx.stroke();
            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // CURRENT DRAWING
      if (isDrawing && currentPointsRef.current.length > 0) {
        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor;
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : 'cursor-crosshair'}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onPointerLeave={handlePointerUp}
          />
      </div>
    </div>
  );
};

// components/AxisMap.tsx
import React, { useRef } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';

export const AxisMap: React.FC = () => {
  const { project, updateAxisValue, ui, selectKeyframe, deleteKeyframe } = useStore();
  const containerRef = useRef<HTMLDivElement>(null);

  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  const handlePointer = (e: React.PointerEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    // Raw value
    let x = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    let y = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

    const SNAP_INCREMENT = 0.1;
    x = Math.round(x / SNAP_INCREMENT) * SNAP_INCREMENT;
    y = Math.round(y / SNAP_INCREMENT) * SNAP_INCREMENT;

    if (e.buttons > 0) {
      updateAxisValue(axisX.id, x);
      updateAxisValue(axisY.id, y);
      (e.target as Element).setPointerCapture(e.pointerId);
    }
  };

  const selectedKf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-48">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400">Interpolation Matrix</span>

          {selectedKf && project.keyframes.length > 1 && (
             <button 
               onClick={() => deleteKeyframe(selectedKf.id)}
               className="text-[10px] text-red-500 hover:bg-red-50 px-2 py-0.5 rounded"
             >
               Delete State
             </button>
          )}
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-white rounded-lg border border-gray-200 cursor-crosshair overflow-hidden shadow-inner"
          onPointerDown={handlePointer}
          onPointerMove={handlePointer}
        >
          {/* 10x10 Grid Lines */}
          <div className="absolute inset-0" style={{ 
              backgroundImage: 'linear-gradient(#F3F4F6 1px, transparent 1px), linear-gradient(90deg, #F3F4F6 1px, transparent 1px)', 
              backgroundSize: '10% 10%' 
          }}></div>

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;
            const isSelected = ui.selectedKeyframeId === kf.id;

            // DOES THIS KEYFRAME HAVE DATA FOR CURRENT LAYER?
            const hasLayerData = kf.layerStates.some(ls => ls.layerId === ui.selectedLayerId && ls.strokes.length > 0);

            return (
              <div
                key={kf.id}
                onClick={(e) => { e.stopPropagation(); selectKeyframe(kf.id); }}
                className={`absolute -ml-1.5 -mt-1.5 rounded-full transition-transform cursor-pointer hover:scale-125 flex items-center justify-center ${
                    isSelected ? 'z-20 scale-110' : 'z-10'
                }`}
                style={{ 
                    left: `${kfX * 100}%`, 
                    top: `${kfY * 100}%`,
                    width: '12px',
                    height: '12px',
                }}
                title={hasLayerData ? "Active State" : "Empty State (Ghost)"}
              >
                  {/* Outer Ring (Selection) */}
                  {isSelected && (
                      <div className="absolute inset-0 rounded-full border-2 border-blue-500 shadow-sm" />
                  )}

                  {/* Inner Dot (Data Status) */}
                  <div className={`rounded-full ${
                      hasLayerData 
                        ? 'w-2 h-2 bg-gray-800' // Solid dot if data exists
                        : 'w-2 h-2 border border-gray-300 bg-white' // Hollow if ghost
                  }`} />
              </div>
            );
          })}

          {/* Current Cursor */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30 transition-all duration-75 ease-linear"
            style={{ left: `${axisX.currentValue * 100}%`, top: `${axisY.currentValue * 100}%` }}
          >
             <svg viewBox="0 0 24 24" fill="none" stroke={APP_COLORS.primary} strokeWidth="3">
               <line x1="12" y1="0" x2="12" y2="24" />
               <line x1="0" y1="12" x2="24" y2="12" />
             </svg>
          </div>
        </div>

        <div className="mt-2 flex justify-between text-[10px] text-gray-400 font-mono">
          <span>X: {Math.round(axisX.currentValue * 100)}%</span>
          <span>Y: {Math.round(axisY.currentValue * 100)}%</span>
        </div>
      </div>
    </div>
  );
};

