                       else setFillColor('none');
                       setActiveColorPicker(null); 
                   }}
                   title="No Color"
                   >
                       <Icons.NoFill />
                   </button>

                   {PALETTE_COLORS.map(color => (
                     <button
                       key={color}
                       className="w-6 h-6 rounded-full border border-gray-100 hover:scale-110 transition-transform"
                       style={{ backgroundColor: color }}
