// components/AxisMap.tsx
import React, { useRef } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';

export const AxisMap: React.FC = () => {
  const { project, updateAxisValue, ui, selectKeyframe, deleteKeyframe, toggleSnapMatrixGrid } = useStore();
  const containerRef = useRef<HTMLDivElement>(null);

  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  const handlePointer = (e: React.PointerEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    // Raw value
    let x = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    let y = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

    if (ui.snapPlayMode) {
       const SNAP_INCREMENT = 0.1;
       x = Math.round(x / SNAP_INCREMENT) * SNAP_INCREMENT;
       y = Math.round(y / SNAP_INCREMENT) * SNAP_INCREMENT;
    }

    if (e.buttons > 0) {
      updateAxisValue(axisX.id, x);
      updateAxisValue(axisY.id, y);
      (e.target as Element).setPointerCapture(e.pointerId);
    }
  };

  const selectedKf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-48">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400">Interpolation Matrix</span>

          <div className="flex items-center gap-1">
             {/* GRID SNAP TOGGLE (For Keyframes) */}
             <button 
               onClick={toggleSnapMatrixGrid}
               className={`p-1 rounded transition-colors ${ui.snapMatrixGrid ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:bg-gray-100'}`}
               title="Snap Nodes to Grid"
             >
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 10a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/><path d="M4 18a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/><path d="M16 10a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/><path d="M16 18a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/></svg>
             </button>

             {selectedKf && project.keyframes.length > 1 && (
                <button 
                  onClick={() => deleteKeyframe(selectedKf.id)}
                  className="text-[10px] text-red-500 hover:bg-red-50 px-2 py-0.5 rounded"
                >
                  Delete State
                </button>
             )}
          </div>
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-white rounded-lg border border-gray-200 cursor-crosshair overflow-hidden shadow-inner"
          onPointerDown={handlePointer}
          onPointerMove={handlePointer}
        >
          {/* Grid Lines */}
          <div className="absolute inset-0" style={{ 
              backgroundImage: 'linear-gradient(#F3F4F6 1px, transparent 1px), linear-gradient(90deg, #F3F4F6 1px, transparent 1px)', 
              backgroundSize: '10% 10%' 
          }}></div>

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;
            const isSelected = ui.selectedKeyframeId === kf.id;
            const hasDataForCurrentLayer = kf.layerStates.some(ls => ls.layerId === ui.selectedLayerId && ls.strokes.length > 0);

            return (
              <div
                key={kf.id}
                onClick={(e) => { e.stopPropagation(); selectKeyframe(kf.id); }}
                className={`absolute -ml-1.5 -mt-1.5 rounded-full transition-transform cursor-pointer hover:scale-125 flex items-center justify-center ${
                    isSelected ? 'z-20 scale-110' : 'z-10'
                }`}
                style={{ 
                    left: `${kfX * 100}%`, 
                    top: `${kfY * 100}%`,
                    width: '12px',
                    height: '12px',
                }}
                title={hasDataForCurrentLayer ? "Active State" : "Empty State"}
              >
                  {isSelected && (
                      <div className="absolute inset-0 rounded-full border-2 border-blue-500 shadow-sm" />
                  )}

                  <div className={`rounded-full ${
                      hasDataForCurrentLayer
                        ? 'w-2 h-2 bg-gray-800' 
                        : 'w-2 h-2 border border-gray-300 bg-white' 
                  }`} />
              </div>
            );
          })}

          {/* Current Cursor */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30 transition-all duration-75 ease-linear"
            style={{ left: `${axisX.currentValue * 100}%`, top: `${axisY.currentValue * 100}%` }}
          >
             <svg viewBox="0 0 24 24" fill="none" stroke={APP_COLORS.primary} strokeWidth="3">
               <line x1="12" y1="0" x2="12" y2="24" />
               <line x1="0" y1="12" x2="24" y2="12" />
             </svg>
          </div>
        </div>

        <div className="mt-2 flex justify-between text-[10px] text-gray-400 font-mono">
          <span>X: {Math.round(axisX.currentValue * 100)}%</span>
          <span>Y: {Math.round(axisY.currentValue * 100)}%</span>
        </div>
      </div>
    </div>
  );
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke } = useStore();

  // Interaction State
  const [isDrawing, setIsDrawing] = useState(false);
  const currentPointsRef = useRef<Point[]>([]); 

  const [isDraggingStroke, setIsDraggingStroke] = useState(false);
  const [dragStartPos, setDragStartPos] = useState<Point | null>(null);
  const [originalStrokePoints, setOriginalStrokePoints] = useState<Point[]>([]);

  // Bounding Box Interaction (Resize)
  const [isResizing, setIsResizing] = useState(false);
  const [initialBox, setInitialBox] = useState<{minX: number, maxX: number, minY: number, maxY: number} | null>(null);

  // Polyline State
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null); // For polyline preview

  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const availW = contW - margin;
      const availH = contH - margin;
      const scaleW = availW / CANVAS_WIDTH;
      const scaleH = availH / CANVAS_HEIGHT;
      const newScale = Math.min(scaleW, scaleH, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  // --- Helpers ---
  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    let p: Point = {
      x: (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width),
      y: (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height),
      pressure: e.pressure || 0.5
    };

    // Snap only in Edit mode and if enabled (also applied in Play mode for matrix later)
    if (ui.snapToGrid) {
      p = snapPointToGrid(p, ui.gridSize);
    }
    return p;
  };

  const finishPolyline = (closed = false) => {
    if (polylinePoints.length > 1) {
      // Pass 'true' to skip simplification for Polyline strokes
      addStrokeToCurrentKeyframe(polylinePoints, closed, true);
    }
    setPolylinePoints([]);
  };

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    // 1. Play Mode (Axis Control) - Handled in move mostly, but capture here
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }

    // 2. Selection Mode
    if (ui.selectedTool === 'select') {
       // ... Selection Logic ...
       const hitId = findHitStroke(p);
       if (hitId) {
          selectStroke(hitId);
          setIsDraggingStroke(true);
          setDragStartPos(p);

          const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
          if (kf) {
             const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
             if (layerState && layerState.strokes.length > 0) {
                setOriginalStrokePoints(layerState.strokes[0].points);
                const pts = layerState.strokes[0].points;
                setInitialBox({ 
                    minX: Math.min(...pts.map(pt => pt.x)), 
                    maxX: Math.max(...pts.map(pt => pt.x)), 
                    minY: Math.min(...pts.map(pt => pt.y)), 
                    maxY: Math.max(...pts.map(pt => pt.y)) 
                });
             }
          }
          (e.target as Element).setPointerCapture(e.pointerId);
       } else {
          selectStroke(null);
          setInitialBox(null);
       }
       return;
    }

    // 3. Polyline Mode
    if (ui.selectedTool === 'polyline') {
       // Logic: Check if clicking Start Point -> Close Loop
       if (polylinePoints.length > 0) {
           const startPoint = polylinePoints[0];
           if (distance(p, startPoint) < 15) { // Threshold for closing
               finishPolyline(true);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, p]);
       return;
    }

    // 4. Pen
    if (ui.selectedTool === 'pen') {
      setIsDrawing(true);
      currentPointsRef.current = [p]; // Reset points
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(p); // For cursor previews

    // Play Mode
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        const relX = e.clientX - rect.left;
        const relY = e.clientY - rect.top;
        let normX = Math.max(0, Math.min(1, relX / rect.width));
        let normY = Math.max(0, Math.min(1, relY / rect.height));

        // Use snapPlayMode instead of snapToGrid
        if (ui.snapPlayMode) {
            const increments = 10;
            normX = Math.round(normX * increments) / increments;
            normY = Math.round(normY * increments) / increments;
        }

        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }

    // Dragging Stroke (Move)
    if (isDraggingStroke && dragStartPos && ui.selectedStrokeId) {
       const dx = p.x - dragStartPos.x;
       const dy = p.y - dragStartPos.y;
       const newPoints = originalStrokePoints.map(pt => ({
          x: pt.x + dx,
          y: pt.y + dy,
          pressure: pt.pressure
       }));
       updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
       return;
    }

    if (isDrawing && ui.selectedTool === 'pen') {
       currentPointsRef.current.push(p);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
      (e.target as Element).releasePointerCapture(e.pointerId);
      return;
    }

    if (isDraggingStroke) {
       setIsDraggingStroke(false);
       setDragStartPos(null);
    }

    if (isDrawing) {
      setIsDrawing(false);
      if (currentPointsRef.current.length > 1) {
          const start = currentPointsRef.current[0];
          const end = currentPointsRef.current[currentPointsRef.current.length - 1];
          const isClosed = distance(start, end) < 15; // Auto-close Pen

          addStrokeToCurrentKeyframe([...currentPointsRef.current], isClosed);
      }
      currentPointsRef.current = [];
    }

    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  // Double Click to finish Polyline (Open)
  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          finishPolyline(false);
      }
  };

  // Helper to find hit
  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // Keyboard for Polyline Finish
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') finishPolyline(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [polylinePoints]);


  // RENDER LOOP
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);

        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; 
           ctx.globalAlpha = ui.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== ui.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // CURRENT AXES (for Interpolation)
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      // --- LAYER LOOP ---
      project.layers.forEach(layer => {
        if (!layer.visible) return;

        // --- DECOUPLED WEIGHT CALCULATION ---
        // 1. Identify which keyframes actually affect THIS layer
        const layerRelevantKeyframes = project.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        // If no keyframes have data for this layer, nothing to draw
        if (layerRelevantKeyframes.length === 0) return;

        // 2. Calculate weights relative only to these keyframes
        // This ensures that if Keyframe B has no data, it's excluded from the weighted average,
        // preventing the stroke from "fading out" towards B.
        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes);

        // Pre-filter for optimization
        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;

        // --- Inactive Layer Dimming ---
        const isLayerActive = layer.id === ui.selectedLayerId;
        const layerGlobalAlpha = (isLayerActive || ui.mode === 'play') ? layer.opacity : (layer.opacity * ui.inactiveLayerOpacity);

        // Gather stroke variants
        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { 
                weight: kf.weight, 
                points: s?.points, 
                style: s, 
                color: s?.color || 'none', // Handle missing strokes as 'none'
                fillColor: s?.fillColor
            };
        });

        // Topology Basis: Prefer the stroke from the keyframe with the highest weight
        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;

        if (!primaryStroke) return;

        // Interpolate using LAYER SPECIFIC MODE
        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill } = interpolateStrokePoints(
            strokeId,
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode // USE PER LAYER MODE
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) {
                ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            }
            if (primaryStroke.closed) {
                ctx.closePath();
            }

            ctx.globalAlpha = layerGlobalAlpha;

            // Handle Blend Modes
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            // FILL
            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }

            // STROKE
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = primaryStroke.width;
                ctx.stroke();
            }

            // Highlight Selection
            if (ui.selectedStrokeId === primaryStroke.id && ui.mode === 'edit') {
               ctx.strokeStyle = '#3B82F6';
               ctx.lineWidth = 1;
               ctx.setLineDash([5, 5]);
               ctx.stroke();
               ctx.setLineDash([]);
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Pen)
      if (isDrawing && currentPointsRef.current.length > 0) {
        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.2)'; // Hint if none
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) {
             ctx.lineTo(mousePos.x, mousePos.y); 
         }

         // Fill Preview
         if (ui.fillColor !== 'none') {
             ctx.fillStyle = ui.fillColor;
             ctx.globalAlpha = 0.2;
             ctx.fill();
             ctx.globalAlpha = 1.0;
         }

         ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = ui.brushSize;
         ctx.stroke();

         // Draw points (Dots)
         ctx.fillStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.globalAlpha = 0.5;
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();

            // Highlight start point for closing
            if (index === 0 && mousePos && distance(p, mousePos) < 15) {
                ctx.beginPath();
                ctx.strokeStyle = APP_COLORS.primary;
                ctx.lineWidth = 2;
                ctx.arc(p.x, p.y, 8, 0, Math.PI * 2);
                ctx.stroke();
            }
         });
         ctx.globalAlpha = 1.0;
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, polylinePoints, mousePos, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE } from '../constants';
import { simplifyPoints, distance } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;

  setGridSize: (size: number) => void;
  toggleSimplifyStrokes: () => void;

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void; // New
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; // Updated sig
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  selectKeyframe: (keyframeId: string) => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,

  history: {
    past: [],
    future: []
  },

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),
  setBrushColor: (color) => set((state) => ({ ui: { ...state.ui, brushColor: color } })),
  setFillColor: (color) => set((state) => ({ ui: { ...state.ui, fillColor: color } })),
  setBrushSize: (size) => set((state) => ({ ui: { ...state.ui, brushSize: size } })),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSimplifyStrokes: () => set((state) => ({ ui: { ...state.ui, simplifyStrokes: !state.ui.simplifyStrokes } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),

  updateAxisValue: (axisId, value) => set((state) => {
    // CRITICAL FIX: Removed the rounding logic (Math.round(... * 100) / 100).
    // This allows smooth, high-precision floating point updates (e.g. 0.12345 instead of 0.12).
    // This eliminates the "stuttering" effect during animation.
    const cleanValue = Math.max(0, Math.min(1, value));

    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let matchingKfId = state.ui.selectedKeyframeId;

    // Check for exact keyframe match (still needs a small threshold for UI snapping)
    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.01;
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, simplifyStrokes } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    let points = rawPoints;
    if (simplifyStrokes && !skipSimplify) {
       points = simplifyPoints(rawPoints, 1.0);
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    const match = keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      return dist < 0.001; 
    });

    if (match) {
      targetKeyframeId = match.id;
    } else {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: closed
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  })
}));

// utils/math.ts
import { Point, Stroke } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Color Interpolation (RGBA) ---

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 0 };

  // Hex
  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    return {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }

  // Rgb / Rgba
  if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        return {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  // Fallback (could add named colors here if needed)
  return { r: 0, g: 0, b: 0, a: 1 };
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    if (rgba.a > 0) {
        rSum += rgba.r * c.weight * rgba.a;
        gSum += rgba.g * c.weight * rgba.a;
        bSum += rgba.b * c.weight * rgba.a;
    }
    aSum += rgba.a * c.weight;
  }

  if (aSum <= 0.001) return 'rgba(0,0,0,0)';

  let visibleWeight = 0;
  colors.forEach(c => { if (c.color !== 'none') visibleWeight += c.weight; });

  let finalR = 0, finalG = 0, finalB = 0;
  if (visibleWeight > 0.001) {
      let vr = 0, vg = 0, vb = 0;
      for (const c of colors) {
          if (c.color !== 'none') {
             const rgba = parseColor(c.color);
             vr += rgba.r * c.weight;
             vg += rgba.g * c.weight;
             vb += rgba.b * c.weight;
          }
      }
      finalR = vr / visibleWeight;
      finalG = vg / visibleWeight;
      finalB = vb / visibleWeight;
  }

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- Point Index Mapping (Virtual Resampling for 'Points' Mode) ---
const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    // Clamp
    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], closed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse with Hysteresis
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) {
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Cyclic Shifts (Closed only)
    if (closed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }
             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};


export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
): Record<string, number> => {
  const weights: Record<string, number> = {};

  if (keyframes.length === 0) return {};
  if (keyframes.length === 1) {
      weights[keyframes[0].id] = 1.0;
      return weights;
  }

  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / (dist * dist);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) weights[id] /= totalWeight;
  } else {
     weights[keyframes[0].id] = 1;
  }

  return weights;
};

// --- THE CORE INTERPOLATOR ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, color: string, fillColor?: string, width: number }[],
  mode: 'resample' | 'points' = 'resample'
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter and clean inputs
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'rgba(0,0,0,0)', width: 1 };

  // 2. Mix Colors & Width
  const color = mixColors(keyframesData.map(k => ({ color: k.color, weight: k.weight })));
  const fillColor = mixColors(keyframesData.map(k => ({ color: k.fillColor || 'none', weight: k.weight })));

  // Calculate Weighted Width
  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;


  // 3. Determine Target Topology
  let TARGET_COUNT = 0;

  if (mode === 'points') {
      TARGET_COUNT = Math.max(...activeKeyframes.map(k => k.points!.length));
  } else {
      TARGET_COUNT = 200; 
  }

  // 4. Determine Topology Reference (Stable Anchor: First Keyframe)
  const referenceStroke = activeKeyframes[0].points!;
  const referenceResampled = mode === 'resample' 
     ? resamplePoints(referenceStroke, TARGET_COUNT)
     : referenceStroke;

  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length-1]) < 15;

  // 5. Accumulate Points
  const resultPoints: Point[] = [];

  for (let i = 0; i < TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'resample') {
              const resampled = resamplePoints(rawPoints, TARGET_COUNT);
              processedPoints = alignPoints(referenceResampled, resampled, isClosed);
          } else {
              const virtualIndex = i * ((rawPoints.length - 1) / (TARGET_COUNT - 1));
              processedPoints = [getPointAtFractionalIndex(rawPoints, virtualIndex)];
          }

          const pt = (mode === 'resample') ? processedPoints[i] : processedPoints[0];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- Optimization ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke } = useStore();

  // Interaction State
  const [isDrawing, setIsDrawing] = useState(false);
  const currentPointsRef = useRef<Point[]>([]); 

  const [isDraggingStroke, setIsDraggingStroke] = useState(false);
  const [dragStartPos, setDragStartPos] = useState<Point | null>(null);
  const [originalStrokePoints, setOriginalStrokePoints] = useState<Point[]>([]);

  // Bounding Box Interaction (Resize)
  const [isResizing, setIsResizing] = useState(false);
  const [initialBox, setInitialBox] = useState<{minX: number, maxX: number, minY: number, maxY: number} | null>(null);

  // Polyline State
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null); // For polyline preview

  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const availW = contW - margin;
      const availH = contH - margin;
      const scaleW = availW / CANVAS_WIDTH;
      const scaleH = availH / CANVAS_HEIGHT;
      const newScale = Math.min(scaleW, scaleH, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  // --- Helpers ---
  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    let p: Point = {
      x: (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width),
      y: (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height),
      pressure: e.pressure || 0.5
    };

    // Snap only in Edit mode and if enabled (also applied in Play mode for matrix later)
    if (ui.snapToGrid) {
      p = snapPointToGrid(p, ui.gridSize);
    }
    return p;
  };

  const finishPolyline = (closed = false) => {
    if (polylinePoints.length > 1) {
      // Pass 'true' to skip simplification for Polyline strokes
      addStrokeToCurrentKeyframe(polylinePoints, closed, true);
    }
    setPolylinePoints([]);
  };

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    // 1. Play Mode (Axis Control) - Handled in move mostly, but capture here
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }

    // 2. Selection Mode
    if (ui.selectedTool === 'select') {
       // ... Selection Logic ...
       const hitId = findHitStroke(p);
       if (hitId) {
          selectStroke(hitId);
          setIsDraggingStroke(true);
          setDragStartPos(p);

          const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
          if (kf) {
             const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
             if (layerState && layerState.strokes.length > 0) {
                setOriginalStrokePoints(layerState.strokes[0].points);
                const pts = layerState.strokes[0].points;
                setInitialBox({ 
                    minX: Math.min(...pts.map(pt => pt.x)), 
                    maxX: Math.max(...pts.map(pt => pt.x)), 
                    minY: Math.min(...pts.map(pt => pt.y)), 
                    maxY: Math.max(...pts.map(pt => pt.y)) 
                });
             }
          }
          (e.target as Element).setPointerCapture(e.pointerId);
       } else {
          selectStroke(null);
          setInitialBox(null);
       }
       return;
    }

    // 3. Polyline Mode
    if (ui.selectedTool === 'polyline') {
       // Logic: Check if clicking Start Point -> Close Loop
       if (polylinePoints.length > 0) {
           const startPoint = polylinePoints[0];
           if (distance(p, startPoint) < 15) { // Threshold for closing
               finishPolyline(true);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, p]);
       return;
    }

    // 4. Pen
    if (ui.selectedTool === 'pen') {
      setIsDrawing(true);
      currentPointsRef.current = [p]; // Reset points
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(p); // For cursor previews

    // Play Mode
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        const relX = e.clientX - rect.left;
        const relY = e.clientY - rect.top;
        let normX = Math.max(0, Math.min(1, relX / rect.width));
        let normY = Math.max(0, Math.min(1, relY / rect.height));

        // Use snapPlayMode instead of snapToGrid
        if (ui.snapPlayMode) {
            const increments = 10;
            normX = Math.round(normX * increments) / increments;
            normY = Math.round(normY * increments) / increments;
        }

        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }

    // Dragging Stroke (Move)
    if (isDraggingStroke && dragStartPos && ui.selectedStrokeId) {
       const dx = p.x - dragStartPos.x;
       const dy = p.y - dragStartPos.y;
       const newPoints = originalStrokePoints.map(pt => ({
          x: pt.x + dx,
          y: pt.y + dy,
          pressure: pt.pressure
       }));
       updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
       return;
    }

    if (isDrawing && ui.selectedTool === 'pen') {
       currentPointsRef.current.push(p);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
      (e.target as Element).releasePointerCapture(e.pointerId);
      return;
    }

    if (isDraggingStroke) {
       setIsDraggingStroke(false);
       setDragStartPos(null);
    }

    if (isDrawing) {
      setIsDrawing(false);
      if (currentPointsRef.current.length > 1) {
          const start = currentPointsRef.current[0];
          const end = currentPointsRef.current[currentPointsRef.current.length - 1];
          const isClosed = distance(start, end) < 15; // Auto-close Pen

          addStrokeToCurrentKeyframe([...currentPointsRef.current], isClosed);
      }
      currentPointsRef.current = [];
    }

    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  // Double Click to finish Polyline (Open)
  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          finishPolyline(false);
      }
  };

  // Helper to find hit
  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // Keyboard for Polyline Finish
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') finishPolyline(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [polylinePoints]);


  // RENDER LOOP
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);

        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; 
           ctx.globalAlpha = ui.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== ui.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // CURRENT AXES (for Interpolation)
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      // --- LAYER LOOP ---
      project.layers.forEach(layer => {
        if (!layer.visible) return;

        // --- DECOUPLED WEIGHT CALCULATION ---
        const layerRelevantKeyframes = project.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;

        // --- Inactive Layer Dimming ---
        const isLayerActive = layer.id === ui.selectedLayerId;
        const layerGlobalAlpha = (isLayerActive || ui.mode === 'play') ? layer.opacity : (layer.opacity * ui.inactiveLayerOpacity);

        // Gather stroke variants
        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { 
                weight: kf.weight, 
                points: s?.points, 
                style: s, 
                color: s?.color || 'none', 
                fillColor: s?.fillColor,
                width: s?.width || 1 // Pass width for interpolation
            };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;

        if (!primaryStroke) return;

        // Interpolate using LAYER SPECIFIC MODE
        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId,
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) {
                ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            }
            if (primaryStroke.closed) {
                ctx.closePath();
            }

            ctx.globalAlpha = layerGlobalAlpha;

            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            // FILL
            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }

            // STROKE
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth; // Use interpolated width
                ctx.stroke();
            }

            // Highlight Selection
            if (ui.selectedStrokeId === primaryStroke.id && ui.mode === 'edit') {
               ctx.strokeStyle = '#3B82F6';
               ctx.lineWidth = 1;
               ctx.setLineDash([5, 5]);
               ctx.stroke();
               ctx.setLineDash([]);
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Pen)
      if (isDrawing && currentPointsRef.current.length > 0) {
        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.2)'; // Hint if none
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) {
             ctx.lineTo(mousePos.x, mousePos.y); 
         }

         // Fill Preview
         if (ui.fillColor !== 'none') {
             ctx.fillStyle = ui.fillColor;
             ctx.globalAlpha = 0.2;
             ctx.fill();
             ctx.globalAlpha = 1.0;
         }

         ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = ui.brushSize;
         ctx.stroke();

         // Draw points (Dots)
         ctx.fillStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.globalAlpha = 0.5;
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();

            // Highlight start point for closing
            if (index === 0 && mousePos && distance(p, mousePos) < 15) {
                ctx.beginPath();
                ctx.strokeStyle = APP_COLORS.primary;
                ctx.lineWidth = 2;
                ctx.arc(p.x, p.y, 8, 0, Math.PI * 2);
                ctx.stroke();
            }
         });
         ctx.globalAlpha = 1.0;
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, polylinePoints, mousePos, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// components/AxisMap.tsx
import React, { useRef } from 'react';
import { useStore } from '../store/useStore';
import { APP_COLORS } from '../constants';

export const AxisMap: React.FC = () => {
  const { project, updateAxisValue, ui, selectKeyframe, deleteKeyframe, toggleSnapMatrixGrid } = useStore();
  const containerRef = useRef<HTMLDivElement>(null);

  const axisX = project.axes.find(a => a.id === 'axis-x');
  const axisY = project.axes.find(a => a.id === 'axis-y');

  if (!axisX || !axisY) return null;

  const handlePointer = (e: React.PointerEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();

    // Raw value
    let x = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    let y = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

    if (ui.snapPlayMode) {
       const SNAP_INCREMENT = 0.1;
       x = Math.round(x / SNAP_INCREMENT) * SNAP_INCREMENT;
       y = Math.round(y / SNAP_INCREMENT) * SNAP_INCREMENT;
    }

    if (e.buttons > 0) {
      updateAxisValue(axisX.id, x);
      updateAxisValue(axisY.id, y);
      (e.target as Element).setPointerCapture(e.pointerId);
    }
  };

  const selectedKf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);

  return (
    <div className="fixed bottom-6 left-6 z-50 flex flex-col gap-2">
      <div className="bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-200 p-3 w-48">
        <div className="flex justify-between items-center mb-2">
          <span className="text-[10px] uppercase font-bold text-gray-400">Interpolation Matrix</span>

          <div className="flex items-center gap-1">
             {/* GRID SNAP TOGGLE (For Keyframes) */}
             <button 
               onClick={toggleSnapMatrixGrid}
               className={`p-1 rounded transition-colors ${ui.snapMatrixGrid ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:bg-gray-100'}`}
               title="Snap Nodes to Grid"
             >
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 10a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/><path d="M4 18a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/><path d="M16 10a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/><path d="M16 18a2 2 0 1 0 4 0a2 2 0 1 0 -4 0"/></svg>
             </button>

             {selectedKf && project.keyframes.length > 1 && (
                <button 
                  onClick={() => deleteKeyframe(selectedKf.id)}
                  className="text-[10px] text-red-500 hover:bg-red-50 px-2 py-0.5 rounded"
                >
                  Delete State
                </button>
             )}
          </div>
        </div>

        <div 
          ref={containerRef}
          className="relative w-full aspect-square bg-white rounded-lg border border-gray-200 cursor-crosshair overflow-hidden shadow-inner"
          onPointerDown={handlePointer}
          onPointerMove={handlePointer}
        >
          {/* Grid Lines */}
          <div className="absolute inset-0" style={{ 
              backgroundImage: 'linear-gradient(#F3F4F6 1px, transparent 1px), linear-gradient(90deg, #F3F4F6 1px, transparent 1px)', 
              backgroundSize: '10% 10%' 
          }}></div>

          {/* Keyframes Dots */}
          {project.keyframes.map(kf => {
            const kfX = kf.axisValues[axisX.id] ?? 0.5;
            const kfY = kf.axisValues[axisY.id] ?? 0.5;
            const isSelected = ui.selectedKeyframeId === kf.id;
            const hasDataForCurrentLayer = kf.layerStates.some(ls => ls.layerId === ui.selectedLayerId && ls.strokes.length > 0);

            return (
              <div
                key={kf.id}
                onClick={(e) => { e.stopPropagation(); selectKeyframe(kf.id); }}
                className={`absolute -ml-1.5 -mt-1.5 rounded-full transition-transform cursor-pointer hover:scale-125 flex items-center justify-center ${
                    isSelected ? 'z-20 scale-110' : 'z-10'
                }`}
                style={{ 
                    left: `${kfX * 100}%`, 
                    top: `${kfY * 100}%`,
                    width: '12px',
                    height: '12px',
                }}
                title={hasDataForCurrentLayer ? "Active State" : "Empty State"}
              >
                  {isSelected && (
                      <div className="absolute inset-0 rounded-full border-2 border-blue-500 shadow-sm" />
                  )}

                  <div className={`rounded-full ${
                      hasDataForCurrentLayer
                        ? 'w-2 h-2 bg-gray-800' 
                        : 'w-2 h-2 border border-gray-300 bg-white' 
                  }`} />
              </div>
            );
          })}

          {/* Current Cursor (NO TRANSITION for immediate feel) */}
          <div 
            className="absolute w-4 h-4 -ml-2 -mt-2 pointer-events-none z-30"
            style={{ left: `${axisX.currentValue * 100}%`, top: `${axisY.currentValue * 100}%` }}
          >
             <svg viewBox="0 0 24 24" fill="none" stroke={APP_COLORS.primary} strokeWidth="3">
               <line x1="12" y1="0" x2="12" y2="24" />
               <line x1="0" y1="12" x2="24" y2="12" />
             </svg>
          </div>
        </div>

        <div className="mt-2 flex justify-between text-[10px] text-gray-400 font-mono">
          <span>X: {(axisX.currentValue * 100).toFixed(1)}%</span>
          <span>Y: {(axisY.currentValue * 100).toFixed(1)}%</span>
        </div>
      </div>
    </div>
  );
};

// types.ts

// --- Basic Geometry ---
export interface Point {
  x: number;
  y: number;
  pressure?: number; // 0 to 1
}

export interface Size {
  width: number;
  height: number;
}

// --- Vector Elements ---
export type StrokeStyle = 'solid' | 'dashed' | 'dotted';

export interface Stroke {
  id: string;
  points: Point[];
  color: string;
  width: number;
  style: StrokeStyle;
  closed: boolean; // True for shapes, false for lines
  fillColor?: string; // Optional fill (if undefined/null, no fill)
}

// --- Layers ---
export type BlendMode = 'normal' | 'multiply' | 'screen' | 'overlay' | 'difference' | 'exclusion';
export type InterpolationMode = 'resample' | 'points';

export interface Layer {
  id: string;
  name: string;
  visible: boolean;
  locked: boolean;
  blendMode: BlendMode;
  opacity: number;
  interpolationMode: InterpolationMode; // Per-layer setting
}

// --- Axes & Keyframes (The Interpolation Engine) ---
export type AxisType = 'mouseX' | 'mouseY' | 'scrollLoop' | 'stylus' | 'time';

export interface Axis {
  id: string;
  name: string;
  type: AxisType;
  min: number;
  max: number;
  currentValue: number; // The live value (0-1 usually)
}

export interface LayerState {
  layerId: string;
  strokes: Stroke[]; // In "Puppet Mode", this array will typically contain exactly ONE stroke.
}

export interface Keyframe {
  id: string;
  name: string;
  // Position in the N-dimensional axis space
  axisValues: Record<string, number>; // e.g., { "x": 0.5, "y": 0 }
  // The content of the drawing at this specific state
  layerStates: LayerState[]; 
}

// --- Project Structure ---
export interface Project {
  id: string;
  name: string;
  version: string;
  created: number;
  modified: number;
  canvasSize: Size; // Fixed dimensions for the artboard
  axes: Axis[];
  layers: Layer[];
  keyframes: Keyframe[];
}

// --- UI State ---
export type ToolType = 'cursor' | 'select' | 'pen' | 'polyline'; // Eraser removed
export type UIMode = 'edit' | 'play';

export interface UIState {
  mode: UIMode;
  selectedTool: ToolType;
  selectedLayerId: string | null;
  selectedKeyframeId: string | null;
  selectedStrokeId: string | null; // For Selection Tool

  isPlaying: boolean;
  isLayerPanelOpen: boolean;

  // Canvas Helpers
  showGrid: boolean;
  snapToGrid: boolean; // Drawing Snap

  // Matrix Helpers
  snapPlayMode: boolean; // Snap Cursor in Matrix
  snapMatrixGrid: boolean; // Snap Keyframes in Matrix (New)
  axisMatrixDivisions: number; // How many grid lines (e.g. 5 for 5x5)
  axisMatrixPadding: number; // Percentage padding (0.1 = 10%)

  gridSize: number;

  // Animation Helpers
  simplifyStrokes: boolean; // New option
  onionSkinEnabled: boolean;
  onionSkinOpacity: number;
  inactiveLayerOpacity: number; // 0 to 1, opacity of non-selected layers

  // Visual Feedback
  ghostStrokeOpacity: number; // Opacity when drawing in a new/undefined state

  zoom: number;
  pan: Point;
  brushSize: number;
  brushColor: string | 'none'; // Can be none now
  fillColor: string | 'none'; 
}

