import React, { useState, useRef } from 'react';
import { useStore } from '../store/useStore';
import { BlendMode } from '../types';

export const LayerPanel: React.FC = () => {
  const { project, toggleLayerVisibility, toggleLayerLock, setLayerBlendMode, setLayerInterpolationMode, selectLayer, addLayer, deleteLayer, renameLayer, reorderLayers, ui, toggleLayerPanel } = useStore();
  const layers = project.layers;

  // Drag and Drop State
  const [draggedLayerIndex, setDraggedLayerIndex] = useState<number | null>(null);

  // Toggle Button (Visible when panel is closed)
  if (!ui.isLayerPanelOpen) {
    return (
       <button 
         onClick={(e) => { e.stopPropagation(); toggleLayerPanel(); }}
         className="absolute left-6 top-28 bg-white/90 p-2 rounded-xl shadow-lg border border-gray-100 text-gray-500 hover:text-gray-900 transition-colors pointer-events-auto"
         title="Open Layers"
       >
         <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M2 17L12 22L22 17"/><path d="M2 12L12 17L22 12"/><path d="M12 2L2 7L12 12L22 7L12 2Z"/></svg>
       </button>
    );
  }

  const handleRename = (id: string, currentName: string) => {
    const newName = prompt("Rename layer:", currentName);
    if (newName) renameLayer(id, newName);
  };

  const onDragStart = (e: React.DragEvent, index: number) => {
      setDraggedLayerIndex(index);
      e.dataTransfer.effectAllowed = "move";
  };

  const onDragOver = (e: React.DragEvent, index: number) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = "move";
  };

  const onDrop = (e: React.DragEvent, targetIndex: number) => {
      e.preventDefault();
      if (draggedLayerIndex === null) return;

      const realDragIndex = layers.length - 1 - draggedLayerIndex;
      const realTargetIndex = layers.length - 1 - targetIndex;

      reorderLayers(realDragIndex, realTargetIndex);
      setDraggedLayerIndex(null);
  };

  return (
    <div 
      onClick={(e) => e.stopPropagation()}
      className="absolute left-6 top-28 w-64 bg-white/90 backdrop-blur-md rounded-2xl shadow-xl border border-gray-100 overflow-hidden flex flex-col max-h-[50vh] pointer-events-auto transition-all duration-300"
    >
      <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-white/50">
        <h2 className="font-bold text-gray-700 text-sm">Layers</h2>
        <div className="flex gap-2">
            <button 
              onClick={addLayer}
              className="text-blue-500 hover:bg-blue-50 rounded-full p-1 transition-colors"
              title="Add New Layer"
            >
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 5v14M5 12h14"/></svg>
            </button>
            <button onClick={toggleLayerPanel} className="text-gray-400 hover:text-gray-600">
               <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="18 15 12 9 6 15"></polyline></svg>
            </button>
        </div>
      </div>

      <div className="overflow-y-auto flex-1 p-2 space-y-1">
        {[...layers].reverse().map((layer, index) => (
          <div 
            key={layer.id}
            draggable
            onDragStart={(e) => onDragStart(e, index)}
            onDragOver={(e) => onDragOver(e, index)}
            onDrop={(e) => onDrop(e, index)}
            onClick={() => selectLayer(layer.id)}
            className={`group flex items-center gap-2 p-2 rounded-xl text-sm cursor-pointer transition-all border relative ${
              ui.selectedLayerId === layer.id 
                ? 'bg-blue-50 border-blue-200 text-blue-900 shadow-sm' 
                : 'hover:bg-gray-50 border-transparent text-gray-600'
            } ${draggedLayerIndex === index ? 'opacity-50' : ''}`}
          >
            <div className="cursor-grab text-gray-300 hover:text-gray-500">
                <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><circle cx="9" cy="5" r="2"/><circle cx="9" cy="12" r="2"/><circle cx="9" cy="19" r="2"/><circle cx="15" cy="5" r="2"/><circle cx="15" cy="12" r="2"/><circle cx="15" cy="19" r="2"/></svg>
            </div>

            <button 
              onClick={(e) => { e.stopPropagation(); toggleLayerVisibility(layer.id); }}
              className={`w-5 h-5 flex items-center justify-center ${layer.visible ? 'text-gray-600' : 'text-gray-300'}`}
            >
              {layer.visible 
                ? <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
                : <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>
              }
            </button>

            <span 
               className="truncate flex-1 font-medium select-none"
               onDoubleClick={() => handleRename(layer.id, layer.name)}
            >
               {layer.name}
            </span>

            <div className="flex gap-1 items-center">
                 <button 
                    onClick={(e) => { 
                       e.stopPropagation(); 
                       setLayerInterpolationMode(layer.id, layer.interpolationMode === 'resample' ? 'points' : 'resample'); 
                    }}
                    className={`p-1 rounded text-[10px] font-bold uppercase transition-colors ${layer.interpolationMode === 'resample' ? 'text-blue-500 bg-blue-50' : 'text-orange-500 bg-orange-50'}`}
                    title={layer.interpolationMode === 'resample' ? 'Mode: Resample (Curve)' : 'Mode: Points (Raw)'}
                 >
                    {layer.interpolationMode === 'resample' ? 'CRV' : 'PNT'}
                 </button>

                 <button
                    onClick={(e) => { e.stopPropagation(); deleteLayer(layer.id); }}
                    className="text-red-400 hover:text-red-600 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                    title="Delete Layer"
                 >
                   <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                 </button>

                 <button
                   onClick={(e) => {
                     e.stopPropagation();
                     const modes: BlendMode[] = ['normal', 'multiply', 'screen', 'difference', 'exclusion'];
                     const nextMode = modes[(modes.indexOf(layer.blendMode) + 1) % modes.length];
                     setLayerBlendMode(layer.id, nextMode);
                   }}
                   className={`text-[9px] uppercase font-bold px-1.5 py-0.5 rounded border min-w-[30px] ${
                     layer.blendMode !== 'normal' 
                        ? 'bg-purple-100 text-purple-700 border-purple-200' 
                        : 'bg-gray-100 text-gray-500 border-gray-200'
                   }`}
                   title={`Blend: ${layer.blendMode}`}
                 >
                  {layer.blendMode.substring(0, 3)}
                </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export const SettingsPanel: React.FC = () => {
  const { project, isSettingsOpen, toggleSettings, ui, toggleGrid, toggleSnapToGrid, toggleOnionSkin, setGridSize, setOnionSkinOpacity, toggleSimplifyStrokes, setInactiveLayerOpacity, toggleSnapPlayMode, resetProject, loadProject, toggleSnapMatrixGrid, setAxisMatrixDivisions, setAxisMatrixPadding, setGhostStrokeOpacity, setInterpolationExponent } = useStore();

  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isSettingsOpen) return null;

  const handleExport = () => {
      const data = JSON.stringify(project, null, 2);
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${project.name.replace(/\s+/g, '_').toLowerCase()}_v${project.version}.json`;
      a.click();
      URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onload = (event) => {
              try {
                  const json = JSON.parse(event.target?.result as string);
                  loadProject(json);
              } catch (err) {
                  alert("Invalid project file.");
              }
          };
          reader.readAsText(file);
      }
  };

  return (
    <div 
      onClick={(e) => e.stopPropagation()}
      className="absolute top-28 right-6 w-80 bg-white/90 backdrop-blur-xl rounded-2xl shadow-2xl border border-gray-200 z-50 p-5 pointer-events-auto max-h-[80vh] overflow-y-auto"
    >
      <div className="flex justify-between items-center mb-5">
        <h3 className="font-bold text-gray-800 text-base">Settings</h3>
        <button onClick={toggleSettings} className="text-gray-400 hover:text-gray-600">
           <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="18 15 12 9 6 15"></polyline></svg>
        </button>
      </div>

      <div className="space-y-6">

        {/* Project Management */}
        <div className="space-y-3">
             <label className="text-xs font-bold text-gray-400 uppercase tracking-wider block">Project</label>
             <div className="flex gap-2">
                 <button onClick={handleExport} className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-700 text-xs font-bold py-2 rounded-lg flex items-center justify-center gap-1">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                    Export
                 </button>
                 <button onClick={() => fileInputRef.current?.click()} className="flex-1 bg-gray-100 hover:bg-gray-200 text-gray-700 text-xs font-bold py-2 rounded-lg flex items-center justify-center gap-1">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
                    Import
                 </button>
                 <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />
             </div>
             <button onClick={() => { if(confirm('Reset project? Unsaved changes will be lost.')) resetProject(); }} className="w-full bg-red-50 hover:bg-red-100 text-red-600 text-xs font-bold py-2 rounded-lg border border-red-100">
                Reset Canvas
             </button>
        </div>

        <hr className="border-gray-100" />

        {/* Matrix Configuration */}
        <div className="space-y-3">
           <label className="text-xs font-bold text-gray-400 uppercase tracking-wider block">Interpolation Matrix</label>

           <div className="flex items-center justify-between">
            <span className="text-sm text-gray-600">Snap to Grid</span>
            <button 
               onClick={toggleSnapMatrixGrid}
               className={`w-10 h-5 rounded-full relative transition-colors ${ui.snapMatrixGrid ? 'bg-blue-500' : 'bg-gray-300'}`}
            >
               <div className={`w-3 h-3 bg-white rounded-full absolute top-1 transition-all ${ui.snapMatrixGrid ? 'left-6' : 'left-1'}`} />
            </button>
          </div>

          <div className="space-y-1">
             <div className="flex justify-between text-xs text-gray-500">
               <span>Grid Divisions</span>
               <span>{ui.axisMatrixDivisions}x{ui.axisMatrixDivisions}</span>
             </div>
             <input 
                type="range" min="2" max="20" step="1" 
                value={ui.axisMatrixDivisions} 
                onChange={(e) => setAxisMatrixDivisions(parseInt(e.target.value))}
                className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer"
             />
          </div>

          <div className="space-y-1">
             <div className="flex justify-between text-xs text-gray-500">
               <span>Edge Padding</span>
               <span>{Math.round(ui.axisMatrixPadding * 100)}%</span>
             </div>
             <input 
                type="range" min="0" max="0.2" step="0.01" 
                value={ui.axisMatrixPadding} 
                onChange={(e) => setAxisMatrixPadding(parseFloat(e.target.value))}
