          <div className="space-y-1">
             <div className="flex justify-between text-xs text-gray-500">
               <span title="Controls how quickly influence drops off. 1 = Linear (Smooth), 2 = Square (Sharp)">Interpolation Power</span>
               <span>{ui.interpolationExponent.toFixed(1)}</span>
             </div>
             <input 
                type="range" min="0.5" max="3.0" step="0.1" 
                value={ui.interpolationExponent} 
                onChange={(e) => setInterpolationExponent(parseFloat(e.target.value))}
