             />
          </div>
        </div>

        <hr className="border-gray-100" />

        {/* Visual Config */}
        <div className="space-y-3">
           <label className="text-xs font-bold text-gray-400 uppercase tracking-wider block">Visuals</label>

           <div className="flex items-center justify-between">
            <span className="text-sm text-gray-600">Show Canvas Grid</span>
            <button 
               onClick={toggleGrid}
               className={`w-10 h-5 rounded-full relative transition-colors ${ui.showGrid ? 'bg-blue-500' : 'bg-gray-300'}`}
            >
               <div className={`w-3 h-3 bg-white rounded-full absolute top-1 transition-all ${ui.showGrid ? 'left-6' : 'left-1'}`} />
            </button>
          </div>

           <div className="space-y-1">
             <div className="flex justify-between text-xs text-gray-500">
               <span>Ghost Opacity (New State)</span>
               <span>{Math.round(ui.ghostStrokeOpacity * 100)}%</span>
             </div>
             <input 
                type="range" min="0.0" max="1.0" step="0.05" 
                value={ui.ghostStrokeOpacity} 
                onChange={(e) => setGhostStrokeOpacity(parseFloat(e.target.value))}
                className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer"
             />
          </div>

           <div className="space-y-1">
             <div className="flex justify-between text-xs text-gray-500">
               <span>Onion Skin Opacity</span>
               <span>{Math.round(ui.onionSkinOpacity * 100)}%</span>
             </div>
             <input 
                type="range" min="0.05" max="0.5" step="0.05" 
                value={ui.onionSkinOpacity} 
                onChange={(e) => setOnionSkinOpacity(parseFloat(e.target.value))}
                className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer"
             />
          </div>
        </div>
      </div>
    </div>
  );
};

// types.ts

// --- Basic Geometry ---
export interface Point {
  x: number;
  y: number;
  pressure?: number; // 0 to 1
}

export interface Size {
  width: number;
  height: number;
}

// --- Vector Elements ---
export type StrokeStyle = 'solid' | 'dashed' | 'dotted';

export interface Stroke {
  id: string;
  points: Point[];
  color: string;
  width: number;
  style: StrokeStyle;
  closed: boolean; // True for shapes, false for lines
  fillColor?: string; // Optional fill (if undefined/null, no fill)
}

// --- Layers ---
export type BlendMode = 'normal' | 'multiply' | 'screen' | 'overlay' | 'difference' | 'exclusion';
export type InterpolationMode = 'resample' | 'points';

export interface Layer {
  id: string;
  name: string;
  visible: boolean;
  locked: boolean;
  blendMode: BlendMode;
  opacity: number;
  interpolationMode: InterpolationMode; // Per-layer setting
}

// --- Axes & Keyframes (The Interpolation Engine) ---
export type AxisType = 'mouseX' | 'mouseY' | 'scrollLoop' | 'stylus' | 'time';

export interface Axis {
  id: string;
  name: string;
  type: AxisType;
  min: number;
  max: number;
  currentValue: number; // The live value (0-1 usually)
}

export interface LayerState {
  layerId: string;
  strokes: Stroke[]; // In "Puppet Mode", this array will typically contain exactly ONE stroke.
}

export interface Keyframe {
  id: string;
  name: string;
  // Position in the N-dimensional axis space
  axisValues: Record<string, number>; // e.g., { "x": 0.5, "y": 0 }
  // The content of the drawing at this specific state
  layerStates: LayerState[]; 
}

// --- Project Structure ---
export interface Project {
  id: string;
  name: string;
  version: string;
  created: number;
  modified: number;
  canvasSize: Size; // Fixed dimensions for the artboard
  axes: Axis[];
  layers: Layer[];
  keyframes: Keyframe[];
}

// --- UI State ---
export type ToolType = 'cursor' | 'select' | 'pen' | 'polyline'; 
export type UIMode = 'edit' | 'play';
export type InterpolationStrategy = 'idw' | 'linear-neighbor'; // New Strategy Option

