            <div className="flex gap-1 p-1 bg-gray-100 rounded-lg">
                <button 
                    onClick={() => setInterpolationStrategy('linear-neighbor')}
                    className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${ui.interpolationStrategy === 'linear-neighbor' ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Linear (Grid)
