// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Color Interpolation (RGBA) ---

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 0 };

  // Hex
  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    return {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }

  // Rgb / Rgba
  if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        return {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  // Fallback (could add named colors here if needed)
  return { r: 0, g: 0, b: 0, a: 1 };
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    if (rgba.a > 0) {
        rSum += rgba.r * c.weight * rgba.a;
        gSum += rgba.g * c.weight * rgba.a;
        bSum += rgba.b * c.weight * rgba.a;
    }
    aSum += rgba.a * c.weight;
  }

  if (aSum <= 0.001) return 'rgba(0,0,0,0)';

  let visibleWeight = 0;
  colors.forEach(c => { if (c.color !== 'none') visibleWeight += c.weight; });

  let finalR = 0, finalG = 0, finalB = 0;
  if (visibleWeight > 0.001) {
      let vr = 0, vg = 0, vb = 0;
      for (const c of colors) {
          if (c.color !== 'none') {
             const rgba = parseColor(c.color);
             vr += rgba.r * c.weight;
             vg += rgba.g * c.weight;
             vb += rgba.b * c.weight;
          }
      }
      finalR = vr / visibleWeight;
      finalG = vg / visibleWeight;
      finalB = vb / visibleWeight;
  }

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- Point Index Mapping (Virtual Resampling for 'Points' Mode) ---
const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    // Clamp
    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], closed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse with Hysteresis
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) {
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Cyclic Shifts (Closed only)
    if (closed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }
             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

// Strategy 1: Global Inverse Distance Weighting (Spherical influence)
const calculateIDWWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number
) => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / Math.pow(dist, exponent);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) weights[id] /= totalWeight;
  } else {
     weights[keyframes[0].id] = 1;
  }
  return weights;
};

// Strategy 2: Bilinear Grid Interpolation (Axis-Separated)
// This strictly calculates weights based on finding the X-interval and Y-interval
// creating a grid cell, then applying bilinear weights. It handles "Out of bounds"
// by clamping to the nearest edge line.
const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;

  // 1. Extract Unique, Sorted Coordinates for Grid Lines
  // We use an Epsilon to group points that are technically "aligned"
  const EPSILON = 0.005;

  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) {
              result.push(sorted[i]);
          }
      }
      return result;
  };

  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  // 2. Find Interval (Cell) and Normalize (Clamped)
  // Logic: Find index 'i' such that grid[i] <= val <= grid[i+1]

  const findInterval = (val: number, grid: number[]) => {
      // Clamp to edges
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };

      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              const t = span === 0 ? 0 : (val - grid[i]) / span;
              return { lower: grid[i], upper: grid[i+1], t };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 }; // Fallback
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  // 3. Identify the 4 Grid Corners
  // We need to find keyframes that match these coordinates.
  // Note: There might be multiple keyframes at the same coordinate (unlikely in this UI but possible)
  // or NO keyframe at a corner (Sparse grid).

  // Weights for the abstract corners
  const wTL = (1 - xInfo.t) * (1 - yInfo.t);
  const wTR = xInfo.t * (1 - yInfo.t);
  const wBL = (1 - xInfo.t) * yInfo.t;
  const wBR = xInfo.t * yInfo.t;

  // Helper to find matching keyframe
  const findKeyframeAt = (x: number, y: number) => {
      return keyframes.find(k => 
          Math.abs((k.axisValues['axis-x'] || 0) - x) < EPSILON && 
          Math.abs((k.axisValues['axis-y'] || 0) - y) < EPSILON
      );
  };

  // 4. Distribute Weights to Actual Keyframes
  // If a corner keyframe is missing, its weight disappears (effectively normalized out later)
  // or we could distribute it to neighbors. For now, simple attribution.

  const addWeight = (x: number, y: number, w: number) => {
      if (w <= 0.0001) return;
      const kf = findKeyframeAt(x, y);
      if (kf) {
          weights[kf.id] = (weights[kf.id] || 0) + w;
      }
  };

  addWeight(xInfo.lower, yInfo.lower, wTL); // Top-Left
  addWeight(xInfo.upper, yInfo.lower, wTR); // Top-Right
  addWeight(xInfo.lower, yInfo.upper, wBL); // Bottom-Left
  addWeight(xInfo.upper, yInfo.upper, wBR); // Bottom-Right

  // 5. Normalize
  let totalW = 0;
  for (const id in weights) totalW += weights[id];

  if (totalW > 0) {
      for (const id in weights) weights[id] /= totalW;
  } else {
      // Fallback: Closest Keyframe by simple distance
      let minDist = Infinity;
      let closestId = keyframes[0].id;
      keyframes.forEach(k => {
          const d = Math.sqrt(Math.pow(curX - (k.axisValues['axis-x']||0), 2) + Math.pow(curY - (k.axisValues['axis-y']||0), 2));
          if (d < minDist) { minDist = d; closestId = k.id; }
      });
      weights[closestId] = 1;
  }

  return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {

   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) {
       return { [keyframes[0].id]: 1.0 };
   }

   if (strategy === 'bilinear-grid') {
       return calculateBilinearGridWeights(currentAxes, keyframes);
   } else {
       return calculateIDWWeights(currentAxes, keyframes, exponent);
   }
};

// --- THE CORE INTERPOLATOR ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, color: string, fillColor?: string, width: number }[],
  mode: 'resample' | 'points' = 'resample'
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter and clean inputs
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'rgba(0,0,0,0)', width: 1 };

  // 2. Mix Colors & Width
  const color = mixColors(keyframesData.map(k => ({ color: k.color, weight: k.weight })));
  const fillColor = mixColors(keyframesData.map(k => ({ color: k.fillColor || 'none', weight: k.weight })));

  // Calculate Weighted Width
  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;


  // 3. Determine Target Topology
  let TARGET_COUNT = 0;

  if (mode === 'points') {
      TARGET_COUNT = Math.max(...activeKeyframes.map(k => k.points!.length));
  } else {
      TARGET_COUNT = 200; 
  }

  // 4. Determine Topology Reference (Stable Anchor: First Keyframe)
  const referenceStroke = activeKeyframes[0].points!;
  const referenceResampled = mode === 'resample' 
     ? resamplePoints(referenceStroke, TARGET_COUNT)
     : referenceStroke;

  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length-1]) < 15;

  // 5. Accumulate Points
  const resultPoints: Point[] = [];

  for (let i = 0; i < TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'resample') {
              const resampled = resamplePoints(rawPoints, TARGET_COUNT);
              processedPoints = alignPoints(referenceResampled, resampled, isClosed);
          } else {
              const virtualIndex = i * ((rawPoints.length - 1) / (TARGET_COUNT - 1));
              processedPoints = [getPointAtFractionalIndex(rawPoints, virtualIndex)];
          }

          const pt = (mode === 'resample') ? processedPoints[i] : processedPoints[0];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- Optimization ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

