// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Color Interpolation (RGBA) ---

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 0 };

  // Hex
  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    return {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }

  // Rgb / Rgba
  if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        return {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  // Fallback (could add named colors here if needed)
  return { r: 0, g: 0, b: 0, a: 1 };
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    if (rgba.a > 0) {
        rSum += rgba.r * c.weight * rgba.a;
        gSum += rgba.g * c.weight * rgba.a;
        bSum += rgba.b * c.weight * rgba.a;
    }
    aSum += rgba.a * c.weight;
  }

  if (aSum <= 0.001) return 'rgba(0,0,0,0)';

  let visibleWeight = 0;
  colors.forEach(c => { if (c.color !== 'none') visibleWeight += c.weight; });

  let finalR = 0, finalG = 0, finalB = 0;
  if (visibleWeight > 0.001) {
      let vr = 0, vg = 0, vb = 0;
      for (const c of colors) {
          if (c.color !== 'none') {
             const rgba = parseColor(c.color);
             vr += rgba.r * c.weight;
             vg += rgba.g * c.weight;
             vb += rgba.b * c.weight;
          }
      }
      finalR = vr / visibleWeight;
      finalG = vg / visibleWeight;
      finalB = vb / visibleWeight;
  }

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- Point Index Mapping (Virtual Resampling for 'Points' Mode) ---
const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    // Clamp
    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], closed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse with Hysteresis
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) {
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Cyclic Shifts (Closed only)
    if (closed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }
             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

// Strategy 1: Global Inverse Distance Weighting (Spherical influence)
const calculateIDWWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number
) => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / Math.pow(dist, exponent);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) weights[id] /= totalWeight;
  } else {
     weights[keyframes[0].id] = 1;
  }
  return weights;
};

// Strategy 2: Grid-Fill Bilinear (Robust Sparse Grid)
// This algorithm fills "holes" in the grid by projecting nearest neighbors
// along axes, ensuring a square bilinear interpolation even with missing corners.
const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  // 1. Extract Grid Lines
  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  // 2. Identify Active Cell (Clamp to edges)
  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  // 3. Helper: Get Virtual Weight for a Corner
  // If a keyframe exists at (targetX, targetY), return { [id]: 1 }.
  // If not, infer it from neighbors on the same Column or Row.
  const resolveCornerWeights = (targetX: number, targetY: number) => {
      const exact = keyframes.find(k => 
          Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && 
          Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON
      );
      if (exact) return { [exact.id]: 1.0 };

      // Missing exact corner? Try Vertical Interpolation (Column Scan)
      const colKfs = keyframes.filter(k => Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON);
      if (colKfs.length > 0) {
          // Find closest above and below
          let above = null, below = null;
          let minAboveDist = Infinity, minBelowDist = Infinity;

          colKfs.forEach(k => {
              const ky = k.axisValues['axis-y'] || 0;
              const dy = ky - targetY;
              if (dy >= 0 && dy < minAboveDist) { above = k; minAboveDist = dy; } // Found lower bound (physically above in logic)
              if (dy <= 0 && -dy < minBelowDist) { below = k; minBelowDist = -dy; }
          });

          // Note: Variable naming 'above/below' vs coordinate Y direction might be flip, 
          // but logic holds: we want bracketing neighbors on Y axis.

          // Re-sort to strictly High/Low
          const sortedY = colKfs.sort((a,b) => (a.axisValues['axis-y']||0) - (b.axisValues['axis-y']||0));
          const lowerK = sortedY.find(k => (k.axisValues['axis-y']||0) >= targetY) || sortedY[sortedY.length-1];
          const upperK = [...sortedY].reverse().find(k => (k.axisValues['axis-y']||0) <= targetY) || sortedY[0];

          if (lowerK && upperK) {
               if (lowerK.id === upperK.id) return { [lowerK.id]: 1.0 };
               const y1 = upperK.axisValues['axis-y']||0; // smaller Y
               const y2 = lowerK.axisValues['axis-y']||0; // larger Y
               const t = (y2 === y1) ? 0 : (targetY - y1) / (y2 - y1);
               return { [upperK.id]: 1-t, [lowerK.id]: t };
          }
      }

      // If Column failed, Try Horizontal Interpolation (Row Scan)
      const rowKfs = keyframes.filter(k => Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON);
      if (rowKfs.length > 0) {
          const sortedX = rowKfs.sort((a,b) => (a.axisValues['axis-x']||0) - (b.axisValues['axis-x']||0));
          const rightK = sortedX.find(k => (k.axisValues['axis-x']||0) >= targetX) || sortedX[sortedX.length-1];
          const leftK = [...sortedX].reverse().find(k => (k.axisValues['axis-x']||0) <= targetX) || sortedX[0];

          if (leftK && rightK) {
              if (leftK.id === rightK.id) return { [leftK.id]: 1.0 };
              const x1 = leftK.axisValues['axis-x']||0;
              const x2 = rightK.axisValues['axis-x']||0;
              const t = (x2 === x1) ? 0 : (targetX - x1) / (x2 - x1);
              return { [leftK.id]: 1-t, [rightK.id]: t };
          }
      }

      // Fallback: Global Nearest
      let minDist = Infinity;
      let closestId = keyframes[0].id;
      keyframes.forEach(k => {
          const d = Math.sqrt(Math.pow(targetX - (k.axisValues['axis-x']||0), 2) + Math.pow(targetY - (k.axisValues['axis-y']||0), 2));
          if (d < minDist) { minDist = d; closestId = k.id; }
      });
      return { [closestId]: 1.0 };
  };

  // 4. Calculate Weights for the 4 corners of the active cell
  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) }, // TL
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },       // TR
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },       // BL
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }              // BR
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  // 5. Normalize (Just in case)
  let totalW = 0;
  for (const id in weights) totalW += weights[id];
  if (totalW > 0) {
      for (const id in weights) weights[id] /= totalW;
  }

  return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {

   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) {
       return { [keyframes[0].id]: 1.0 };
   }

   if (strategy === 'bilinear-grid') {
       return calculateBilinearGridWeights(currentAxes, keyframes);
   } else {
       return calculateIDWWeights(currentAxes, keyframes, exponent);
   }
};

// --- THE CORE INTERPOLATOR ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, color: string, fillColor?: string, width: number }[],
  mode: 'resample' | 'points' = 'resample'
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter and clean inputs
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'rgba(0,0,0,0)', width: 1 };

  // 2. Mix Colors & Width
  const color = mixColors(keyframesData.map(k => ({ color: k.color, weight: k.weight })));
  const fillColor = mixColors(keyframesData.map(k => ({ color: k.fillColor || 'none', weight: k.weight })));

  // Calculate Weighted Width
  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;


  // 3. Determine Target Topology
  let TARGET_COUNT = 0;

  if (mode === 'points') {
      TARGET_COUNT = Math.max(...activeKeyframes.map(k => k.points!.length));
  } else {
      TARGET_COUNT = 200; 
  }

  // 4. Determine Topology Reference (Stable Anchor: First Keyframe)
  const referenceStroke = activeKeyframes[0].points!;
  const referenceResampled = mode === 'resample' 
     ? resamplePoints(referenceStroke, TARGET_COUNT)
     : referenceStroke;

  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length-1]) < 15;

  // 5. Accumulate Points
  const resultPoints: Point[] = [];

  for (let i = 0; i < TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'resample') {
              const resampled = resamplePoints(rawPoints, TARGET_COUNT);
              processedPoints = alignPoints(referenceResampled, resampled, isClosed);
          } else {
              const virtualIndex = i * ((rawPoints.length - 1) / (TARGET_COUNT - 1));
              processedPoints = [getPointAtFractionalIndex(rawPoints, virtualIndex)];
          }

          const pt = (mode === 'resample') ? processedPoints[i] : processedPoints[0];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- Optimization ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Color Interpolation (RGBA) ---

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 0 };

  // Hex
  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    return {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }

  // Rgb / Rgba
  if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        return {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  // Fallback (could add named colors here if needed)
  return { r: 0, g: 0, b: 0, a: 1 };
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    if (rgba.a > 0) {
        rSum += rgba.r * c.weight * rgba.a;
        gSum += rgba.g * c.weight * rgba.a;
        bSum += rgba.b * c.weight * rgba.a;
    }
    aSum += rgba.a * c.weight;
  }

  if (aSum <= 0.001) return 'rgba(0,0,0,0)';

  let visibleWeight = 0;
  colors.forEach(c => { if (c.color !== 'none') visibleWeight += c.weight; });

  let finalR = 0, finalG = 0, finalB = 0;
  if (visibleWeight > 0.001) {
      let vr = 0, vg = 0, vb = 0;
      for (const c of colors) {
          if (c.color !== 'none') {
             const rgba = parseColor(c.color);
             vr += rgba.r * c.weight;
             vg += rgba.g * c.weight;
             vb += rgba.b * c.weight;
          }
      }
      finalR = vr / visibleWeight;
      finalG = vg / visibleWeight;
      finalB = vb / visibleWeight;
  }

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- Point Index Mapping (Virtual Resampling for 'Points' Mode) ---
const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    // Clamp
    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], closed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse with Hysteresis
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) {
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Cyclic Shifts (Closed only)
    if (closed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }
             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

// Strategy 1: Global Inverse Distance Weighting (Spherical influence)
const calculateIDWWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number
) => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / Math.pow(dist, exponent);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) weights[id] /= totalWeight;
  } else {
     weights[keyframes[0].id] = 1;
  }
  return weights;
};

// Strategy 2: Grid-Fill Bilinear (Mesh Logic)
// Priority:
// 1. Exact Match
// 2. Orthogonal Projection (Row OR Column Bracket)
//    - If Row Bracket exists (Left & Right), use it.
//    - If Col Bracket exists (Top & Bottom), use it.
//    - If BOTH exist, average them (inner grid).
// 3. Fallback (Global Nearest)
const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  // 1. Extract Grid Lines
  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  // 2. Identify Active Cell (Clamp to edges)
  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  // 3. HELPER: Find Bracketing Neighbors on a specific Axis
  // Returns: { k1, k2, t } or null if not fully bracketed
  const getBracket = (
     targetFixedVal: number, // e.g. Y=0
     targetVarVal: number,   // e.g. X=0.5
     fixedAxis: 'axis-x' | 'axis-y',
     varAxis: 'axis-x' | 'axis-y'
  ) => {
     // Find all keyframes strictly on the fixed line (e.g. Y=0)
     const onLine = keyframes.filter(k => Math.abs((k.axisValues[fixedAxis]||0) - targetFixedVal) < EPSILON);
     if (onLine.length < 2) return null;

     const sorted = onLine.sort((a,b) => (a.axisValues[varAxis]||0) - (b.axisValues[varAxis]||0));

     // Find strictly Low and High
     const low = [...sorted].reverse().find(k => (k.axisValues[varAxis]||0) <= targetVarVal + EPSILON);
     const high = sorted.find(k => (k.axisValues[varAxis]||0) >= targetVarVal - EPSILON);

     if (low && high) {
        // If they are the same point (exact match), handle elsewhere or return t=0
        const v1 = low.axisValues[varAxis]||0;
        const v2 = high.axisValues[varAxis]||0;
        if (Math.abs(v2 - v1) < EPSILON) return null; // Not a bracket, just a point

        const t = (targetVarVal - v1) / (v2 - v1);
        return { low, high, t };
     }
     return null;
  };

  // 4. Resolve Virtual Corner
  const resolveCornerWeights = (targetX: number, targetY: number) => {
      // A. Exact Match
      const exact = keyframes.find(k => 
          Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && 
          Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON
      );
      if (exact) return { [exact.id]: 1.0 };

      // B. Orthogonal Search
      // Try Row Bracket (Left/Right at this Y)
      const rowBracket = getBracket(targetY, targetX, 'axis-y', 'axis-x');
      // Try Col Bracket (Top/Bottom at this X)
      const colBracket = getBracket(targetX, targetY, 'axis-x', 'axis-y');

      // C. Decision Logic
      if (rowBracket && !colBracket) {
         return { [rowBracket.low.id]: 1 - rowBracket.t, [rowBracket.high.id]: rowBracket.t };
      }

      if (!rowBracket && colBracket) {
         return { [colBracket.low.id]: 1 - colBracket.t, [colBracket.high.id]: colBracket.t };
      }

      if (rowBracket && colBracket) {
          // Both exist (inner grid point). Average them for mesh stability.
          // Or we could weight by distance if needed, but 50/50 is smoother for grid.
          const res: Record<string, number> = {};

          const add = (id: string, w: number) => res[id] = (res[id] || 0) + (w * 0.5);

          add(rowBracket.low.id, 1 - rowBracket.t);
          add(rowBracket.high.id, rowBracket.t);
          add(colBracket.low.id, 1 - colBracket.t);
          add(colBracket.high.id, colBracket.t);

          return res;
      }

      // D. Sparse Fallback (No bracket found on either axis)
      // Look for the closest projected point or closest Euclidean
      let minDist = Infinity;
      let closestId = keyframes[0].id;
      keyframes.forEach(k => {
          const d = Math.sqrt(Math.pow(targetX - (k.axisValues['axis-x']||0), 2) + Math.pow(targetY - (k.axisValues['axis-y']||0), 2));
          if (d < minDist) { minDist = d; closestId = k.id; }
      });
      return { [closestId]: 1.0 };
  };

  // 5. Calculate Weights for the 4 corners of the active cell
  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) }, // TL
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },       // TR
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },       // BL
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }              // BR
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  // 6. Normalize
  let totalW = 0;
  for (const id in weights) totalW += weights[id];
  if (totalW > 0) {
      for (const id in weights) weights[id] /= totalW;
  }

  return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {

   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) {
       return { [keyframes[0].id]: 1.0 };
   }

   if (strategy === 'bilinear-grid') {
       return calculateBilinearGridWeights(currentAxes, keyframes);
   } else {
       return calculateIDWWeights(currentAxes, keyframes, exponent);
   }
};

// --- THE CORE INTERPOLATOR ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, color: string, fillColor?: string, width: number }[],
  mode: 'resample' | 'points' = 'resample'
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter and clean inputs
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'rgba(0,0,0,0)', width: 1 };

  // 2. Mix Colors & Width
  const color = mixColors(keyframesData.map(k => ({ color: k.color, weight: k.weight })));
  const fillColor = mixColors(keyframesData.map(k => ({ color: k.fillColor || 'none', weight: k.weight })));

  // Calculate Weighted Width
  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;


  // 3. Determine Target Topology
  let TARGET_COUNT = 0;

  if (mode === 'points') {
      TARGET_COUNT = Math.max(...activeKeyframes.map(k => k.points!.length));
  } else {
      TARGET_COUNT = 200; 
  }

  // 4. Determine Topology Reference (Stable Anchor: First Keyframe)
  const referenceStroke = activeKeyframes[0].points!;
  const referenceResampled = mode === 'resample' 
     ? resamplePoints(referenceStroke, TARGET_COUNT)
     : referenceStroke;

  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length-1]) < 15;

  // 5. Accumulate Points
  const resultPoints: Point[] = [];

  for (let i = 0; i < TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'resample') {
              const resampled = resamplePoints(rawPoints, TARGET_COUNT);
              processedPoints = alignPoints(referenceResampled, resampled, isClosed);
          } else {
              const virtualIndex = i * ((rawPoints.length - 1) / (TARGET_COUNT - 1));
              processedPoints = [getPointAtFractionalIndex(rawPoints, virtualIndex)];
          }

          const pt = (mode === 'resample') ? processedPoints[i] : processedPoints[0];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- Optimization ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

# PROSOPOPUS v2 - MANIFESTO & ARCHITECTURE

> **Version**: 2.9
> **Role**: Source of Truth & Project Memory
> **Concept**: N-Dimensional Vector Interpolation Design Tool

---

## 1. VISION & SCOPE

### Concept Core
Prosopopus n'est pas un logiciel d'animation temporelle classique (Timeline). C'est un moteur de **Design Paramétrique par États**.
L'utilisateur définit des "États Clés" (Keyframes) positionnés librement dans un espace N-dimensionnel (Matrice d'Interpolation). Le moteur génère le visuel final en interpolant entre ces états en fonction de la position d'un curseur (Souris X/Y, Pression, Scroll, etc.).

### Philosophie "Puppet Mode"
Pour garantir une interpolation fluide sans artefact topologique, le système fonctionne par correspondance stricte :
*   Chaque calque (Layer) contient au maximum **un tracé (Stroke)** par Keyframe.
*   L'interpolation calcule la moyenne pondérée de ce tracé unique à travers les dimensions.

---

## 2. STACK TECHNIQUE

*   **Runtime**: React 19 (Hooks intensive).
*   **State Management**: Zustand (Store centralisé, pattern Redux-like simplifié, History Stack pour Undo/Redo).
*   **Rendering Engine**: HTML5 Canvas API (2D Context).
    *   Pas de SVG pour le rendu principal (performance critique requise pour le 60fps lors de l'interpolation de milliers de points).
    *   Device Pixel Ratio (DPR) handling pour la netteté sur écrans Retina/High-DPI.
*   **Styling**: Tailwind CSS (Utility-first).
*   **Inputs**: Pointer Events API (unification Mouse/Touch/Pen avec support de la pression).

---

## 3. DESIGN SYSTEM (MODERN MINIMALIST)

L'esthétique doit rester invisible pour laisser place au contenu.

### Atomic Tokens
*   **Radius**: `rounded-full` pour les boutons, `rounded-2xl` pour les panneaux.
*   **Surfaces**: `bg-white/90` avec `backdrop-blur-md` ou `backdrop-blur-xl`.
*   **Borders**: Fines, `border-gray-200` ou `border-gray-100`.
*   **Shadows**: `shadow-xl` diffuse pour l'élévation, `shadow-sm` pour les états actifs.

### Palette (APP_COLORS)
*   **Background**: `#EAEAEA` (Gris neutre chaud).
*   **Primary**: `#3B82F6` (Blue 500 - Actions, Sélection).
*   **Surface**: `#FFFFFF` (Panneaux).
*   **Text**: `#1F2937` (Gris foncé).
*   **Destructive**: Red 500 (Delete).

### Layout Rules
*   **Toolbar**: Flottante, centrée en haut, horizontale.
*   **AxisMap**: Flottante, ancrée en bas à gauche, taille fixe mais contenu relatif.
*   **Panels**: Latéraux, escamotables (Layers à gauche, Settings à droite).

---

## 4. ARCHITECTURE DES DONNÉES (Schema TypeScript)

La structure de données est normalisée pour éviter la redondance.

```typescript
// L'atome de base
interface Point {
  x: number;
  y: number;
  pressure?: number; // 0.0 à 1.0
}

// Le contenu graphique
interface Stroke {
  id: string;
  points: Point[];
  color: string; // Hex ou RGBA
  width: number; // Épaisseur interpolable
  closed: boolean;
  fillColor?: string;
  style: 'solid' | 'dashed' | 'dotted';
}

// L'état d'un calque à un instant T (Keyframe)
interface LayerState {
  layerId: string;
  strokes: Stroke[]; // Array, mais souvent length=1 en Puppet Mode
}

// Le nœud dans la matrice N-dimensionnelle
interface Keyframe {
  id: string;
  axisValues: Record<string, number>; // ex: { "axis-x": 0.5, "axis-y": 1.0 }
  layerStates: LayerState[];
}

// La définition d'une dimension de contrôle
interface Axis {
  id: string; // 'axis-x' | 'axis-y'
  currentValue: number; // 0.0 à 1.0 (Float précis)
  min: number;
  max: number;
}

// Le Calque (Propriétés globales)
interface Layer {
  id: string;
  blendMode: 'normal' | 'multiply' | 'screen' | 'overlay' | 'difference' | 'exclusion';
  interpolationMode: 'resample' | 'points'; // Lissage courbe vs Points bruts
  visible: boolean;
  locked: boolean;
  opacity: number;
}

// La Racine
interface Project {
  axes: Axis[];
  layers: Layer[];
  keyframes: Keyframe[];
  canvasSize: { width: number, height: number };
}
```

---

## 5. LOGIQUE D'INTERPOLATION (The Engine)

L'interpolation se fait à la volée (`requestAnimationFrame`) dans le composant `Canvas`.

### Algorithme : Grid-Fill (Virtual Corners)
Pour résoudre les problèmes de distorsion dans les matrices éparses, nous utilisons une approche "Mesh" plutôt que de simples distances.

1.  **Input**: Valeurs courantes des Axes (ex: X=0.33, Y=0.85).
2.  **Grid Extraction** : Identification des lignes et colonnes uniques formées par les Keyframes existants.
3.  **Active Cell Identification** : Détermination de la cellule rectangulaire englobante du curseur.
4.  **Virtual Corner Resolution (Scan Orthogonal)** : Pour chaque coin de la cellule active :
    *   **Priorité 1 (Exact)** : Un Keyframe existe à ces coordonnées précises.
    *   **Priorité 2 (Bracket Orthogonal)** : Si le coin est vide, on cherche des voisins alignés sur la même ligne (Row Bracket) ou colonne (Column Bracket). Si trouvés, on interpole linéairement entre eux.
    *   **Priorité 3 (Fallback)** : Keyframe le plus proche (Euclidien).
5.  **Bilinear Weighting** : Calcul des poids finaux par interpolation bilinéaire des 4 états (réels ou virtuels) de la cellule.
6.  **Resampling & Lerp** :
    *   Alignement topologique des formes (Resample + Cyclic Shift).
    *   Mélange linéaire des points, largeurs et couleurs (`mixColors` avec cache).

---

## 6. REGISTRE DES FONCTIONNALITÉS (IMMUTABLE)

Ces fonctionnalités constituent le cœur de l'expérience utilisateur et ne doivent pas être supprimées sans remplacement supérieur.

### Outils (Tools)
*   **Pen**: Dessin libre, lissage automatique post-tracé.
*   **Polyline**: Dessin point par point, double-clic ou Enter pour finir.
*   **Select/Transform**: Sélection de tracé, déplacement (Translation), redimensionnement par Bounding Box.

### Gestion des Calques
*   **Reorder**: Drag & Drop (Le haut de la liste = Premier plan).
*   **Blend Modes**: Support complet des modes Canvas (Multiply, Screen, Difference, Exclusion).
*   **Interpolation Mode**: Choix par calque entre `Resample` (Courbes lisses) et `Points` (Raw data).

### Matrice & Navigation
*   **AxisMap**: Visualisation 2D de l'espace des états.
*   **Snap Matrix**: Grille magnétique paramétrable (Divisions & Padding) pour positionner les Keyframes précisément.
*   **Snap Playhead**: Magnétisme du curseur de lecture (Play Mode).
*   **Strict Selection**: Un Keyframe n'est éditable que si l'on est *exactement* dessus. Sinon, on est en mode "Ghost" (Création).

### Helpers Visuels
*   **Onion Skin**: Voir les états adjacents en transparence.
*   **Grid**: Grille de fond paramétrable.
*   **Ghost Opacity**: Transparence réduite lorsqu'on dessine dans un état non-défini (interpolation vide).

### Gestion de Projet
*   **Format JSON**: Import/Export complet de la structure `Project`.
*   **Reset**: Remise à zéro totale (Zone de danger).

---

## 7. FUTUR & CONSIGNES D'IA

Pour toute modification future :
1.  **Non-Destructif** : Ne jamais retirer une variable du Store sans vérifier son impact sur le JSON Export.
2.  **Performance** : L'interpolation est le goulot d'étranglement. Éviter les calculs lourds (ex: filtres SVG complexes) dans la boucle de rendu.
3.  **UI/UX** : Maintenir l'approche "Settings Panel" pour les configurations complexes afin de ne pas encombrer la Toolbar principale.

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Color Interpolation (RGBA) ---

// PERFORMANCE: Cache for parsed colors to avoid repetitive Regex/ParseInt
const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 0 };

  // Return cached if exists
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  // Hex
  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }

  // Rgb / Rgba
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  // Fallback (could add named colors here if needed)
  else {
      // Create a dummy element to let browser parse named colors (slow, but cached)
      // For now, default black.
      result = { r: 0, g: 0, b: 0, a: 1 };
  }

  // Save to cache (limit cache size could be good but for a palette app usually fine)
  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    // Weight alpha blending
    if (rgba.a > 0) {
        rSum += rgba.r * c.weight * rgba.a;
        gSum += rgba.g * c.weight * rgba.a;
        bSum += rgba.b * c.weight * rgba.a;
    }
    aSum += rgba.a * c.weight;
  }

  if (aSum <= 0.001) return 'rgba(0,0,0,0)';

  let visibleWeight = 0;
  colors.forEach(c => { if (c.color !== 'none') visibleWeight += c.weight; });

  let finalR = 0, finalG = 0, finalB = 0;

  // Normalization logic:
  // If we have mixed colors, we want the average RGB of the visible parts
  if (visibleWeight > 0.001) {
      let vr = 0, vg = 0, vb = 0;
      for (const c of colors) {
          if (c.color !== 'none') {
             const rgba = parseColor(c.color);
             vr += rgba.r * c.weight;
             vg += rgba.g * c.weight;
             vb += rgba.b * c.weight;
          }
      }
      finalR = vr / visibleWeight;
      finalG = vg / visibleWeight;
      finalB = vb / visibleWeight;
  }

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- Point Index Mapping (Virtual Resampling for 'Points' Mode) ---
const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    // Clamp
    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], closed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse with Hysteresis
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) {
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Cyclic Shifts (Closed only)
    if (closed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }
             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

// Strategy 1: Global Inverse Distance Weighting (Spherical influence)
const calculateIDWWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number
) => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / Math.pow(dist, exponent);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) weights[id] /= totalWeight;
  } else {
     weights[keyframes[0].id] = 1;
  }
  return weights;
};

// Strategy 2: Grid-Fill Bilinear (Mesh Logic)
// Priority:
// 1. Exact Match
// 2. Orthogonal Projection (Row OR Column Bracket)
//    - If Row Bracket exists (Left & Right), use it.
//    - If Col Bracket exists (Top & Bottom), use it.
//    - If BOTH exist, average them (inner grid).
// 3. Fallback (Global Nearest)
const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  // 1. Extract Grid Lines
  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  // 2. Identify Active Cell (Clamp to edges)
  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  // 3. HELPER: Find Bracketing Neighbors on a specific Axis
  // Returns: { k1, k2, t } or null if not fully bracketed
  const getBracket = (
     targetFixedVal: number, // e.g. Y=0
     targetVarVal: number,   // e.g. X=0.5
     fixedAxis: 'axis-x' | 'axis-y',
     varAxis: 'axis-x' | 'axis-y'
  ) => {
     // Find all keyframes strictly on the fixed line (e.g. Y=0)
     const onLine = keyframes.filter(k => Math.abs((k.axisValues[fixedAxis]||0) - targetFixedVal) < EPSILON);
     if (onLine.length < 2) return null;

     const sorted = onLine.sort((a,b) => (a.axisValues[varAxis]||0) - (b.axisValues[varAxis]||0));

     // Find strictly Low and High
     const low = [...sorted].reverse().find(k => (k.axisValues[varAxis]||0) <= targetVarVal + EPSILON);
     const high = sorted.find(k => (k.axisValues[varAxis]||0) >= targetVarVal - EPSILON);

     if (low && high) {
        // If they are the same point (exact match), handle elsewhere or return t=0
        const v1 = low.axisValues[varAxis]||0;
        const v2 = high.axisValues[varAxis]||0;
        if (Math.abs(v2 - v1) < EPSILON) return null; // Not a bracket, just a point

        const t = (targetVarVal - v1) / (v2 - v1);
        return { low, high, t };
     }
     return null;
  };

  // 4. Resolve Virtual Corner
  const resolveCornerWeights = (targetX: number, targetY: number) => {
      // A. Exact Match
      const exact = keyframes.find(k => 
          Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && 
          Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON
      );
      if (exact) return { [exact.id]: 1.0 };

      // B. Orthogonal Search
      // Try Row Bracket (Left/Right at this Y)
      const rowBracket = getBracket(targetY, targetX, 'axis-y', 'axis-x');
      // Try Col Bracket (Top/Bottom at this X)
      const colBracket = getBracket(targetX, targetY, 'axis-x', 'axis-y');

      // C. Decision Logic
      if (rowBracket && !colBracket) {
         return { [rowBracket.low.id]: 1 - rowBracket.t, [rowBracket.high.id]: rowBracket.t };
      }

      if (!rowBracket && colBracket) {
         return { [colBracket.low.id]: 1 - colBracket.t, [colBracket.high.id]: colBracket.t };
      }

      if (rowBracket && colBracket) {
          // Both exist (inner grid point). Average them for mesh stability.
          // Or we could weight by distance if needed, but 50/50 is smoother for grid.
          const res: Record<string, number> = {};

          const add = (id: string, w: number) => res[id] = (res[id] || 0) + (w * 0.5);

          add(rowBracket.low.id, 1 - rowBracket.t);
          add(rowBracket.high.id, rowBracket.t);
          add(colBracket.low.id, 1 - colBracket.t);
          add(colBracket.high.id, colBracket.t);

          return res;
      }

      // D. Sparse Fallback (No bracket found on either axis)
      // Look for the closest projected point or closest Euclidean
      let minDist = Infinity;
      let closestId = keyframes[0].id;
      keyframes.forEach(k => {
          const d = Math.sqrt(Math.pow(targetX - (k.axisValues['axis-x']||0), 2) + Math.pow(targetY - (k.axisValues['axis-y']||0), 2));
          if (d < minDist) { minDist = d; closestId = k.id; }
      });
      return { [closestId]: 1.0 };
  };

  // 5. Calculate Weights for the 4 corners of the active cell
  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) }, // TL
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },       // TR
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },       // BL
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }              // BR
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  // 6. Normalize
  let totalW = 0;
  for (const id in weights) totalW += weights[id];
  if (totalW > 0) {
      for (const id in weights) weights[id] /= totalW;
  }

  return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {

   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) {
       return { [keyframes[0].id]: 1.0 };
   }

   if (strategy === 'bilinear-grid') {
       return calculateBilinearGridWeights(currentAxes, keyframes);
   } else {
       return calculateIDWWeights(currentAxes, keyframes, exponent);
   }
};

// --- THE CORE INTERPOLATOR ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, color: string, fillColor?: string, width: number }[],
  mode: 'resample' | 'points' = 'resample'
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter and clean inputs
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'rgba(0,0,0,0)', width: 1 };

  // 2. Mix Colors & Width
  const color = mixColors(keyframesData.map(k => ({ color: k.color, weight: k.weight })));
  const fillColor = mixColors(keyframesData.map(k => ({ color: k.fillColor || 'none', weight: k.weight })));

  // Calculate Weighted Width
  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;


  // 3. Determine Target Topology
  let TARGET_COUNT = 0;

  if (mode === 'points') {
      TARGET_COUNT = Math.max(...activeKeyframes.map(k => k.points!.length));
  } else {
      TARGET_COUNT = 200; 
  }

  // 4. Determine Topology Reference (Stable Anchor: First Keyframe)
  const referenceStroke = activeKeyframes[0].points!;
  const referenceResampled = mode === 'resample' 
     ? resamplePoints(referenceStroke, TARGET_COUNT)
     : referenceStroke;

  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length-1]) < 15;

  // 5. Accumulate Points
  const resultPoints: Point[] = [];

  for (let i = 0; i < TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'resample') {
              const resampled = resamplePoints(rawPoints, TARGET_COUNT);
              processedPoints = alignPoints(referenceResampled, resampled, isClosed);
          } else {
              const virtualIndex = i * ((rawPoints.length - 1) / (TARGET_COUNT - 1));
              processedPoints = [getPointAtFractionalIndex(rawPoints, virtualIndex)];
          }

          const pt = (mode === 'resample') ? processedPoints[i] : processedPoints[0];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- Optimization ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke } = useStore();

  // Interaction State
  const [isDrawing, setIsDrawing] = useState(false);
  const currentPointsRef = useRef<Point[]>([]); 

  const [isDraggingStroke, setIsDraggingStroke] = useState(false);
  const [dragStartPos, setDragStartPos] = useState<Point | null>(null);
  const [originalStrokePoints, setOriginalStrokePoints] = useState<Point[]>([]);

  // Bounding Box Interaction (Resize)
  const [isResizing, setIsResizing] = useState(false);
  const [initialBox, setInitialBox] = useState<{minX: number, maxX: number, minY: number, maxY: number} | null>(null);

  // Polyline State
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null); // For polyline preview

  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const availW = contW - margin;
      const availH = contH - margin;
      const scaleW = availW / CANVAS_WIDTH;
      const scaleH = availH / CANVAS_HEIGHT;
      const newScale = Math.min(scaleW, scaleH, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  // --- Helpers ---
  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    let p: Point = {
      x: (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width),
      y: (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height),
      pressure: e.pressure || 0.5
    };

    if (ui.snapToGrid) {
      p = snapPointToGrid(p, ui.gridSize);
    }
    return p;
  };

  const finishPolyline = (closed = false) => {
    if (polylinePoints.length > 1) {
      addStrokeToCurrentKeyframe(polylinePoints, closed, true);
    }
    setPolylinePoints([]);
  };

  // --- Handlers ---

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }

    if (ui.selectedTool === 'select') {
       const hitId = findHitStroke(p);
       if (hitId) {
          selectStroke(hitId);
          setIsDraggingStroke(true);
          setDragStartPos(p);

          const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
          if (kf) {
             const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
             if (layerState && layerState.strokes.length > 0) {
                setOriginalStrokePoints(layerState.strokes[0].points);
                const pts = layerState.strokes[0].points;
                setInitialBox({ 
                    minX: Math.min(...pts.map(pt => pt.x)), 
                    maxX: Math.max(...pts.map(pt => pt.x)), 
                    minY: Math.min(...pts.map(pt => pt.y)), 
                    maxY: Math.max(...pts.map(pt => pt.y)) 
                });
             }
          }
          (e.target as Element).setPointerCapture(e.pointerId);
       } else {
          selectStroke(null);
          setInitialBox(null);
       }
       return;
    }

    if (ui.selectedTool === 'polyline') {
       if (polylinePoints.length > 0) {
           const startPoint = polylinePoints[0];
           if (distance(p, startPoint) < 15) { 
               finishPolyline(true);
               return;
           }
       }
       setPolylinePoints(prev => [...prev, p]);
       return;
    }

    if (ui.selectedTool === 'pen') {
      setIsDrawing(true);
      currentPointsRef.current = [p];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(p); 

    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        const relX = e.clientX - rect.left;
        const relY = e.clientY - rect.top;
        let normX = Math.max(0, Math.min(1, relX / rect.width));
        let normY = Math.max(0, Math.min(1, relY / rect.height));

        if (ui.snapPlayMode) {
            const increments = 10;
            normX = Math.round(normX * increments) / increments;
            normY = Math.round(normY * increments) / increments;
        }

        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }

    if (isDraggingStroke && dragStartPos && ui.selectedStrokeId) {
       const dx = p.x - dragStartPos.x;
       const dy = p.y - dragStartPos.y;
       const newPoints = originalStrokePoints.map(pt => ({
          x: pt.x + dx,
          y: pt.y + dy,
          pressure: pt.pressure
       }));
       updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
       return;
    }

    if (isDrawing && ui.selectedTool === 'pen') {
       currentPointsRef.current.push(p);
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (ui.mode === 'play') {
      (e.target as Element).releasePointerCapture(e.pointerId);
      return;
    }

    if (isDraggingStroke) {
       setIsDraggingStroke(false);
       setDragStartPos(null);
    }

    if (isDrawing) {
      setIsDrawing(false);
      if (currentPointsRef.current.length > 1) {
          const start = currentPointsRef.current[0];
          const end = currentPointsRef.current[currentPointsRef.current.length - 1];
          const isClosed = distance(start, end) < 15; 

          addStrokeToCurrentKeyframe([...currentPointsRef.current], isClosed);
      }
      currentPointsRef.current = [];
    }

    (e.target as Element).releasePointerCapture(e.pointerId);
  };

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          finishPolyline(false);
      }
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') finishPolyline(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [polylinePoints]);


  // RENDER LOOP
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);

        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; 
           ctx.globalAlpha = ui.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== ui.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // CURRENT AXES
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      // --- LAYER LOOP ---
      project.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = project.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        // Pass the configured exponent AND Strategy
        const weights = calculateInterpolationWeights(
            currentAxesDict, 
            layerRelevantKeyframes, 
            ui.interpolationExponent, 
            ui.interpolationStrategy
        );

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;

        const isLayerActive = layer.id === ui.selectedLayerId;
        const isCreatingNewState = ui.selectedKeyframeId === null;

        // Determine Base Opacity for the Layer
        let layerGlobalAlpha = layer.opacity;

        if (!isLayerActive && ui.mode !== 'play') {
           layerGlobalAlpha *= ui.inactiveLayerOpacity;
        }

        // If we are in "Create State" mode (interpolated), the background interpolation is ghosted
        if (isCreatingNewState && ui.mode === 'edit') {
            layerGlobalAlpha *= ui.ghostStrokeOpacity;
        }

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { 
                weight: kf.weight, 
                points: s?.points, 
                style: s, 
                color: s?.color || 'none', 
                fillColor: s?.fillColor,
                width: s?.width || 1
            };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;

        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId,
            primaryStroke.points, 
            strokeData, 
            layer.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) {
                ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            }
            if (primaryStroke.closed) {
                ctx.closePath();
            }

            ctx.globalAlpha = layerGlobalAlpha;

            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            // FILL
            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }

            // STROKE
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            // Highlight Selection
            if (ui.selectedStrokeId === primaryStroke.id && ui.mode === 'edit') {
               ctx.strokeStyle = '#3B82F6';
               ctx.lineWidth = 1;
               ctx.setLineDash([5, 5]);
               ctx.stroke();
               ctx.setLineDash([]);
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING (Pen)
      if (isDrawing && currentPointsRef.current.length > 0) {
        // If we are NOT on a defined keyframe (selectedKeyframeId === null), use ghost opacity
        const activeOpacity = ui.selectedKeyframeId === null ? ui.ghostStrokeOpacity : 1.0;
        ctx.globalAlpha = activeOpacity;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();

        ctx.globalAlpha = 1.0; // Reset
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         // Same logic for polyline
         const activeOpacity = ui.selectedKeyframeId === null ? ui.ghostStrokeOpacity : 1.0;
         ctx.globalAlpha = activeOpacity;

         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) {
             ctx.lineTo(mousePos.x, mousePos.y); 
         }

         if (ui.fillColor !== 'none') {
             ctx.fillStyle = ui.fillColor;
             // If drawing opacity is already low, keep fill proportional or fixed? 
             // Let's keep fill at 20% of the active opacity.
             ctx.globalAlpha = activeOpacity * 0.2; 
             ctx.fill();
             ctx.globalAlpha = activeOpacity;
         }

         ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = ui.brushSize;
         ctx.stroke();

         // Anchors
         ctx.fillStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();

            if (index === 0 && mousePos && distance(p, mousePos) < 15) {
                ctx.beginPath();
                ctx.strokeStyle = APP_COLORS.primary;
                ctx.lineWidth = 2;
                ctx.arc(p.x, p.y, 8, 0, Math.PI * 2);
                ctx.stroke();
            }
         });

         ctx.globalAlpha = 1.0; // Reset
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, polylinePoints, mousePos, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void; // New

  setGridSize: (size: number) => void;
  toggleSimplifyStrokes: () => void;

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void; // New
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; // Updated sig
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  selectKeyframe: (keyframeId: string) => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  // UPDATED: Live update of stroke properties
  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 // Update the first stroke (Puppet Mode assumption)
                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  // UPDATED: Live update of stroke properties
  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  // UPDATED: Live update of stroke properties
  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSimplifyStrokes: () => set((state) => ({ ui: { ...state.ui, simplifyStrokes: !state.ui.simplifyStrokes } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  updateAxisValue: (axisId, value) => set((state) => {
    // Smooth value
    const cleanValue = Math.max(0, Math.min(1, value));

    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    // Strict Selection Logic:
    // If we are NOT exactly on a keyframe (with small threshold), we are in an INTERPOLATED state.
    // In this case, selectedKeyframeId should be NULL.
    let matchingKfId = null;

    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; // Slightly wider threshold for snapping comfort
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, simplifyStrokes } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    let points = rawPoints;
    if (simplifyStrokes && !skipSimplify) {
       points = simplifyPoints(rawPoints, 1.0);
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    // If selectedKeyframeId is null (interpolated state), we ALWAYS create a new keyframe
    // unless we happen to land exactly on one (which should be handled by updateAxisValue logic)

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: closed
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  })
}));

// utils/math.ts
import { Point, Stroke, InterpolationStrategy } from '../types';

export const distance = (p1: Point, p2: Point): number => {
  return Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
};

export const lerp = (start: number, end: number, t: number): number => {
  return start * (1 - t) + end * t;
};

// --- Transformation Helpers ---

export const rotatePoint = (p: Point, center: Point, angleRad: number): Point => {
  const cos = Math.cos(angleRad);
  const sin = Math.sin(angleRad);
  const dx = p.x - center.x;
  const dy = p.y - center.y;
  return {
    x: center.x + (dx * cos - dy * sin),
    y: center.y + (dx * sin + dy * cos),
    pressure: p.pressure
  };
};

export const getBoundingBox = (points: Point[]): { minX: number, maxX: number, minY: number, maxY: number, width: number, height: number, centerX: number, centerY: number } => {
  if (points.length === 0) return { minX:0, maxX:0, minY:0, maxY:0, width:0, height:0, centerX:0, centerY:0 };

  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of points) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }

  return {
    minX, maxX, minY, maxY,
    width: maxX - minX,
    height: maxY - minY,
    centerX: minX + (maxX - minX) / 2,
    centerY: minY + (maxY - minY) / 2
  };
};

// --- Color Interpolation (RGBA) ---

// PERFORMANCE: Cache for parsed colors to avoid repetitive Regex/ParseInt
const colorCache: Record<string, { r: number, g: number, b: number, a: number }> = {};

const parseColor = (color: string): { r: number, g: number, b: number, a: number } => {
  if (!color || color === 'none') return { r: 0, g: 0, b: 0, a: 0 };

  // Return cached if exists
  if (colorCache[color]) return colorCache[color];

  let result = { r: 0, g: 0, b: 0, a: 1 };

  // Hex
  if (color.startsWith('#')) {
    let hex = color.slice(1);
    if (hex.length === 3) hex = hex.split('').map(c => c + c).join('');
    const bigint = parseInt(hex, 16);
    result = {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255,
      a: 1
    };
  }

  // Rgb / Rgba
  else if (color.startsWith('rgb')) {
    const match = color.match(/(\d+(\.\d+)?)/g);
    if (match) {
        result = {
            r: parseFloat(match[0]),
            g: parseFloat(match[1]),
            b: parseFloat(match[2]),
            a: match[3] ? parseFloat(match[3]) : 1
        };
    }
  }

  // Fallback (could add named colors here if needed)
  else {
      // Create a dummy element to let browser parse named colors (slow, but cached)
      // For now, default black.
      result = { r: 0, g: 0, b: 0, a: 1 };
  }

  // Save to cache (limit cache size could be good but for a palette app usually fine)
  colorCache[color] = result;
  return result;
};

export const mixColors = (colors: { color: string | 'none', weight: number }[]): string => {
  let rSum = 0, gSum = 0, bSum = 0, aSum = 0;

  for (const c of colors) {
    const rgba = parseColor(c.color);
    // Weight alpha blending
    if (rgba.a > 0) {
        rSum += rgba.r * c.weight * rgba.a;
        gSum += rgba.g * c.weight * rgba.a;
        bSum += rgba.b * c.weight * rgba.a;
    }
    aSum += rgba.a * c.weight;
  }

  if (aSum <= 0.001) return 'rgba(0,0,0,0)';

  let visibleWeight = 0;
  colors.forEach(c => { if (c.color !== 'none') visibleWeight += c.weight; });

  let finalR = 0, finalG = 0, finalB = 0;

  // Normalization logic:
  // If we have mixed colors, we want the average RGB of the visible parts
  if (visibleWeight > 0.001) {
      let vr = 0, vg = 0, vb = 0;
      for (const c of colors) {
          if (c.color !== 'none') {
             const rgba = parseColor(c.color);
             vr += rgba.r * c.weight;
             vg += rgba.g * c.weight;
             vb += rgba.b * c.weight;
          }
      }
      finalR = vr / visibleWeight;
      finalG = vg / visibleWeight;
      finalB = vb / visibleWeight;
  }

  return `rgba(${Math.round(finalR)}, ${Math.round(finalG)}, ${Math.round(finalB)}, ${aSum.toFixed(3)})`;
};

// --- Geometry Helpers ---

const getPathLength = (points: Point[]): number => {
  let len = 0;
  for (let i = 1; i < points.length; i++) {
    len += distance(points[i - 1], points[i]);
  }
  return len;
};

// STRICT Arc-Length Resampling (Percentage Mode)
export const resamplePoints = (points: Point[], targetCount: number): Point[] => {
  if (points.length < 2 || targetCount < 2) return points;

  const totalLength = getPathLength(points);
  if (totalLength === 0) return Array(targetCount).fill(points[0]);

  const step = totalLength / (targetCount - 1);
  const newPoints: Point[] = [points[0]];

  let currentDist = 0;
  let nextPointIndex = 1;

  for (let i = 1; i < targetCount; i++) {
    const targetDist = i * step;
    let distSoFar = currentDist;
    let p1 = points[nextPointIndex - 1];
    let p2 = points[nextPointIndex];
    let segmentDist = distance(p1, p2);

    while (distSoFar + segmentDist < targetDist && nextPointIndex < points.length - 1) {
      distSoFar += segmentDist;
      currentDist = distSoFar;
      nextPointIndex++;
      p1 = points[nextPointIndex - 1];
      p2 = points[nextPointIndex];
      segmentDist = distance(p1, p2);
    }

    const segmentLocalDist = targetDist - distSoFar;
    const t = segmentDist === 0 ? 0 : segmentLocalDist / segmentDist;

    newPoints.push({
      x: lerp(p1.x, p2.x, t),
      y: lerp(p1.y, p2.y, t),
      pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    });
  }

  while (newPoints.length < targetCount) newPoints.push(points[points.length - 1]);
  if (newPoints.length > targetCount) newPoints.length = targetCount;

  return newPoints;
};

// --- Point Index Mapping (Virtual Resampling for 'Points' Mode) ---
const getPointAtFractionalIndex = (points: Point[], index: number): Point => {
    if (points.length === 0) return { x: 0, y: 0, pressure: 0 };
    if (points.length === 1) return points[0];

    // Clamp
    if (index <= 0) return points[0];
    if (index >= points.length - 1) return points[points.length - 1];

    const i = Math.floor(index);
    const t = index - i;
    const p1 = points[i];
    const p2 = points[i+1];

    return {
        x: lerp(p1.x, p2.x, t),
        y: lerp(p1.y, p2.y, t),
        pressure: lerp(p1.pressure || 0.5, p2.pressure || 0.5, t)
    };
};

export const snapPointToGrid = (p: Point, gridSize: number): Point => {
  return {
    x: Math.round(p.x / gridSize) * gridSize,
    y: Math.round(p.y / gridSize) * gridSize,
    pressure: p.pressure
  };
};

// --- Hit Testing ---

const distToSegment = (p: Point, v: Point, w: Point) => {
  const l2 = Math.pow(distance(v, w), 2);
  if (l2 === 0) return distance(p, v);
  let t = ((p.x - v.x) * (w.x - v.x) + (p.y - v.y) * (w.y - v.y)) / l2;
  t = Math.max(0, Math.min(1, t));
  const projection = { x: v.x + t * (w.x - v.x), y: v.y + t * (w.y - v.y) };
  return distance(p, projection);
};

export const isPointInStroke = (p: Point, points: Point[], threshold: number = 10): boolean => {
  for (let i = 0; i < points.length - 1; i++) {
    if (distToSegment(p, points[i], points[i+1]) < threshold) return true;
  }
  return false;
};

// --- Robust Alignment ---

const alignPoints = (reference: Point[], target: Point[], closed: boolean): Point[] => {
    if (reference.length !== target.length || reference.length === 0) return target;

    const len = reference.length;

    const getError = (ptsA: Point[], ptsB: Point[]) => {
        let err = 0;
        for(let i=0; i<len; i++) {
            const dx = ptsA[i].x - ptsB[i].x;
            const dy = ptsA[i].y - ptsB[i].y;
            err += dx*dx + dy*dy;
        }
        return err;
    };

    let bestPoints = [...target];
    let minError = getError(reference, target);

    // 1. Check Reverse with Hysteresis
    const reversed = [...target].reverse();
    const reverseError = getError(reference, reversed);

    if (reverseError < minError * 0.8) {
        minError = reverseError;
        bestPoints = reversed;
    }

    // 2. Cyclic Shifts (Closed only)
    if (closed) {
        let workingSet = [...bestPoints];
        for (let offset = 1; offset < len; offset++) {
             const shifted = new Array(len);
             for(let k=0; k<len; k++) {
                 shifted[k] = workingSet[(k + offset) % len];
             }
             const err = getError(reference, shifted);
             if (err < minError) {
                 minError = err;
                 bestPoints = shifted;
             }
        }
    } 

    return bestPoints;
};

// --- INTERPOLATION STRATEGIES ---

// Strategy 1: Global Inverse Distance Weighting (Spherical influence)
const calculateIDWWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number
) => {
  const weights: Record<string, number> = {};
  let totalWeight = 0;

  for (const kf of keyframes) {
    let dist = 0;
    for (const axisId in currentAxes) {
      const diff = (currentAxes[axisId] || 0) - (kf.axisValues[axisId] || 0);
      dist += diff * diff;
    }
    dist = Math.sqrt(dist);

    if (dist < 0.001) {
      const result: Record<string, number> = {};
      keyframes.forEach(k => result[k.id] = 0);
      result[kf.id] = 1.0;
      return result;
    }

    const weight = 1 / Math.pow(dist, exponent);
    weights[kf.id] = weight;
    totalWeight += weight;
  }

  if (totalWeight > 0) {
    for (const id in weights) weights[id] /= totalWeight;
  } else {
     weights[keyframes[0].id] = 1;
  }
  return weights;
};

// Strategy 2: Grid-Fill Bilinear (Mesh Logic)
const calculateBilinearGridWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[]
) => {
  const weights: Record<string, number> = {};

  const curX = currentAxes['axis-x'] || 0;
  const curY = currentAxes['axis-y'] || 0;
  const EPSILON = 0.005;

  // 1. Extract Grid Lines
  const distinctCoords = (arr: number[]) => {
      const sorted = [...arr].sort((a,b) => a - b);
      const result = [];
      if (sorted.length > 0) result.push(sorted[0]);
      for (let i = 1; i < sorted.length; i++) {
          if (sorted[i] > sorted[i-1] + EPSILON) result.push(sorted[i]);
      }
      return result;
  };
  const xCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-x'] || 0));
  const yCoords = distinctCoords(keyframes.map(k => k.axisValues['axis-y'] || 0));

  if (xCoords.length === 0 || yCoords.length === 0) {
      if (keyframes.length > 0) weights[keyframes[0].id] = 1;
      return weights;
  }

  // 2. Identify Active Cell (Clamp to edges)
  const findInterval = (val: number, grid: number[]) => {
      if (val <= grid[0]) return { lower: grid[0], upper: grid[0], t: 0 };
      if (val >= grid[grid.length - 1]) return { lower: grid[grid.length - 1], upper: grid[grid.length - 1], t: 0 };
      for (let i = 0; i < grid.length - 1; i++) {
          if (val >= grid[i] && val <= grid[i+1]) {
              const span = grid[i+1] - grid[i];
              return { lower: grid[i], upper: grid[i+1], t: span === 0 ? 0 : (val - grid[i]) / span };
          }
      }
      return { lower: grid[0], upper: grid[0], t: 0 };
  };

  const xInfo = findInterval(curX, xCoords);
  const yInfo = findInterval(curY, yCoords);

  // 3. HELPER: Find Bracketing Neighbors on a specific Axis
  const getBracket = (
     targetFixedVal: number, // e.g. Y=0
     targetVarVal: number,   // e.g. X=0.5
     fixedAxis: 'axis-x' | 'axis-y',
     varAxis: 'axis-x' | 'axis-y'
  ) => {
     // Find all keyframes strictly on the fixed line (e.g. Y=0)
     const onLine = keyframes.filter(k => Math.abs((k.axisValues[fixedAxis]||0) - targetFixedVal) < EPSILON);
     if (onLine.length < 2) return null;

     const sorted = onLine.sort((a,b) => (a.axisValues[varAxis]||0) - (b.axisValues[varAxis]||0));

     // Find strictly Low and High
     const low = [...sorted].reverse().find(k => (k.axisValues[varAxis]||0) <= targetVarVal + EPSILON);
     const high = sorted.find(k => (k.axisValues[varAxis]||0) >= targetVarVal - EPSILON);

     if (low && high) {
        // If they are the same point (exact match), handle elsewhere or return t=0
        const v1 = low.axisValues[varAxis]||0;
        const v2 = high.axisValues[varAxis]||0;
        if (Math.abs(v2 - v1) < EPSILON) return null; // Not a bracket, just a point

        const t = (targetVarVal - v1) / (v2 - v1);
        return { low, high, t };
     }
     return null;
  };

  // 4. Resolve Virtual Corner
  const resolveCornerWeights = (targetX: number, targetY: number) => {
      // A. Exact Match
      const exact = keyframes.find(k => 
          Math.abs((k.axisValues['axis-x']||0) - targetX) < EPSILON && 
          Math.abs((k.axisValues['axis-y']||0) - targetY) < EPSILON
      );
      if (exact) return { [exact.id]: 1.0 };

      // B. Orthogonal Search
      // Try Row Bracket (Left/Right at this Y)
      const rowBracket = getBracket(targetY, targetX, 'axis-y', 'axis-x');
      // Try Col Bracket (Top/Bottom at this X)
      const colBracket = getBracket(targetX, targetY, 'axis-x', 'axis-y');

      // C. Decision Logic
      if (rowBracket && !colBracket) {
         return { [rowBracket.low.id]: 1 - rowBracket.t, [rowBracket.high.id]: rowBracket.t };
      }

      if (!rowBracket && colBracket) {
         return { [colBracket.low.id]: 1 - colBracket.t, [colBracket.high.id]: colBracket.t };
      }

      if (rowBracket && colBracket) {
          const res: Record<string, number> = {};
          const add = (id: string, w: number) => res[id] = (res[id] || 0) + (w * 0.5);
          add(rowBracket.low.id, 1 - rowBracket.t);
          add(rowBracket.high.id, rowBracket.t);
          add(colBracket.low.id, 1 - colBracket.t);
          add(colBracket.high.id, colBracket.t);
          return res;
      }

      // D. Sparse Fallback (No bracket found on either axis)
      let minDist = Infinity;
      let closestId = keyframes[0].id;
      keyframes.forEach(k => {
          const d = Math.sqrt(Math.pow(targetX - (k.axisValues['axis-x']||0), 2) + Math.pow(targetY - (k.axisValues['axis-y']||0), 2));
          if (d < minDist) { minDist = d; closestId = k.id; }
      });
      return { [closestId]: 1.0 };
  };

  // 5. Calculate Weights for the 4 corners of the active cell
  const corners = [
      { x: xInfo.lower, y: yInfo.lower, wBase: (1 - xInfo.t) * (1 - yInfo.t) }, // TL
      { x: xInfo.upper, y: yInfo.lower, wBase: xInfo.t * (1 - yInfo.t) },       // TR
      { x: xInfo.lower, y: yInfo.upper, wBase: (1 - xInfo.t) * yInfo.t },       // BL
      { x: xInfo.upper, y: yInfo.upper, wBase: xInfo.t * yInfo.t }              // BR
  ];

  corners.forEach(c => {
      if (c.wBase <= 0.0001) return;
      const cornerComposition = resolveCornerWeights(c.x, c.y);
      for (const kfId in cornerComposition) {
          weights[kfId] = (weights[kfId] || 0) + (cornerComposition[kfId] * c.wBase);
      }
  });

  // 6. Normalize
  let totalW = 0;
  for (const id in weights) totalW += weights[id];
  if (totalW > 0) {
      for (const id in weights) weights[id] /= totalW;
  }

  return weights;
};

export const calculateInterpolationWeights = (
  currentAxes: Record<string, number>,
  keyframes: { id: string; axisValues: Record<string, number> }[],
  exponent: number = 2,
  strategy: InterpolationStrategy = 'bilinear-grid'
): Record<string, number> => {

   if (keyframes.length === 0) return {};
   if (keyframes.length === 1) {
       return { [keyframes[0].id]: 1.0 };
   }

   if (strategy === 'bilinear-grid') {
       return calculateBilinearGridWeights(currentAxes, keyframes);
   } else {
       return calculateIDWWeights(currentAxes, keyframes, exponent);
   }
};

// --- THE CORE INTERPOLATOR ---

export const interpolateStrokePoints = (
  strokeId: string,
  basePoints: Point[], 
  keyframesData: { weight: number; points: Point[] | undefined, color: string, fillColor?: string, width: number }[],
  mode: 'resample' | 'points' = 'resample'
): { points: Point[], color: string, fillColor: string, width: number } => {

  // 1. Filter and clean inputs
  const activeKeyframes = keyframesData.filter(k => k.weight > 0.0001 && k.points && k.points.length > 0);
  if (activeKeyframes.length === 0) return { points: [], color: 'rgba(0,0,0,0)', fillColor: 'rgba(0,0,0,0)', width: 1 };

  // 2. Mix Colors & Width
  const color = mixColors(keyframesData.map(k => ({ color: k.color, weight: k.weight })));
  const fillColor = mixColors(keyframesData.map(k => ({ color: k.fillColor || 'none', weight: k.weight })));

  // Calculate Weighted Width
  let totalWidth = 0;
  let widthWeightDivisor = 0;
  activeKeyframes.forEach(k => {
      totalWidth += (k.width || 1) * k.weight;
      widthWeightDivisor += k.weight;
  });
  const width = widthWeightDivisor > 0 ? totalWidth / widthWeightDivisor : 1;


  // 3. Determine Target Topology
  let TARGET_COUNT = 0;

  if (mode === 'points') {
      TARGET_COUNT = Math.max(...activeKeyframes.map(k => k.points!.length));
  } else {
      TARGET_COUNT = 200; 
  }

  // 4. Determine Topology Reference (Stable Anchor: First Keyframe)
  const referenceStroke = activeKeyframes[0].points!;
  const referenceResampled = mode === 'resample' 
     ? resamplePoints(referenceStroke, TARGET_COUNT)
     : referenceStroke;

  const isClosed = distance(referenceStroke[0], referenceStroke[referenceStroke.length-1]) < 15;

  // 5. Accumulate Points
  const resultPoints: Point[] = [];

  for (let i = 0; i < TARGET_COUNT; i++) {
      let x = 0;
      let y = 0;
      let pressure = 0;
      let totalWeight = 0;

      for (const kf of activeKeyframes) {
          const rawPoints = kf.points!;
          let processedPoints: Point[] = [];

          if (mode === 'resample') {
              const resampled = resamplePoints(rawPoints, TARGET_COUNT);
              processedPoints = alignPoints(referenceResampled, resampled, isClosed);
          } else {
              const virtualIndex = i * ((rawPoints.length - 1) / (TARGET_COUNT - 1));
              processedPoints = [getPointAtFractionalIndex(rawPoints, virtualIndex)];
          }

          const pt = (mode === 'resample') ? processedPoints[i] : processedPoints[0];

          x += pt.x * kf.weight;
          y += pt.y * kf.weight;
          pressure += (pt.pressure || 0.5) * kf.weight;
          totalWeight += kf.weight;
      }

      if (totalWeight > 0) {
          resultPoints.push({
              x: x / totalWeight,
              y: y / totalWeight,
              pressure: pressure / totalWeight
          });
      }
  }

  return { points: resultPoints, color, fillColor, width };
};

// --- Optimization ---

const perpendicularDistance = (point: Point, lineStart: Point, lineEnd: Point): number => {
  let dx = lineEnd.x - lineStart.x;
  let dy = lineEnd.y - lineStart.y;
  const mag = Math.sqrt(dx * dx + dy * dy);
  if (mag > 0.0) { dx /= mag; dy /= mag; }
  const pvx = point.x - lineStart.x;
  const pvy = point.y - lineStart.y;
  const pvdot = pvx * dx + pvy * dy;
  const dsx = pvdot * dx;
  const dsy = pvdot * dy;
  const ax = pvx - dsx;
  const ay = pvy - dsy;
  return Math.sqrt(ax * ax + ay * ay);
};

export const simplifyPoints = (points: Point[], epsilon: number = 2): Point[] => {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  const end = points.length - 1;
  for (let i = 1; i < end; i++) {
    const d = perpendicularDistance(points[i], points[0], points[end]);
    if (d > dmax) { index = i; dmax = d; }
  }
  if (dmax > epsilon) {
    const recResults1 = simplifyPoints(points.slice(0, index + 1), epsilon);
    const recResults2 = simplifyPoints(points.slice(index, end + 1), epsilon);
    return [...recResults1.slice(0, -1), ...recResults2];
  } else {
    return [points[0], points[end]];
  }
};

