// HELPER: Toggle Component
const SettingsToggle = ({ label, active, onClick }: { label: string, active: boolean, onClick: () => void }) => (
    <div className="flex items-center justify-between py-1 cursor-pointer" onClick={onClick}>
        <span className="text-sm text-gray-600">{label}</span>
        <div className={`w-9 h-5 rounded-full relative transition-colors duration-200 ${active ? 'bg-blue-500' : 'bg-gray-200'}`}>
            <div className={`w-3 h-3 bg-white rounded-full absolute top-1 shadow-sm transition-transform duration-200 ${active ? 'translate-x-5' : 'translate-x-1'}`} />
        </div>
    </div>
);

export const SettingsPanel: React.FC = () => {
  const { 
      project, isSettingsOpen, toggleSettings, ui, 
      toggleGrid, toggleSnapToGrid, toggleOnionSkin, 
      setOnionSkinOpacity, toggleSimplifyStrokes, 
      resetProject, loadProject, toggleSnapMatrixGrid, 
      setAxisMatrixDivisions, setAxisMatrixPadding, 
      setGhostStrokeOpacity, setInterpolationExponent, 
      setInterpolationStrategy, setGridSize 
  } = useStore();

  const fileInputRef = useRef<HTMLInputElement>(null);

  if (!isSettingsOpen) return null;

  const handleExport = () => {
      const data = JSON.stringify(project, null, 2);
      const blob = new Blob([data], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${project.name.replace(/\s+/g, '_').toLowerCase()}_v${project.version}.json`;
      a.click();
      URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onload = (event) => {
              try {
                  const json = JSON.parse(event.target?.result as string);
                  loadProject(json);
              } catch (err) {
                  alert("Invalid project file.");
              }
          };
          reader.readAsText(file);
      }
  };

  return (
    <div 
      onClick={(e) => e.stopPropagation()}
      className="absolute top-28 right-6 w-80 bg-white/95 backdrop-blur-2xl rounded-2xl shadow-2xl border border-gray-100 z-50 flex flex-col max-h-[70vh] pointer-events-auto overflow-hidden animate-in fade-in slide-in-from-top-4 duration-200"
    >
      {/* Header */}
      <div className="flex justify-between items-center p-4 border-b border-gray-100 bg-white/50">
        <h3 className="font-bold text-gray-800 text-base">Settings</h3>
        <button onClick={toggleSettings} className="text-gray-400 hover:text-gray-600 bg-gray-50 rounded-full p-1">
           <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="18 15 12 9 6 15"></polyline></svg>
        </button>
      </div>

      <div className="p-5 space-y-6 overflow-y-auto custom-scrollbar">

        {/* SECTION: CANVAS */}
        <SettingsSection title="Canvas & Guides">
            <SettingsToggle label="Show Grid" active={ui.showGrid} onClick={toggleGrid} />

            <div className="flex items-center justify-between">
                <SettingsToggle label="Snap to Grid" active={ui.snapToGrid} onClick={toggleSnapToGrid} />
                <div className="flex items-center gap-2">
                    <span className="text-xs text-gray-400">Px</span>
                    <input 
                       type="number" 
                       value={ui.gridSize} 
                       onChange={(e) => setGridSize(Math.max(10, parseInt(e.target.value)))}
                       className="w-12 text-xs border border-gray-200 rounded p-1 text-center"
                    />
                </div>
            </div>

            {ui.showGrid && (
                <SettingsRow label="Grid Size" value={`${ui.gridSize}px`}>
                     <input type="range" min="10" max="100" step="10" value={ui.gridSize} onChange={(e) => setGridSize(parseInt(e.target.value))} className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-500"/>
                </SettingsRow>
            )}

            <SettingsToggle label="Simplify Strokes (Clean Lines)" active={ui.simplifyStrokes} onClick={toggleSimplifyStrokes} />

            <SettingsRow label="Ghost Opacity (New State)" value={`${Math.round(ui.ghostStrokeOpacity * 100)}%`}>
                 <input type="range" min="0" max="1" step="0.05" value={ui.ghostStrokeOpacity} onChange={(e) => setGhostStrokeOpacity(parseFloat(e.target.value))} className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-500"/>
            </SettingsRow>

             <SettingsToggle label="Onion Skin" active={ui.onionSkinEnabled} onClick={toggleOnionSkin} />
             {ui.onionSkinEnabled && (
                <SettingsRow label="Opacity" value={`${Math.round(ui.onionSkinOpacity * 100)}%`}>
                     <input type="range" min="0.05" max="0.5" step="0.05" value={ui.onionSkinOpacity} onChange={(e) => setOnionSkinOpacity(parseFloat(e.target.value))} className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-500"/>
                </SettingsRow>
             )}
        </SettingsSection>

        {/* SECTION: INTERPOLATION */}
        <SettingsSection title="Interpolation Matrix">
             <SettingsToggle label="Snap Matrix Keyframes" active={ui.snapMatrixGrid} onClick={toggleSnapMatrixGrid} />

             <SettingsRow label="Grid Divisions" value={`${ui.axisMatrixDivisions}x${ui.axisMatrixDivisions}`}>
                <input type="range" min="2" max="20" step="1" value={ui.axisMatrixDivisions} onChange={(e) => setAxisMatrixDivisions(parseInt(e.target.value))} className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-500"/>
             </SettingsRow>

             <SettingsRow label="Edge Padding" value={`${Math.round(ui.axisMatrixPadding * 100)}%`}>
                <input type="range" min="0" max="0.2" step="0.01" value={ui.axisMatrixPadding} onChange={(e) => setAxisMatrixPadding(parseFloat(e.target.value))} className="w-full h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-500"/>
             </SettingsRow>

             <div className="pt-2">
                <label className="text-xs text-gray-500 font-medium mb-1 block">Algorithm</label>
                <div className="flex bg-gray-100 rounded-lg p-1">
                    <button onClick={() => setInterpolationStrategy('bilinear-grid')} className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${ui.interpolationStrategy === 'bilinear-grid' ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>
                        Bilinear Grid
                    </button>
                    <button onClick={() => setInterpolationStrategy('idw')} className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${ui.interpolationStrategy === 'idw' ? 'bg-white shadow text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>
                        Radial
                    </button>
                </div>
             </div>
        </SettingsSection>

        {/* SECTION: PROJECT */}
        <SettingsSection title="Project Management">
             <div className="grid grid-cols-2 gap-2">
                 <button onClick={handleExport} className="bg-gray-50 hover:bg-gray-100 border border-gray-200 text-gray-700 text-xs font-bold py-2.5 rounded-xl flex items-center justify-center gap-2 transition-colors">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                    Export JSON
                 </button>
                 <button onClick={() => fileInputRef.current?.click()} className="bg-gray-50 hover:bg-gray-100 border border-gray-200 text-gray-700 text-xs font-bold py-2.5 rounded-xl flex items-center justify-center gap-2 transition-colors">
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
                    Import JSON
                 </button>
                 <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />
             </div>

             <button 
                onClick={() => { if(confirm('Are you sure you want to reset the entire project? This cannot be undone.')) resetProject(); }} 
                className="w-full mt-2 bg-red-50 hover:bg-red-100 text-red-600 border border-red-200 text-xs font-bold py-3 rounded-xl transition-colors flex items-center justify-center gap-2"
             >
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                Reset Project
             </button>
        </SettingsSection>

      </div>
    </div>
  );
