// store/useStore.ts
import { create } from 'zustand';
import { Project, UIState, ToolType, Axis, Layer, Keyframe, Point, Stroke, LayerState, BlendMode, UIMode, InterpolationMode, InterpolationStrategy } from '../types';
import { DEFAULT_PROJECT, INITIAL_UI_STATE, DEFAULT_LAYER, DEFAULT_KEYFRAME } from '../constants';
import { simplifyPoints, distance } from '../utils/math';

interface StoreState {
  project: Project;
  ui: UIState;

  history: {
    past: Project[];
    future: Project[];
  };

  isSettingsOpen: boolean;

  // Actions
  undo: () => void;
  redo: () => void;

  // Project Actions
  resetProject: () => void;
  loadProject: (project: Project) => void;

  toggleSettings: () => void;
  toggleLayerPanel: () => void;
  closeAllPanels: () => void; // Used for clicking outside

  setMode: (mode: UIMode) => void;

  setTool: (tool: ToolType) => void;
  setBrushColor: (color: string) => void;
  setFillColor: (color: string) => void;
  setBrushSize: (size: number) => void;

  // Config Actions
  toggleGrid: () => void;
  toggleSnapToGrid: () => void;

  toggleSnapPlayMode: () => void;
  toggleSnapMatrixGrid: () => void;
  setAxisMatrixDivisions: (val: number) => void;
  setAxisMatrixPadding: (val: number) => void;
  setInterpolationExponent: (val: number) => void;
  setInterpolationStrategy: (val: InterpolationStrategy) => void; // New

  setGridSize: (size: number) => void;
  toggleSimplifyStrokes: () => void;

  toggleOnionSkin: () => void;
  setOnionSkinOpacity: (opacity: number) => void;
  setInactiveLayerOpacity: (opacity: number) => void;
  setGhostStrokeOpacity: (opacity: number) => void;

  // Layer Actions
  addLayer: () => void;
  deleteLayer: (layerId: string) => void;
  renameLayer: (layerId: string, name: string) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  toggleLayerVisibility: (layerId: string) => void;
  toggleLayerLock: (layerId: string) => void;
  setLayerBlendMode: (layerId: string, mode: BlendMode) => void;
  setLayerInterpolationMode: (layerId: string, mode: InterpolationMode) => void; // New
  selectLayer: (layerId: string) => void;

  updateAxisValue: (axisId: string, value: number) => void;

  addStrokeToCurrentKeyframe: (points: Point[], closed?: boolean, skipSimplify?: boolean) => void; // Updated sig
  updateStrokeInCurrentKeyframe: (strokeId: string, newPoints: Point[]) => void;

  createKeyframeAtCurrentAxes: () => void;
  deleteKeyframe: (keyframeId: string) => void;
  selectKeyframe: (keyframeId: string) => void;

  selectStroke: (strokeId: string | null) => void;
}

const MAX_HISTORY = 50;

export const useStore = create<StoreState>((set, get) => ({
  project: DEFAULT_PROJECT,
  ui: INITIAL_UI_STATE,
  isSettingsOpen: false,

  history: {
    past: [],
    future: []
  },

  resetProject: () => set(() => ({
      project: {
          ...DEFAULT_PROJECT,
          id: `project-${Date.now()}`,
          created: Date.now(),
          modified: Date.now(),
          // Ensure distinct instances for object references
          layers: [{...DEFAULT_LAYER, id: `layer-${Date.now()}`}],
          keyframes: [{...DEFAULT_KEYFRAME, id: `kf-${Date.now()}`, layerStates: [{ layerId: `layer-${Date.now()}`, strokes: [] }] }]
      },
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: `layer-${Date.now()}`,
          selectedKeyframeId: `kf-${Date.now()}`
      },
      history: { past: [], future: [] }
  })),

  loadProject: (project) => set(() => ({
      project: project,
      ui: {
          ...INITIAL_UI_STATE,
          selectedLayerId: project.layers[0]?.id || null,
          selectedKeyframeId: project.keyframes[0]?.id || null
      },
      history: { past: [], future: [] }
  })),

  toggleSettings: () => set((state) => ({ isSettingsOpen: !state.isSettingsOpen, ui: { ...state.ui, isLayerPanelOpen: false } })),
  toggleLayerPanel: () => set((state) => ({ ui: { ...state.ui, isLayerPanelOpen: !state.ui.isLayerPanelOpen }, isSettingsOpen: false })),
  closeAllPanels: () => set((state) => ({ isSettingsOpen: false, ui: { ...state.ui, isLayerPanelOpen: false } })),

  setMode: (mode) => set((state) => ({ ui: { ...state.ui, mode } })),

  undo: () => set((state) => {
    if (state.history.past.length === 0) return state;
    const previous = state.history.past[state.history.past.length - 1];
    const newPast = state.history.past.slice(0, -1);
    return {
      project: previous,
      history: {
        past: newPast,
        future: [state.project, ...state.history.future]
      }
    };
  }),

  redo: () => set((state) => {
    if (state.history.future.length === 0) return state;
    const next = state.history.future[0];
    const newFuture = state.history.future.slice(1);
    return {
      project: next,
      history: {
        past: [...state.history.past, state.project],
        future: newFuture
      }
    };
  }),

  setTool: (tool) => set((state) => ({ ui: { ...state.ui, selectedTool: tool, selectedStrokeId: null } })),

  // UPDATED: Live update of stroke properties
  setBrushColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    // Try to update existing stroke if we are on a keyframe
    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 // Push to history
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 // Update the first stroke (Puppet Mode assumption)
                 newStrokes[0] = { ...newStrokes[0], color: color === 'none' ? 'rgba(0,0,0,0)' : color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
       ui: { ...state.ui, brushColor: color },
       project,
       history
    };
  }),

  // UPDATED: Live update of stroke properties
  setFillColor: (color) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], fillColor: color };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, fillColor: color },
        project,
        history
    };
  }),

  // UPDATED: Live update of stroke properties
  setBrushSize: (size) => set((state) => {
    let project = state.project;
    let history = state.history;

    if (state.ui.selectedKeyframeId && state.ui.selectedLayerId) {
        const kfId = state.ui.selectedKeyframeId;
        const layerId = state.ui.selectedLayerId;

        const kfIndex = project.keyframes.findIndex(k => k.id === kfId);
        if (kfIndex > -1) {
             const kf = project.keyframes[kfIndex];
             const lsIndex = kf.layerStates.findIndex(ls => ls.layerId === layerId);

             if (lsIndex > -1 && kf.layerStates[lsIndex].strokes.length > 0) {
                 const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

                 const newKeyframes = [...project.keyframes];
                 const newKf = { ...newKeyframes[kfIndex] };
                 const newLayerStates = [...newKf.layerStates];
                 const newLs = { ...newLayerStates[lsIndex] };
                 const newStrokes = [...newLs.strokes];

                 newStrokes[0] = { ...newStrokes[0], width: size };

                 newLs.strokes = newStrokes;
                 newLayerStates[lsIndex] = newLs;
                 newKf.layerStates = newLayerStates;
                 newKeyframes[kfIndex] = newKf;

                 project = { ...project, keyframes: newKeyframes };
                 history = { past, future: [] };
             }
        }
    }

    return { 
        ui: { ...state.ui, brushSize: size },
        project,
        history
    };
  }),

  toggleGrid: () => set((state) => ({ ui: { ...state.ui, showGrid: !state.ui.showGrid } })),
  toggleSnapToGrid: () => set((state) => ({ ui: { ...state.ui, snapToGrid: !state.ui.snapToGrid } })),

  toggleSnapPlayMode: () => set((state) => ({ ui: { ...state.ui, snapPlayMode: !state.ui.snapPlayMode } })),
  toggleSnapMatrixGrid: () => set((state) => ({ ui: { ...state.ui, snapMatrixGrid: !state.ui.snapMatrixGrid } })),
  setAxisMatrixDivisions: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixDivisions: val } })),
  setAxisMatrixPadding: (val) => set((state) => ({ ui: { ...state.ui, axisMatrixPadding: val } })),
  setInterpolationExponent: (val) => set((state) => ({ ui: { ...state.ui, interpolationExponent: val } })),
  setInterpolationStrategy: (val) => set((state) => ({ ui: { ...state.ui, interpolationStrategy: val } })),

  setGridSize: (size) => set((state) => ({ ui: { ...state.ui, gridSize: size } })),
  toggleSimplifyStrokes: () => set((state) => ({ ui: { ...state.ui, simplifyStrokes: !state.ui.simplifyStrokes } })),

  toggleOnionSkin: () => set((state) => ({ ui: { ...state.ui, onionSkinEnabled: !state.ui.onionSkinEnabled } })),
  setOnionSkinOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, onionSkinOpacity: opacity } })),
  setInactiveLayerOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, inactiveLayerOpacity: opacity } })),
  setGhostStrokeOpacity: (opacity) => set((state) => ({ ui: { ...state.ui, ghostStrokeOpacity: opacity } })),

  updateAxisValue: (axisId, value) => set((state) => {
    // Smooth value
    const cleanValue = Math.max(0, Math.min(1, value));

    const newAxes = state.project.axes.map(a => 
      a.id === axisId ? { ...a, currentValue: cleanValue } : a
    );

    const currentAxisValues: Record<string, number> = {};
    newAxes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    // Strict Selection Logic:
    // If we are NOT exactly on a keyframe (with small threshold), we are in an INTERPOLATED state.
    // In this case, selectedKeyframeId should be NULL.
    let matchingKfId = null;

    const exactMatch = state.project.keyframes.find(kf => {
      let dist = 0;
      for (const id in currentAxisValues) {
        dist += Math.abs((kf.axisValues[id] || 0) - currentAxisValues[id]);
      }
      return dist < 0.02; // Slightly wider threshold for snapping comfort
    });

    if (exactMatch) {
      matchingKfId = exactMatch.id;
    }

    return { 
      project: { ...state.project, axes: newAxes },
      ui: { ...state.ui, selectedKeyframeId: matchingKfId }
    };
  }),

  selectLayer: (layerId) => set((state) => ({ ui: { ...state.ui, selectedLayerId: layerId } })),
  selectKeyframe: (keyframeId) => set((state) => ({ ui: { ...state.ui, selectedKeyframeId: keyframeId } })),
  selectStroke: (strokeId) => set((state) => ({ ui: { ...state.ui, selectedStrokeId: strokeId } })),

  addLayer: () => set((state) => {
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newId = `layer-${Date.now()}`;
    const newLayer: Layer = {
      id: newId,
      name: `Layer ${state.project.layers.length + 1}`,
      visible: true,
      locked: false,
      blendMode: 'normal',
      opacity: 1,
      interpolationMode: 'resample'
    };
    return {
      project: { ...state.project, layers: [...state.project.layers, newLayer] },
      ui: { ...state.ui, selectedLayerId: newId },
      history: { past, future: [] }
    };
  }),

  reorderLayers: (fromIndex, toIndex) => set((state) => {
    if (fromIndex === toIndex) return state;
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = [...state.project.layers];
    const [moved] = newLayers.splice(fromIndex, 1);
    newLayers.splice(toIndex, 0, moved);

    return {
       project: { ...state.project, layers: newLayers },
       history: { past, future: [] }
    };
  }),

  deleteLayer: (layerId) => set((state) => {
    if (state.project.layers.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newLayers = state.project.layers.filter(l => l.id !== layerId);

    const newKeyframes = state.project.keyframes.map(kf => ({
       ...kf,
       layerStates: kf.layerStates.filter(ls => ls.layerId !== layerId)
    }));

    return {
      project: { ...state.project, layers: newLayers, keyframes: newKeyframes },
      ui: { ...state.ui, selectedLayerId: newLayers[newLayers.length - 1].id },
      history: { past, future: [] }
    };
  }),

  renameLayer: (layerId, name) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => l.id === layerId ? { ...l, name } : l)
    }
  })),

  toggleLayerVisibility: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, visible: !l.visible } : l
      )
    }
  })),

  toggleLayerLock: (layerId) => set((state) => ({
    project: {
      ...state.project,
      layers: state.project.layers.map(l => 
        l.id === layerId ? { ...l, locked: !l.locked } : l
      )
    }
  })),

  setLayerBlendMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, blendMode: mode } : l
        )
      }
    };
  }),

  setLayerInterpolationMode: (layerId, mode) => set((state) => {
    return {
      project: {
        ...state.project,
        layers: state.project.layers.map(l => 
          l.id === layerId ? { ...l, interpolationMode: mode } : l
        )
      }
    };
  }),

  addStrokeToCurrentKeyframe: (rawPoints, closed = false, skipSimplify = false) => set((state) => {
    const { selectedLayerId, brushColor, fillColor, brushSize, simplifyStrokes, snapToGrid } = state.ui;
    if (!selectedLayerId) return state;

    const layer = state.project.layers.find(l => l.id === selectedLayerId);
    if (layer?.locked || !layer?.visible) return state;

    // --- SMART DEFAULTS LOGIC ---
    let points = rawPoints;
    let shouldUpdateLayerMode = false;

    // If SnapToGrid is active, we enforce clean lines and point interpolation
    if (snapToGrid) {
        // Force simplification (Clean Lines) with decent epsilon
        points = simplifyPoints(rawPoints, 2.5);

        // If layer is currently in 'resample' mode, we should switch it to 'points'
        if (layer.interpolationMode === 'resample') {
            shouldUpdateLayerMode = true;
        }
    } else if (simplifyStrokes && !skipSimplify) {
       points = simplifyPoints(rawPoints, 2.5);
    }

    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);

    // --- STATE PREPARATION ---

    // Update Layer Mode if needed
    let updatedLayers = [...state.project.layers];
    if (shouldUpdateLayerMode) {
        updatedLayers = updatedLayers.map(l => 
            l.id === selectedLayerId ? { ...l, interpolationMode: 'points' } : l
        );
    }

    const currentAxisValues: Record<string, number> = {};
    state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

    let targetKeyframeId = state.ui.selectedKeyframeId;
    let keyframes = [...state.project.keyframes];

    if (targetKeyframeId === null) {
      const newKfId = `kf-${Date.now()}`;
      const newKeyframe: Keyframe = {
        id: newKfId,
        name: `Keyframe ${keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: [] 
      };
      keyframes.push(newKeyframe);
      targetKeyframeId = newKfId;
    }

    const newStroke: Stroke = {
      id: `stroke-${selectedLayerId}-unique`,
      points,
      color: brushColor as string, 
      fillColor: fillColor,
      width: brushSize,
      style: 'solid',
      closed: closed
    };

    const newKeyframes = keyframes.map(kf => {
      if (kf.id === targetKeyframeId) {
        const existingLayerStateIndex = kf.layerStates.findIndex(ls => ls.layerId === selectedLayerId);
        let newLayerStates = [...kf.layerStates];

        if (existingLayerStateIndex >= 0) {
          newLayerStates[existingLayerStateIndex] = {
            ...newLayerStates[existingLayerStateIndex],
            strokes: [newStroke]
          };
        } else {
          newLayerStates.push({
            layerId: selectedLayerId,
            strokes: [newStroke]
          });
        }
        return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { 
      project: { ...state.project, keyframes: newKeyframes, layers: updatedLayers },
      ui: { ...state.ui, selectedKeyframeId: targetKeyframeId },
      history: { past, future: [] }
    };
  }),

  updateStrokeInCurrentKeyframe: (strokeId, newPoints) => set((state) => {
    const kfId = state.ui.selectedKeyframeId;
    if (!kfId) return state;

    const keyframes = state.project.keyframes.map(kf => {
      if (kf.id === kfId) {
         const newLayerStates = kf.layerStates.map(ls => {
            if (ls.layerId === state.ui.selectedLayerId) {
               return {
                  ...ls,
                  strokes: ls.strokes.map(s => ({ ...s, points: newPoints }))
               };
            }
            return ls;
         });
         return { ...kf, layerStates: newLayerStates };
      }
      return kf;
    });

    return { project: { ...state.project, keyframes }};
  }),

  createKeyframeAtCurrentAxes: () => set((state) => {
     const currentAxisValues: Record<string, number> = {};
     state.project.axes.forEach(a => currentAxisValues[a.id] = a.currentValue);

     const newKeyframe: Keyframe = {
        id: `kf-${Date.now()}`,
        name: `Keyframe ${state.project.keyframes.length}`,
        axisValues: currentAxisValues,
        layerStates: []
      };

      return {
        project: { ...state.project, keyframes: [...state.project.keyframes, newKeyframe] },
        ui: { ...state.ui, selectedKeyframeId: newKeyframe.id }
      };
  }),

  deleteKeyframe: (keyframeId) => set((state) => {
    if (state.project.keyframes.length <= 1) return state; 
    const past = [...state.history.past, state.project].slice(-MAX_HISTORY);
    const newKeyframes = state.project.keyframes.filter(k => k.id !== keyframeId);

    let newSelectedId = state.ui.selectedKeyframeId;
    if (keyframeId === newSelectedId) {
      newSelectedId = newKeyframes[0].id;
    }

    return {
      project: { ...state.project, keyframes: newKeyframes },
      ui: { ...state.ui, selectedKeyframeId: newSelectedId },
      history: { past, future: [] }
    };
  })
}));

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke } = useStore();

  // -- State --
  const currentPointsRef = useRef<Point[]>([]); 
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Transform State
  const [interactionMode, setInteractionMode] = useState<InteractionMode>('none');
  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);

  // Transform Data
  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; // Original points snapshot
  } | null>(null);

  // Live Bounding Box (Visual only, committed on drag end)
  const [selectionBounds, setSelectionBounds] = useState<{
      cx: number; cy: number; width: number; height: number; rotation: number;
  } | null>(null);

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- Selection Logic --

  // Update selection bounds when selection changes
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }

    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;

    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;

    // Calculate AABB (Axis Aligned Bounding Box)
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX,
        cy: bbox.centerY,
        width: bbox.width,
        height: bbox.height,
        rotation: 0 // Reset rotation on new selection (simplification)
    });

  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Hit Testing for Gizmos --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;

      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2;
      const hh = height / 2;

      // Rotate point into local space of the box to check handles easily
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);

      const HANDLE_SIZE = 10 / scale; // Screen-consistent size

      // Rotator (Top + offset)
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';

      // Corners
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';

      // Body (Hit test roughly inside box)
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';

      return null;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    // 1. Play Mode
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }

    // 2. Select / Transform Mode
    if (ui.selectedTool === 'select') {
        const hitGizmo = getGizmoHit(p, selectionBounds);

        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            // Initiate Transform
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

            if (stroke) {
                setTransformStart({
                    mouse: p,
                    center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation,
                    width: selectionBounds.width,
                    height: selectionBounds.height,
                    points: stroke.points // Snapshot original points
                });

                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else {
                    setInteractionMode('resizing');
                    setActiveHandle(hitGizmo as ResizeHandle);
                }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }

        // Select Stroke
        const hitId = findHitStroke(p);
        if (hitId) {
            selectStroke(hitId);
            // Don't start drag immediately to prevent jump, wait for next move or explicit drag
        } else {
            selectStroke(null);
        }
        return;
    }

    // 3. Polyline
    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);

       // A. Closing Loop Logic (Clicking near first point)
       // RESTRICTION: Only close automatically if Fill Color is present
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           if (ui.fillColor !== 'none') {
               addStrokeToCurrentKeyframe(polylinePoints, true, true);
               setPolylinePoints([]);
               return;
           }
       }

       // B. Finishing Line Logic (Clicking near last point - Double Click simulation)
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           // If we click very close to the last placed point, we finish the open line
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }

       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    // 4. Pen
    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing');
      setIsDrawing(true);
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p)); // Snap cursor preview

    // Play Mode
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        let normX = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        let normY = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }
        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }

    // Transform Logic
    if (interactionMode !== 'none' && transformStart && selectionBounds) {

        // A. DRAGGING (MOVE)
        if (interactionMode === 'dragging') {
            let dx = p.x - transformStart.mouse.x;
            let dy = p.y - transformStart.mouse.y;

            // Snap delta to grid
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx;
                const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize;
                const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x;
                dy = snappedY - transformStart.center.y;
            }

            setSelectionBounds({
                ...selectionBounds,
                cx: transformStart.center.x + dx,
                cy: transformStart.center.y + dy
            });
        }

        // B. ROTATING
        else if (interactionMode === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle;
            let newRotation = transformStart.angle + dAngle;

            // Shift to snap rotation (15 deg / 45 deg steps)
            if (e.shiftKey) {
                const step = Math.PI / 12; // 15 deg
                newRotation = Math.round(newRotation / step) * step;
            }

            setSelectionBounds({
                ...selectionBounds,
                rotation: newRotation
            });
        }

        // C. RESIZING
        else if (interactionMode === 'resizing' && activeHandle) {
            // Calculate delta in rotated space
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x;
            let dy = unrotatedMouse.y - unrotatedStart.y;

            // Proportional Resize (Shift)
            if (e.shiftKey) {
                const aspect = transformStart.width / transformStart.height;
                if (activeHandle === 'br' || activeHandle === 'tl') {
                    dy = dx / aspect;
                } else {
                    dy = -dx / aspect;
                }
            }

            // Snap Size to Grid
            if (ui.snapToGrid && !e.shiftKey) {
                 // Simplistic snap for resize delta
                 dx = Math.round(dx / ui.gridSize) * ui.gridSize;
                 dy = Math.round(dy / ui.gridSize) * ui.gridSize;
            }

            let newW = transformStart.width;
            let newH = transformStart.height;
            // Center usually shifts during resize unless Alt is held (not implemented)
            // But for now let's scale from center (simplest) or corner? 
            // Corner is better.

            // Actually, scaling from center is easier for the Gizmo logic we have
            // Let's modify width/height
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; } // Scale from center logic
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }

            // Prevent flipping
            newW = Math.max(1, newW);
            newH = Math.max(1, newH);

            setSelectionBounds({
                ...selectionBounds,
                width: newW,
                height: newH
            });
        }
        return;
    }

    // Drawing
    if (interactionMode === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    (e.target as Element).releasePointerCapture(e.pointerId);

    // Commit Transform
    if (interactionMode !== 'none' && transformStart && selectionBounds && ui.selectedStrokeId) {
        // We need to apply the transformation matrix (S * R * T) to the original points
        // T = NewCenter - OldCenter
        // R = NewRotation - OldRotation
        // S = NewSize / OldSize

        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;

        const newPoints = transformStart.points.map(pt => {
            // 1. Localize to center
            let x = pt.x - transformStart.center.x;
            let y = pt.y - transformStart.center.y;

            // 2. Rotate (Initial offset) -> unnecessary if we assume 0 rotation start for bbox, 
            // but stroke points might be anywhere.
            // Actually, we rotate points around center by dRot
            // But wait, the points were unrotated relative to the bbox? No.

            // Standard Affine Transform:
            // P' = T * R * S * P_local

            // Scale
            x *= scaleX;
            y *= scaleY;

            // Rotate
            const cos = Math.cos(dRot);
            const sin = Math.sin(dRot);
            const rx = x * cos - y * sin;
            const ry = x * sin + y * cos;

            // Translate
            return {
                x: rx + transformStart.center.x + dX,
                y: ry + transformStart.center.y + dY,
                pressure: pt.pressure
            };
        });

        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // Commit Drawing
    if (interactionMode === 'drawing') {
        if (currentPointsRef.current.length > 1) {
            const start = currentPointsRef.current[0];
            const end = currentPointsRef.current[currentPointsRef.current.length - 1];

            // RESTRICTION: Only close automatically if Fill Color is present
            let isClosed = false;
            if (ui.fillColor !== 'none' && distance(start, end) < 15) {
                isClosed = true;
            }

            addStrokeToCurrentKeyframe([...currentPointsRef.current], isClosed);
        }
    }

    // Reset
    setInteractionMode('none');
    setIsDrawing(false);
    setActiveHandle(null);
    setTransformStart(null);
    currentPointsRef.current = [];
  };

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) {
              addStrokeToCurrentKeyframe(polylinePoints, false, true);
          }
          setPolylinePoints([]);
      }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
          if (ui.selectedTool === 'polyline') handleDoubleClick();
      }
      if (e.key === 'Escape') {
          setPolylinePoints([]);
          setInteractionMode('none');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [polylinePoints, ui.selectedTool]);


  // -- Render Loop --
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; 
           ctx.globalAlpha = ui.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== ui.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      project.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = project.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, ui.interpolationExponent, ui.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === ui.selectedLayerId;
        const isCreatingNewState = ui.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && ui.mode !== 'play') layerGlobalAlpha *= ui.inactiveLayerOpacity;
        if (isCreatingNewState && ui.mode === 'edit') layerGlobalAlpha *= ui.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, primaryStroke.points, strokeData, layer.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            if (primaryStroke.closed) ctx.closePath();

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING
      if (isDrawing && currentPointsRef.current.length > 0) {
        // If we are drawing in an undefined state (interpolated state), use reduced opacity
        // Otherwise (we are on a keyframe), use full opacity
        const isGhostState = ui.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         // Same ghost logic for polyline
         const isGhostState = ui.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) ctx.lineTo(mousePos.x, mousePos.y); 

         if (ui.fillColor !== 'none') {
             ctx.fillStyle = ui.fillColor;
             // Fill should be slightly transparent while drawing
             ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = ui.brushSize;
         ctx.stroke();

         ctx.fillStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // GIZMOS (Transform Tool)
      if (selectionBounds && ui.selectedTool === 'select' && ui.mode === 'edit') {
          const { cx, cy, width, height, rotation } = selectionBounds;

          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          // Bounding Box
          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          // Handles
          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          // Rotation Handle
          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, polylinePoints, mousePos, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT, selectionBounds, interactionMode, transformStart]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke } = useStore();

  // -- State --
  const currentPointsRef = useRef<Point[]>([]); 
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Transform State
  const [interactionMode, setInteractionMode] = useState<InteractionMode>('none');
  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);

  // Transform Data
  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; // Original points snapshot
  } | null>(null);

  // Live Bounding Box (Visual only, committed on drag end)
  const [selectionBounds, setSelectionBounds] = useState<{
      cx: number; cy: number; width: number; height: number; rotation: number;
  } | null>(null);

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- Selection Logic --

  // Update selection bounds when selection changes
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }

    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;

    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;

    // Calculate AABB (Axis Aligned Bounding Box)
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX,
        cy: bbox.centerY,
        width: bbox.width,
        height: bbox.height,
        rotation: 0 // Reset rotation on new selection (simplification)
    });

  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Hit Testing for Gizmos --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;

      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2;
      const hh = height / 2;

      // Rotate point into local space of the box to check handles easily
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);

      const HANDLE_SIZE = 10 / scale; // Screen-consistent size

      // Rotator (Top + offset)
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';

      // Corners
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';

      // Body (Hit test roughly inside box)
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';

      return null;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    // 1. Play Mode
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }

    // 2. Select / Transform Mode
    if (ui.selectedTool === 'select') {
        const hitGizmo = getGizmoHit(p, selectionBounds);

        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            // Initiate Transform
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

            if (stroke) {
                setTransformStart({
                    mouse: p,
                    center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation,
                    width: selectionBounds.width,
                    height: selectionBounds.height,
                    points: stroke.points // Snapshot original points
                });

                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else {
                    setInteractionMode('resizing');
                    setActiveHandle(hitGizmo as ResizeHandle);
                }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }

        // Select Stroke
        const hitId = findHitStroke(p);
        if (hitId) {
            selectStroke(hitId);
            // Don't start drag immediately to prevent jump, wait for next move or explicit drag
        } else {
            selectStroke(null);
        }
        return;
    }

    // 3. Polyline
    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);

       // A. Closing Loop Logic (Clicking near first point)
       // RESTRICTION: Only close automatically if Fill Color is present
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           if (ui.fillColor !== 'none') {
               addStrokeToCurrentKeyframe(polylinePoints, true, true);
               setPolylinePoints([]);
               return;
           }
       }

       // B. Finishing Line Logic (Clicking near last point - Double Click simulation)
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           // If we click very close to the last placed point, we finish the open line
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }

       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    // 4. Pen
    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing');
      setIsDrawing(true);
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p)); // Snap cursor preview

    // Play Mode
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        let normX = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        let normY = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }
        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }

    // Transform Logic
    if (interactionMode !== 'none' && transformStart && selectionBounds) {

        // A. DRAGGING (MOVE)
        if (interactionMode === 'dragging') {
            let dx = p.x - transformStart.mouse.x;
            let dy = p.y - transformStart.mouse.y;

            // Snap delta to grid
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx;
                const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize;
                const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x;
                dy = snappedY - transformStart.center.y;
            }

            setSelectionBounds({
                ...selectionBounds,
                cx: transformStart.center.x + dx,
                cy: transformStart.center.y + dy
            });
        }

        // B. ROTATING
        else if (interactionMode === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle;
            let newRotation = transformStart.angle + dAngle;

            // Shift to snap rotation (15 deg / 45 deg steps)
            if (e.shiftKey) {
                const step = Math.PI / 12; // 15 deg
                newRotation = Math.round(newRotation / step) * step;
            }

            setSelectionBounds({
                ...selectionBounds,
                rotation: newRotation
            });
        }

        // C. RESIZING
        else if (interactionMode === 'resizing' && activeHandle) {
            // Calculate delta in rotated space
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x;
            let dy = unrotatedMouse.y - unrotatedStart.y;

            // Proportional Resize (Shift)
            if (e.shiftKey) {
                const aspect = transformStart.width / transformStart.height;
                if (activeHandle === 'br' || activeHandle === 'tl') {
                    dy = dx / aspect;
                } else {
                    dy = -dx / aspect;
                }
            }

            // Snap Size to Grid
            if (ui.snapToGrid && !e.shiftKey) {
                 // Simplistic snap for resize delta
                 dx = Math.round(dx / ui.gridSize) * ui.gridSize;
                 dy = Math.round(dy / ui.gridSize) * ui.gridSize;
            }

            let newW = transformStart.width;
            let newH = transformStart.height;
            // Center usually shifts during resize unless Alt is held (not implemented)
            // But for now let's scale from center (simplest) or corner? 
            // Corner is better.

            // Actually, scaling from center is easier for the Gizmo logic we have
            // Let's modify width/height
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; } // Scale from center logic
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }

            // Prevent flipping
            newW = Math.max(1, newW);
            newH = Math.max(1, newH);

            setSelectionBounds({
                ...selectionBounds,
                width: newW,
                height: newH
            });
        }
        return;
    }

    // Drawing
    if (interactionMode === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    (e.target as Element).releasePointerCapture(e.pointerId);

    // Commit Transform
    if (interactionMode !== 'none' && transformStart && selectionBounds && ui.selectedStrokeId) {
        // We need to apply the transformation matrix (S * R * T) to the original points
        // T = NewCenter - OldCenter
        // R = NewRotation - OldRotation
        // S = NewSize / OldSize

        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;

        const newPoints = transformStart.points.map(pt => {
            // 1. Localize to center
            let x = pt.x - transformStart.center.x;
            let y = pt.y - transformStart.center.y;

            // 2. Rotate (Initial offset) -> unnecessary if we assume 0 rotation start for bbox, 
            // but stroke points might be anywhere.
            // Actually, we rotate points around center by dRot
            // But wait, the points were unrotated relative to the bbox? No.

            // Standard Affine Transform:
            // P' = T * R * S * P_local

            // Scale
            x *= scaleX;
            y *= scaleY;

            // Rotate
            const cos = Math.cos(dRot);
            const sin = Math.sin(dRot);
            const rx = x * cos - y * sin;
            const ry = x * sin + y * cos;

            // Translate
            return {
                x: rx + transformStart.center.x + dX,
                y: ry + transformStart.center.y + dY,
                pressure: pt.pressure
            };
        });

        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // Commit Drawing
    if (interactionMode === 'drawing') {
        if (currentPointsRef.current.length > 1) {
            // REMOVED AUTO-CLOSE LOGIC FOR PEN TOOL AS REQUESTED
            addStrokeToCurrentKeyframe([...currentPointsRef.current], false);
        }
    }

    // Reset
    setInteractionMode('none');
    setIsDrawing(false);
    setActiveHandle(null);
    setTransformStart(null);
    currentPointsRef.current = [];
  };

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) {
              addStrokeToCurrentKeyframe(polylinePoints, false, true);
          }
          setPolylinePoints([]);
      }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
          if (ui.selectedTool === 'polyline') handleDoubleClick();
      }
      if (e.key === 'Escape') {
          setPolylinePoints([]);
          setInteractionMode('none');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [polylinePoints, ui.selectedTool]);


  // -- Render Loop --
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; 
           ctx.globalAlpha = ui.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== ui.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      project.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = project.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, ui.interpolationExponent, ui.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === ui.selectedLayerId;
        const isCreatingNewState = ui.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && ui.mode !== 'play') layerGlobalAlpha *= ui.inactiveLayerOpacity;
        if (isCreatingNewState && ui.mode === 'edit') layerGlobalAlpha *= ui.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, primaryStroke.points, strokeData, layer.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            if (primaryStroke.closed) ctx.closePath();

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING
      if (isDrawing && currentPointsRef.current.length > 0) {
        // If we are drawing in an undefined state (interpolated state), use reduced opacity
        // Otherwise (we are on a keyframe), use full opacity
        const isGhostState = ui.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         // Same ghost logic for polyline
         const isGhostState = ui.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) ctx.lineTo(mousePos.x, mousePos.y); 

         if (ui.fillColor !== 'none') {
             ctx.fillStyle = ui.fillColor;
             // Fill should be slightly transparent while drawing
             ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = ui.brushSize;
         ctx.stroke();

         ctx.fillStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // GIZMOS (Transform Tool)
      if (selectionBounds && ui.selectedTool === 'select' && ui.mode === 'edit') {
          const { cx, cy, width, height, rotation } = selectionBounds;

          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          // Bounding Box
          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          // Handles
          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          // Rotation Handle
          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, polylinePoints, mousePos, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT, selectionBounds, interactionMode, transformStart]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};

// components/Canvas.tsx
import React, { useRef, useLayoutEffect, useEffect, useState } from 'react';
import { useStore } from '../store/useStore';
import { interpolateStrokePoints, snapPointToGrid, isPointInStroke, calculateInterpolationWeights, distance, getBoundingBox, rotatePoint, lerp } from '../utils/math';
import { Point } from '../types';
import { APP_COLORS } from '../constants';

type InteractionMode = 'none' | 'drawing' | 'polyline' | 'dragging' | 'resizing' | 'rotating';
type ResizeHandle = 'tl' | 'tr' | 'bl' | 'br';

export const Canvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { ui, project, updateAxisValue, addStrokeToCurrentKeyframe, updateStrokeInCurrentKeyframe, selectStroke } = useStore();

  // -- State --
  const currentPointsRef = useRef<Point[]>([]); 
  const [polylinePoints, setPolylinePoints] = useState<Point[]>([]);
  const [mousePos, setMousePos] = useState<Point | null>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Transform State
  const [interactionMode, setInteractionMode] = useState<InteractionMode>('none');
  const [activeHandle, setActiveHandle] = useState<ResizeHandle | null>(null);

  // Transform Data
  const [transformStart, setTransformStart] = useState<{
      mouse: Point;
      center: Point;
      angle: number;
      width: number;
      height: number;
      points: Point[]; // Original points snapshot
  } | null>(null);

  // Live Bounding Box (Visual only, committed on drag end)
  const [selectionBounds, setSelectionBounds] = useState<{
      cx: number; cy: number; width: number; height: number; rotation: number;
  } | null>(null);

  // Layout
  const [scale, setScale] = useState(1);
  const CANVAS_WIDTH = project.canvasSize.width;
  const CANVAS_HEIGHT = project.canvasSize.height;

  // -- Helpers --

  // Auto-Scale Canvas
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      const { width: contW, height: contH } = containerRef.current.getBoundingClientRect();
      const margin = 80;
      const newScale = Math.min((contW - margin) / CANVAS_WIDTH, (contH - margin) / CANVAS_HEIGHT, 1);
      setScale(Math.max(0.1, newScale));
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, [CANVAS_WIDTH, CANVAS_HEIGHT]);

  const getCanvasPoint = (e: React.PointerEvent): Point => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    const x = (e.clientX - rect.left) * (CANVAS_WIDTH / rect.width);
    const y = (e.clientY - rect.top) * (CANVAS_HEIGHT / rect.height);
    return { x, y, pressure: e.pressure || 0.5 };
  };

  const getSnappedPoint = (p: Point): Point => {
      if (ui.snapToGrid) return snapPointToGrid(p, ui.gridSize);
      return p;
  };

  // -- Selection Logic --

  // Update selection bounds when selection changes
  useEffect(() => {
    if (ui.selectedTool !== 'select' || !ui.selectedStrokeId || !ui.selectedKeyframeId) {
        setSelectionBounds(null);
        return;
    }

    const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
    if (!kf) return;
    const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
    if (!layerState) return;

    const stroke = layerState.strokes.find(s => s.id === ui.selectedStrokeId);
    if (!stroke) return;

    // Calculate AABB (Axis Aligned Bounding Box)
    const bbox = getBoundingBox(stroke.points);
    setSelectionBounds({
        cx: bbox.centerX,
        cy: bbox.centerY,
        width: bbox.width,
        height: bbox.height,
        rotation: 0 // Reset rotation on new selection (simplification)
    });

  }, [ui.selectedStrokeId, ui.selectedKeyframeId, ui.selectedLayerId, ui.selectedTool, project.keyframes]);

  // -- Hit Testing for Gizmos --
  const getGizmoHit = (p: Point, bounds: { cx: number, cy: number, width: number, height: number, rotation: number } | null) => {
      if (!bounds) return null;

      const { cx, cy, width, height, rotation } = bounds;
      const hw = width / 2;
      const hh = height / 2;

      // Rotate point into local space of the box to check handles easily
      const localP = rotatePoint(p, {x: cx, y: cy}, -rotation);

      const HANDLE_SIZE = 10 / scale; // Screen-consistent size

      // Rotator (Top + offset)
      if (distance(localP, {x: cx, y: cy - hh - 25}) < HANDLE_SIZE) return 'rotator';

      // Corners
      if (distance(localP, {x: cx - hw, y: cy - hh}) < HANDLE_SIZE) return 'tl';
      if (distance(localP, {x: cx + hw, y: cy - hh}) < HANDLE_SIZE) return 'tr';
      if (distance(localP, {x: cx - hw, y: cy + hh}) < HANDLE_SIZE) return 'bl';
      if (distance(localP, {x: cx + hw, y: cy + hh}) < HANDLE_SIZE) return 'br';

      // Body (Hit test roughly inside box)
      if (localP.x >= cx - hw && localP.x <= cx + hw && localP.y >= cy - hh && localP.y <= cy + hh) return 'body';

      return null;
  };

  const findHitStroke = (p: Point): string | null => {
     const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
     if (!kf) return null;
     const layerState = kf.layerStates.find(ls => ls.layerId === ui.selectedLayerId);
     if (!layerState) return null;
     for (let i = layerState.strokes.length - 1; i >= 0; i--) {
        const s = layerState.strokes[i];
        if (isPointInStroke(p, s.points)) return s.id;
     }
     return null;
  };

  // -- Event Handlers --

  const handlePointerDown = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);

    // 1. Play Mode
    if (ui.mode === 'play') {
       (e.target as Element).setPointerCapture(e.pointerId);
       return;
    }

    // 2. Select / Transform Mode
    if (ui.selectedTool === 'select') {
        const hitGizmo = getGizmoHit(p, selectionBounds);

        if (hitGizmo && selectionBounds && ui.selectedStrokeId) {
            // Initiate Transform
            const kf = project.keyframes.find(k => k.id === ui.selectedKeyframeId);
            const ls = kf?.layerStates.find(s => s.layerId === ui.selectedLayerId);
            const stroke = ls?.strokes.find(s => s.id === ui.selectedStrokeId);

            if (stroke) {
                setTransformStart({
                    mouse: p,
                    center: { x: selectionBounds.cx, y: selectionBounds.cy },
                    angle: selectionBounds.rotation,
                    width: selectionBounds.width,
                    height: selectionBounds.height,
                    points: stroke.points // Snapshot original points
                });

                if (hitGizmo === 'body') setInteractionMode('dragging');
                else if (hitGizmo === 'rotator') setInteractionMode('rotating');
                else {
                    setInteractionMode('resizing');
                    setActiveHandle(hitGizmo as ResizeHandle);
                }
                (e.target as Element).setPointerCapture(e.pointerId);
            }
            return;
        }

        // Select Stroke
        const hitId = findHitStroke(p);
        if (hitId) {
            selectStroke(hitId);
            // Don't start drag immediately to prevent jump, wait for next move or explicit drag
        } else {
            selectStroke(null);
        }
        return;
    }

    // 3. Polyline
    if (ui.selectedTool === 'polyline') {
       const snappedP = getSnappedPoint(p);

       // A. Closing Loop Logic (Clicking near first point)
       if (polylinePoints.length > 2 && distance(snappedP, polylinePoints[0]) < 15) {
           addStrokeToCurrentKeyframe(polylinePoints, true, true);
           setPolylinePoints([]);
           return;
       }

       // B. Finishing Line Logic (Clicking near last point - Double Click simulation)
       if (polylinePoints.length > 0) {
           const lastPoint = polylinePoints[polylinePoints.length - 1];
           // If we click very close to the last placed point, we finish the open line
           if (distance(snappedP, lastPoint) < 15) {
               addStrokeToCurrentKeyframe(polylinePoints, false, true);
               setPolylinePoints([]);
               return;
           }
       }

       setPolylinePoints(prev => [...prev, snappedP]);
       return;
    }

    // 4. Pen
    if (ui.selectedTool === 'pen') {
      setInteractionMode('drawing');
      setIsDrawing(true);
      currentPointsRef.current = [getSnappedPoint(p)];
      (e.target as Element).setPointerCapture(e.pointerId);
    } 
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    const p = getCanvasPoint(e);
    setMousePos(getSnappedPoint(p)); // Snap cursor preview

    // Play Mode
    if (ui.mode === 'play') {
        const rect = canvasRef.current!.getBoundingClientRect();
        let normX = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        let normY = Math.max(0, Math.min(1, (e.clientY - rect.top) / rect.height));

        if (ui.snapPlayMode) {
            normX = Math.round(normX * 10) / 10;
            normY = Math.round(normY * 10) / 10;
        }
        updateAxisValue('axis-x', normX);
        updateAxisValue('axis-y', normY);
        return;
    }

    // Transform Logic
    if (interactionMode !== 'none' && transformStart && selectionBounds) {

        // A. DRAGGING (MOVE)
        if (interactionMode === 'dragging') {
            let dx = p.x - transformStart.mouse.x;
            let dy = p.y - transformStart.mouse.y;

            // Snap delta to grid
            if (ui.snapToGrid) {
                const targetX = transformStart.center.x + dx;
                const targetY = transformStart.center.y + dy;
                const snappedX = Math.round(targetX / ui.gridSize) * ui.gridSize;
                const snappedY = Math.round(targetY / ui.gridSize) * ui.gridSize;
                dx = snappedX - transformStart.center.x;
                dy = snappedY - transformStart.center.y;
            }

            setSelectionBounds({
                ...selectionBounds,
                cx: transformStart.center.x + dx,
                cy: transformStart.center.y + dy
            });
        }

        // B. ROTATING
        else if (interactionMode === 'rotating') {
            const currentAngle = Math.atan2(p.y - selectionBounds.cy, p.x - selectionBounds.cx);
            const startAngle = Math.atan2(transformStart.mouse.y - selectionBounds.cy, transformStart.mouse.x - selectionBounds.cx);
            let dAngle = currentAngle - startAngle;
            let newRotation = transformStart.angle + dAngle;

            // Shift to snap rotation (15 deg / 45 deg steps)
            if (e.shiftKey) {
                const step = Math.PI / 12; // 15 deg
                newRotation = Math.round(newRotation / step) * step;
            }

            setSelectionBounds({
                ...selectionBounds,
                rotation: newRotation
            });
        }

        // C. RESIZING
        else if (interactionMode === 'resizing' && activeHandle) {
            // Calculate delta in rotated space
            const unrotatedMouse = rotatePoint(p, transformStart.center, -transformStart.angle);
            const unrotatedStart = rotatePoint(transformStart.mouse, transformStart.center, -transformStart.angle);
            let dx = unrotatedMouse.x - unrotatedStart.x;
            let dy = unrotatedMouse.y - unrotatedStart.y;

            // Proportional Resize (Shift)
            if (e.shiftKey) {
                const aspect = transformStart.width / transformStart.height;
                if (activeHandle === 'br' || activeHandle === 'tl') {
                    dy = dx / aspect;
                } else {
                    dy = -dx / aspect;
                }
            }

            // Snap Size to Grid
            if (ui.snapToGrid && !e.shiftKey) {
                 // Simplistic snap for resize delta
                 dx = Math.round(dx / ui.gridSize) * ui.gridSize;
                 dy = Math.round(dy / ui.gridSize) * ui.gridSize;
            }

            let newW = transformStart.width;
            let newH = transformStart.height;
            // Center usually shifts during resize unless Alt is held (not implemented)
            // But for now let's scale from center (simplest) or corner? 
            // Corner is better.

            // Actually, scaling from center is easier for the Gizmo logic we have
            // Let's modify width/height
            if (activeHandle === 'br') { newW += dx * 2; newH += dy * 2; } // Scale from center logic
            if (activeHandle === 'tl') { newW -= dx * 2; newH -= dy * 2; }
            if (activeHandle === 'tr') { newW += dx * 2; newH -= dy * 2; }
            if (activeHandle === 'bl') { newW -= dx * 2; newH += dy * 2; }

            // Prevent flipping
            newW = Math.max(1, newW);
            newH = Math.max(1, newH);

            setSelectionBounds({
                ...selectionBounds,
                width: newW,
                height: newH
            });
        }
        return;
    }

    // Drawing
    if (interactionMode === 'drawing') {
        currentPointsRef.current.push(getSnappedPoint(p));
    }
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    (e.target as Element).releasePointerCapture(e.pointerId);

    // Commit Transform
    if (interactionMode !== 'none' && transformStart && selectionBounds && ui.selectedStrokeId) {
        // We need to apply the transformation matrix (S * R * T) to the original points
        // T = NewCenter - OldCenter
        // R = NewRotation - OldRotation
        // S = NewSize / OldSize

        const scaleX = selectionBounds.width / transformStart.width;
        const scaleY = selectionBounds.height / transformStart.height;
        const dRot = selectionBounds.rotation - transformStart.angle;
        const dX = selectionBounds.cx - transformStart.center.x;
        const dY = selectionBounds.cy - transformStart.center.y;

        const newPoints = transformStart.points.map(pt => {
            // 1. Localize to center
            let x = pt.x - transformStart.center.x;
            let y = pt.y - transformStart.center.y;

            // 2. Rotate (Initial offset) -> unnecessary if we assume 0 rotation start for bbox, 
            // but stroke points might be anywhere.
            // Actually, we rotate points around center by dRot
            // But wait, the points were unrotated relative to the bbox? No.

            // Standard Affine Transform:
            // P' = T * R * S * P_local

            // Scale
            x *= scaleX;
            y *= scaleY;

            // Rotate
            const cos = Math.cos(dRot);
            const sin = Math.sin(dRot);
            const rx = x * cos - y * sin;
            const ry = x * sin + y * cos;

            // Translate
            return {
                x: rx + transformStart.center.x + dX,
                y: ry + transformStart.center.y + dY,
                pressure: pt.pressure
            };
        });

        updateStrokeInCurrentKeyframe(ui.selectedStrokeId, newPoints);
    }

    // Commit Drawing
    if (interactionMode === 'drawing') {
        if (currentPointsRef.current.length > 1) {
            // REMOVED AUTO-CLOSE LOGIC FOR PEN TOOL AS REQUESTED
            addStrokeToCurrentKeyframe([...currentPointsRef.current], false);
        }
    }

    // Reset
    setInteractionMode('none');
    setIsDrawing(false);
    setActiveHandle(null);
    setTransformStart(null);
    currentPointsRef.current = [];
  };

  const handleDoubleClick = () => {
      if (ui.selectedTool === 'polyline') {
          if (polylinePoints.length > 1) {
              addStrokeToCurrentKeyframe(polylinePoints, false, true);
          }
          setPolylinePoints([]);
      }
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
          if (ui.selectedTool === 'polyline') handleDoubleClick();
      }
      if (e.key === 'Escape') {
          setPolylinePoints([]);
          setInteractionMode('none');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [polylinePoints, ui.selectedTool]);


  // -- Render Loop --
  useLayoutEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = CANVAS_WIDTH * dpr;
    canvas.height = CANVAS_HEIGHT * dpr;
    ctx.scale(dpr, dpr);

    let animationFrameId: number;

    const render = () => {
      ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // GRID
      if (ui.showGrid && ui.mode === 'edit') {
        ctx.fillStyle = '#D1D5DB';
        const gridSize = ui.gridSize;
        const centerX = CANVAS_WIDTH / 2;
        const centerY = CANVAS_HEIGHT / 2;
        const startX = (centerX % gridSize);
        const startY = (centerY % gridSize);
        for (let x = startX; x <= CANVAS_WIDTH; x += gridSize) {
           for (let y = startY; y <= CANVAS_HEIGHT; y += gridSize) {
              ctx.beginPath();
              ctx.arc(x, y, 1.5, 0, Math.PI * 2);
              ctx.fill();
           }
        }
      }

      // ONION SKIN
      if (ui.onionSkinEnabled && ui.mode === 'edit') {
         project.keyframes.forEach(kf => {
           if (kf.id === ui.selectedKeyframeId) return; 
           ctx.globalAlpha = ui.onionSkinOpacity;
           kf.layerStates.forEach(ls => {
              if (ls.layerId !== ui.selectedLayerId) return;
              const stroke = ls.strokes[0];
              if (stroke && stroke.points.length > 1) {
                ctx.beginPath();
                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                for (let i = 1; i < stroke.points.length; i++) ctx.lineTo(stroke.points[i].x, stroke.points[i].y);
                if (stroke.closed) ctx.closePath();
                ctx.strokeStyle = '#3B82F6'; 
                ctx.lineWidth = 1; 
                ctx.stroke();
              }
           });
           ctx.globalAlpha = 1.0;
         });
      }

      // INTERPOLATION RENDERING
      const currentAxesDict: Record<string, number> = {};
      project.axes.forEach(a => currentAxesDict[a.id] = a.currentValue);

      project.layers.forEach(layer => {
        if (!layer.visible) return;

        const layerRelevantKeyframes = project.keyframes.filter(kf => {
            const ls = kf.layerStates.find(s => s.layerId === layer.id);
            return ls && ls.strokes.length > 0;
        });

        if (layerRelevantKeyframes.length === 0) return;

        const weights = calculateInterpolationWeights(currentAxesDict, layerRelevantKeyframes, ui.interpolationExponent, ui.interpolationStrategy);

        const activeKeyframes = layerRelevantKeyframes
             .map(k => ({ ...k, weight: weights[k.id] || 0 }))
             .filter(k => k.weight > 0.0001);

        const strokeId = `stroke-${layer.id}-unique`;
        const isLayerActive = layer.id === ui.selectedLayerId;
        const isCreatingNewState = ui.selectedKeyframeId === null;

        let layerGlobalAlpha = layer.opacity;
        if (!isLayerActive && ui.mode !== 'play') layerGlobalAlpha *= ui.inactiveLayerOpacity;
        if (isCreatingNewState && ui.mode === 'edit') layerGlobalAlpha *= ui.ghostStrokeOpacity;

        const strokeData = activeKeyframes.map(kf => {
            const state = kf.layerStates.find(ls => ls.layerId === layer.id);
            const s = state?.strokes[0]; 
            return { weight: kf.weight, points: s?.points, style: s, color: s?.color || 'none', fillColor: s?.fillColor, width: s?.width || 1 };
        });

        const sortedByWeight = [...strokeData].sort((a,b) => b.weight - a.weight);
        const primaryStroke = sortedByWeight.find(sd => sd.style)?.style;
        if (!primaryStroke) return;

        const { points: interpolatedPoints, color: interpolatedColor, fillColor: interpolatedFill, width: interpolatedWidth } = interpolateStrokePoints(
            strokeId, primaryStroke.points, strokeData, layer.interpolationMode
        );

        if (interpolatedPoints.length > 0) {
            ctx.beginPath();
            ctx.moveTo(interpolatedPoints[0].x, interpolatedPoints[0].y);
            for (let i = 1; i < interpolatedPoints.length; i++) ctx.lineTo(interpolatedPoints[i].x, interpolatedPoints[i].y);
            if (primaryStroke.closed) ctx.closePath();

            ctx.globalAlpha = layerGlobalAlpha;
            switch(layer.blendMode) {
                case 'multiply': ctx.globalCompositeOperation = 'multiply'; break;
                case 'screen': ctx.globalCompositeOperation = 'screen'; break;
                case 'overlay': ctx.globalCompositeOperation = 'overlay'; break;
                case 'difference': ctx.globalCompositeOperation = 'difference'; break;
                case 'exclusion': ctx.globalCompositeOperation = 'exclusion'; break;
                default: ctx.globalCompositeOperation = 'source-over';
            }

            if (interpolatedFill && interpolatedFill !== 'none') {
                ctx.fillStyle = interpolatedFill;
                ctx.fill();
            }
            if (interpolatedColor && interpolatedColor !== 'none') {
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';
                ctx.strokeStyle = interpolatedColor;
                ctx.lineWidth = interpolatedWidth;
                ctx.stroke();
            }

            ctx.globalAlpha = 1.0;
            ctx.globalCompositeOperation = 'source-over';
        }
      });

      // ACTIVE DRAWING
      if (isDrawing && currentPointsRef.current.length > 0) {
        // If we are drawing in an undefined state (interpolated state), use reduced opacity
        // Otherwise (we are on a keyframe), use full opacity
        const isGhostState = ui.selectedKeyframeId === null;
        ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;

        ctx.beginPath();
        const pts = currentPointsRef.current;
        ctx.moveTo(pts[0].x, pts[0].y);
        for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
        ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.2)'; 
        ctx.lineWidth = ui.brushSize;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
        ctx.globalAlpha = 1.0; 
      }

      // ACTIVE POLYLINE
      if (polylinePoints.length > 0) {
         // Same ghost logic for polyline
         const isGhostState = ui.selectedKeyframeId === null;
         ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;

         ctx.beginPath();
         ctx.moveTo(polylinePoints[0].x, polylinePoints[0].y);
         for (let i = 1; i < polylinePoints.length; i++) ctx.lineTo(polylinePoints[i].x, polylinePoints[i].y);

         if (mousePos) ctx.lineTo(mousePos.x, mousePos.y); 

         if (ui.fillColor !== 'none') {
             ctx.fillStyle = ui.fillColor;
             // Fill should be slightly transparent while drawing
             ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity * 0.5 : 0.5;
             ctx.fill();
             ctx.globalAlpha = isGhostState ? ui.ghostStrokeOpacity : 1.0;
         }

         ctx.strokeStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         ctx.lineWidth = ui.brushSize;
         ctx.stroke();

         ctx.fillStyle = ui.brushColor !== 'none' ? ui.brushColor : 'rgba(0,0,0,0.5)';
         polylinePoints.forEach((p, index) => {
            ctx.beginPath();
            const r = (index === 0) ? 5 : 3; 
            ctx.arc(p.x, p.y, r, 0, Math.PI * 2);
            ctx.fill();
         });
         ctx.globalAlpha = 1.0; 
      }

      // GIZMOS (Transform Tool)
      if (selectionBounds && ui.selectedTool === 'select' && ui.mode === 'edit') {
          const { cx, cy, width, height, rotation } = selectionBounds;

          ctx.save();
          ctx.translate(cx, cy);
          ctx.rotate(rotation);

          // Bounding Box
          ctx.beginPath();
          ctx.strokeStyle = '#3B82F6';
          ctx.lineWidth = 1;
          ctx.rect(-width/2, -height/2, width, height);
          ctx.stroke();

          // Handles
          const HANDLE_SIZE = 8; 
          ctx.fillStyle = '#FFFFFF';
          ctx.strokeStyle = '#3B82F6';

          const drawHandle = (x: number, y: number) => {
              ctx.beginPath();
              ctx.rect(x - HANDLE_SIZE/2, y - HANDLE_SIZE/2, HANDLE_SIZE, HANDLE_SIZE);
              ctx.fill();
              ctx.stroke();
          };

          drawHandle(-width/2, -height/2); // TL
          drawHandle(width/2, -height/2);  // TR
          drawHandle(-width/2, height/2);  // BL
          drawHandle(width/2, height/2);   // BR

          // Rotation Handle
          ctx.beginPath();
          ctx.moveTo(0, -height/2);
          ctx.lineTo(0, -height/2 - 25);
          ctx.stroke();

          ctx.beginPath();
          ctx.arc(0, -height/2 - 25, 4, 0, Math.PI * 2);
          ctx.fillStyle = '#3B82F6';
          ctx.fill();

          ctx.restore();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();
    return () => cancelAnimationFrame(animationFrameId);
  }, [project, ui, polylinePoints, mousePos, isDrawing, CANVAS_WIDTH, CANVAS_HEIGHT, selectionBounds, interactionMode, transformStart]);

  return (
    <div 
      ref={containerRef} 
      className="absolute inset-0 z-0 flex items-center justify-center bg-[#EAEAEA] touch-none"
    >
      <div 
        style={{ 
          width: CANVAS_WIDTH, 
          height: CANVAS_HEIGHT,
          transform: `scale(${scale})`,
          boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.15)' 
        }}
        className="bg-white rounded-xl overflow-hidden relative transition-transform duration-200 ease-out origin-center ring-4 ring-white/50"
      >
          <canvas 
            ref={canvasRef} 
            className={`block w-full h-full ${ui.mode === 'play' ? 'cursor-move' : (ui.selectedTool === 'select' ? 'cursor-default' : 'cursor-crosshair')}`}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onDoubleClick={handleDoubleClick}
          />
      </div>
    </div>
  );
};
